    // MARK: - Live joins (tape / takeover / slate)

    /// Gary's pick for a live-score row, if tonight's board has one.
    private func pickFor(_ live: LiveScore) -> GaryPick? {
        todayPicks.first { p in
            abbrGameMatches(live.abbrGame, matchup: "\(p.awayTeam ?? "") @ \(p.homeTeam ?? "")")
        }
    }

    private func verdictFor(_ live: LiveScore) -> HomeLiveVerdict {
        guard let pick = pickFor(live) else { return .neutral }
        return HomeLiveVerdict.evaluate(pick: pick, live: live)
    }

    /// Tape cells: every game Gary has a side in plus anything live, live
    /// games first.
    private var tapeCells: [HomeLiveTape.Cell] {
        let interesting = liveScoresNow.filter { $0.isLive || pickFor($0) != nil }
        let ordered = interesting.sorted { a, b in
            if a.isLive != b.isLive { return a.isLive }
            return (a.game_id ?? "") < (b.game_id ?? "")
        }
        return ordered.prefix(8).map { ls in
            let v = verdictFor(ls)
            let status: String
            if ls.isLive {
                let vt = v == .covering ? "COVERING" : v == .trailing ? "TRAILING" : ""
                status = [ls.detail ?? "", vt].filter { !$0.isEmpty }.joined(separator: " · ")
            } else if ls.isFinal {
                status = "FINAL"
            } else {
                status = (pickFor(ls)?.pick ?? ls.detail ?? "").uppercased()
            }
            return HomeLiveTape.Cell(
                id: ls.game_id ?? ls.abbrGame,
                eyebrow: [(ls.league ?? "").uppercased(), ls.isLive ? "LIVE" : ""].filter { !$0.isEmpty }.joined(separator: " · "),
                line: ls.scoreLine ?? ls.abbrGame,
                status: status.uppercased(),
                tone: ls.isLive || ls.isFinal ? v : .neutral,
                isLive: ls.isLive
            )
        }
    }

    /// The live takeover: the in-progress game Gary has the most conviction
    /// in (highest-confidence pick among live games).
    private var takeoverModel: (live: LiveScore, pickLine: String, verdict: HomeLiveVerdict)? {
        let candidates: [(LiveScore, GaryPick)] = liveScoresNow
            .filter { $0.isLive }
            .compactMap { ls in pickFor(ls).map { (ls, $0) } }
        guard let best = candidates.max(by: { ($0.1.confidence ?? 0) < ($1.1.confidence ?? 0) }) else { return nil }
        return (best.0, best.1.pick ?? "", HomeLiveVerdict.evaluate(pick: best.1, live: best.0))
    }

    /// Gary's pick for a slate game, once posted — matched by team names.
    private func pickFor(slate g: DailySlateRow) -> GaryPick? {
        let away = Self.shortTeam(g.away_team).lowercased()
        let home = Self.shortTeam(g.home_team).lowercased()
        guard !away.isEmpty, !home.isEmpty else { return nil }
        return todayPicks.first {
            ($0.awayTeam ?? "").lowercased().contains(away) && ($0.homeTeam ?? "").lowercased().contains(home)
        }
    }

    private func slateRow(_ g: DailySlateRow, id: String, chip: String) -> HomeSlateSection.Row {
        HomeSlateSection.Row(
            id: id,
            title: "\(Self.shortTeam(g.away_team)) @ \(Self.shortTeam(g.home_team))",
            sub: (g.venue ?? "").uppercased(), tone: nil, chip: chip, league: g.league,
            time: Formatters.formatCommenceTime(g.commence_time).uppercased())
    }

    private var pregameSlateRows: [HomeSlateSection.Row] {
        // The REAL board: every game from daily_slate, Gary's call overlaid
        // when posted, the ML price until then.
        guard !slateGames.isEmpty else {
            let sorted = todayPicks.sorted { ($0.commence_time ?? "") < ($1.commence_time ?? "") }
            return sorted.prefix(8).map { p in
                HomeSlateSection.Row(id: p.id, title: "\(Self.shortTeam(p.awayTeam)) @ \(Self.shortTeam(p.homeTeam))",
                                     sub: (p.venue ?? "").uppercased(), tone: nil, chip: p.pick ?? "",
                                     league: p.league, time: Formatters.formatCommenceTime(p.displayTime).uppercased())
            }
        }
        // Start-time order, full stop — the founder's read: "here's the games
        // organized by start times", sports identified by accent, not by rank.
        let orderedSlate = slateGames.sorted { ($0.commence_time ?? "") < ($1.commence_time ?? "") }
        return orderedSlate.enumerated().map { i, g in
            let chip: String
            if let pick = pickFor(slate: g)?.pick, !pick.isEmpty {
                chip = pick
            } else if let mlh = g.ml_home, abs(mlh) <= 2000 {
                chip = String(format: "%@ %+.0f", Self.shortTeam(g.home_team).uppercased(), mlh)
            } else {
                chip = "—"
            }
            return slateRow(g, id: "ds-\(i)", chip: chip)
        }
    }

    /// SPREADS — tonight's board sorted by spread size, biggest first. One
    /// list shows both extremes (the monsters up top, the coin-flips at the
    /// bottom); the chip names the favorite at its number.
    private var spreadSlateRows: [HomeSlateSection.Row] {
        // MLB spreads past the run-line band are book glitches, not lines.
        let withSpread = slateGames.filter {
            let s = $0.spread ?? 0
            return s != 0 && ($0.league != "MLB" || abs(s) <= 3.5)
        }
        let sorted = withSpread.sorted { abs($0.spread ?? 0) > abs($1.spread ?? 0) }
        return sorted.enumerated().map { i, g in
            let s = g.spread ?? 0   // HOME line: home favored = negative
            let favored = s < 0 ? Self.shortTeam(g.home_team) : Self.shortTeam(g.away_team)
            return slateRow(g, id: "sp-\(i)",
                            chip: String(format: "%@ %+.1f", favored.uppercased(), -abs(s)))
        }
    }

    /// HOME DOGS — hosts at plus money tonight, biggest price first.
    private var homeDogSlateRows: [HomeSlateSection.Row] {
        let dogs = slateGames.filter { let m = $0.ml_home ?? 0; return m > 0 && m <= 2000 }
        let sorted = dogs.sorted { ($0.ml_home ?? 0) > ($1.ml_home ?? 0) }
        return sorted.enumerated().map { i, g in
            slateRow(g, id: "hd-\(i)",
                     chip: "\(Self.shortTeam(g.home_team).uppercased()) +\(Int(g.ml_home ?? 0))")
        }
    }

    private var liveSlateRows: [HomeSlateSection.Row] {
        let sorted = todayPicks.sorted { ($0.commence_time ?? "") < ($1.commence_time ?? "") }
        return sorted.prefix(8).map { p in
            let live = liveScoresNow.first {
                abbrGameMatches($0.abbrGame, matchup: "\(p.awayTeam ?? "") @ \(p.homeTeam ?? "")")
            }
            guard let ls = live else {
                let sub = [Formatters.formatCommenceTime(p.displayTime), p.venue].compactMap { $0 }.filter { !$0.isEmpty }
                    .joined(separator: " · ").uppercased()
                return HomeSlateSection.Row(id: p.id,
                                            title: "\(Self.shortTeam(p.awayTeam)) @ \(Self.shortTeam(p.homeTeam))",
                                            sub: sub, tone: nil, chip: p.pick ?? "")
            }
            let v = HomeLiveVerdict.evaluate(pick: p, live: ls)
            let title = ls.scoreLine ?? ls.abbrGame
            var sub: String
            var tone: HomeLiveVerdict? = nil
            if ls.isLive {
                let vt = v == .covering ? "COVERING" : v == .trailing ? "TRAILING" : ""
                sub = [ls.detail ?? "", vt].filter { !$0.isEmpty }.joined(separator: " · ").uppercased()
                tone = v
            } else if ls.isFinal {
                sub = v == .covering ? "FINAL · CASHED ✓" : v == .trailing ? "FINAL · NO CASH" : "FINAL"
                tone = v
            } else {
                sub = [Formatters.formatCommenceTime(p.displayTime), p.venue].compactMap { $0 }.filter { !$0.isEmpty }
                    .joined(separator: " · ").uppercased()
            }
            return HomeSlateSection.Row(id: p.id, title: title, sub: sub, tone: tone, chip: p.pick ?? "")
        }
    }

    private var liveBoardSub: String {
        let lives = liveScoresNow.filter { $0.isLive }.count
        let finals = liveScoresNow.filter { $0.isFinal && pickFor($0) != nil }.count
        let upcoming = max(0, todayPicks.count - lives - finals)
        return "\(finals) settled · \(lives) live · \(upcoming) upcoming"
    }

    /// Tonight so far, from finals Gary had a side in.
    private var tonightRecord: (w: Int, l: Int) {
        var w = 0, l = 0
        for ls in liveScoresNow where ls.isFinal {
            guard let p = pickFor(ls) else { continue }
            switch HomeLiveVerdict.evaluate(pick: p, live: ls) {
            case .covering: w += 1
            case .trailing: l += 1
            case .neutral: break
            }
        }
        return (w, l)
    }

    private var liveCountText: String? {
        let n = liveScoresNow.filter { $0.isLive }.count
        return n > 0 ? "\(n) LIVE" : nil
    }

    /// Last word of a team name — "Red Sox" → "Sox", good enough for a row
    /// title when the live poller hasn't given us real abbreviations.
    static func shortTeam(_ name: String?) -> String {
        guard let last = name?.split(separator: " ").last else { return "—" }
        return String(last)
    }

    /// Box-score-style prop results for the biggest settled game of the
    /// latest graded night: PLAYER / LINE / RESULT / grade.
    /// The Prop Box tab set: Gary's densest graded game leads, then the
    /// whole league's night — every homer, multi-hit game and K show, his
    /// result attached only where he actually had the position.
    private var propBoxTabs: [HomePropBoxSection.Tab] {
        var tabs: [HomePropBoxSection.Tab] = []
        if let first = propBoxGames.first {
            tabs.append(HomePropBoxSection.Tab(
                label: "THE BOX", title: first.label, status: first.status,
                cols: ("PLAYER", "LINE", "RESULT"), rows: first.rows,
                gameOptions: propBoxGames))
        }
        let cats: [(key: String, label: String, noun: String)] = [
            ("hr", "HR", "homered"),
            ("multi_hit", "2+ HITS", "had multi-hit nights"),
            ("k_show", "K SHOW", "struck out 7+")
        ]
        for c in cats {
            let all = nightHighlights.filter { $0.category == c.key }
            guard !all.isEmpty else { continue }
            // Biggest stat lines first (every detail leads with its number),
            // Gary's positions break ties.
            func lead(_ d: String?) -> Int { Int((d ?? "").prefix(while: { $0.isNumber })) ?? 0 }
            let sorted = all.sorted {
                let (a, b) = (lead($0.detail), lead($1.detail))
                if a != b { return a > b }
                return ($0.gary_result != nil) && ($1.gary_result == nil)
            }
            let rows = sorted.prefix(10).map { h in
                HomePropBoxSection.Row(
                    player: NightBoard.shortPlayer(h.player_name).uppercased(),
                    line: Self.shortTeam(h.team).uppercased(),
                    actual: h.detail ?? "",
                    state: h.gary_result,
                    tint: TeamColors.color(for: h.team))
            }
            tabs.append(HomePropBoxSection.Tab(
                label: c.label, title: "\(all.count) \(c.noun)", status: "LAST NIGHT",
                cols: ("PLAYER", "TEAM", "NIGHT"), rows: Array(rows)))
        }
        return tabs
    }

    /// THE BOX's game dropdown: an "ALL" option (Gary's 2 best winners + 2 best
    /// losers from last night's graded props), then one option per game Gary had
    /// props in — densest first, the game's final score as the label.
    static func buildPropBoxGames(props: [PropResult], games: [GameResult]) -> [HomePropBoxSection.GameOption] {
        let graded = props.filter { ["won", "lost", "push"].contains($0.result ?? "") }
        guard let latest = graded.compactMap({ $0.game_date }).max() else { return [] }
        let day = graded.filter { $0.game_date == latest }
        guard !day.isEmpty else { return [] }

        func row(_ p: PropResult) -> HomePropBoxSection.Row {
            let unit = Self.propUnit(p.prop_type)
            let dir = (p.bet ?? "").lowercased().hasPrefix("u") ? "U" : "O"
            return HomePropBoxSection.Row(
                player: NightBoard.shortPlayer(p.player_name).uppercased(),
                line: "\(dir) \(Self.trimNum(p.line_value?.value ?? "—")) \(unit)",
                actual: "\(Self.trimNum(p.actual_value?.value ?? "—")) \(unit)",
                state: p.result)
        }

        var options: [HomePropBoxSection.GameOption] = []

        // ALL — Gary's two highest-confidence winners and two highest-confidence losers.
        let byConf = day.sorted { ($0.confidence ?? 0) > ($1.confidence ?? 0) }
        let allRows = Array(byConf.filter { $0.result == "won" }.prefix(2).map(row))
                    + Array(byConf.filter { $0.result == "lost" }.prefix(2).map(row))
        if !allRows.isEmpty {
            options.append(.init(label: "ALL", status: "LAST NIGHT", rows: allRows))
        }

        // One option per game Gary had props in — densest first.
        let byGame = Dictionary(grouping: day.filter { $0.matchup?.isEmpty == false }) { $0.matchup ?? "" }
        let ordered = byGame.sorted {
            $0.value.count != $1.value.count ? $0.value.count > $1.value.count : $0.key < $1.key
        }
        for (matchup, gprops) in ordered {
            var label = matchup
            if let g = games.first(where: { $0.game_date == latest && ($0.matchup ?? "") == matchup }),
               let score = g.final_score?.split(separator: "-"), score.count == 2 {
                let parts = matchup.components(separatedBy: " @ ")
                if parts.count == 2 {
                    label = "\(Formatters.shortTeamName(parts[0])) \(score[0]) · \(Formatters.shortTeamName(parts[1])) \(score[1])"
                }
            }
            options.append(.init(label: label, status: "FINAL", rows: Array(gprops.prefix(5).map(row))))
        }
        return options
    }

    /// Box-score unit for a prop type — "total_bases" → "TB".
    static func propUnit(_ type: String?) -> String {
        let t = (type ?? "").lowercased()
        if t.contains("total_bases") || t.contains("total bases") { return "TB" }
        if t.contains("strikeout") { return "K" }
        if t.contains("home_run") || t.contains("home run") { return "HR" }
        if t.contains("hits_runs_rbis") { return "H+R+RBI" }
        if t.contains("rbi") { return "RBI" }
        if t.contains("hit") { return "H" }
        if t.contains("run") { return "R" }
        if t.contains("point") { return "PTS" }
        if t.contains("rebound") { return "REB" }
        if t.contains("assist") { return "AST" }
        if t.contains("three") { return "3PT" }
        if t.contains("shots_on_goal") { return "SOG" }
        if t.contains("goal") { return "G" }
        if t.contains("save") { return "SV" }
        return String(t.prefix(3)).uppercased()
    }

    static func trimNum(_ s: String) -> String {
        s.hasSuffix(".0") ? String(s.dropLast(2)) : s
    }

    // MARK: - ② The Scorecard

    /// Yesterday as three big readable numbers. No icons, no emoji, no
    /// caption sentence — data graphics only.
    private func scoreCell(_ value: String, _ label: String, _ color: Color) -> some View {
        VStack(spacing: 3) {
            Text(value)
                .font(GaryFonts.mono(24, bold: true))
                .foregroundStyle(color)
                .lineLimit(1)
                .minimumScaleFactor(0.7)
            Text(label)
                .font(.system(size: 10, weight: .semibold))
                .tracking(0.8)
                .foregroundStyle(.white.opacity(0.45))
        }
        .frame(maxWidth: .infinity)
    }

    // June 5: caption sentence removed — the numbers speak for themselves
    // (user feedback: no editorial one-liners in the UI).
    private var scorecard: some View {
        Button {
            withAnimation(.spring(response: 0.3, dampingFraction: 0.7)) { selectedTab = 4 }
        } label: {
            HStack(spacing: 0) {
                // Window named once, leftmost — every cell in this row is
                // last night's slate (feedback: unlabeled windows next to the
                // form lane's L10 numbers read contradictory).
                scoreCell(Self.recordLine(lastNightRecord.w, lastNightRecord.l, lastNightRecord.p),
                          "LAST NIGHT", .white.opacity(0.92))
                if let net = lastNightNet {
                    Rectangle().fill(Color.white.opacity(0.08)).frame(width: 1, height: 34)
                    scoreCell(Formatters.flatStakeDollars(net), "NET · $100/PICK",
                              net >= 0 ? Color(hex: "#3FB950") : Color(hex: "#E5484D"))
                }
                if let best = bestCashOdds, best > 0 {
                    Rectangle().fill(Color.white.opacity(0.08)).frame(width: 1, height: 34)
                    scoreCell("+\(Int(best))", "BEST CASH", GaryColors.gold)
                }
            }
            .padding(.horizontal, 16)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
    }

    // MARK: - ⑤ Tonight's Board

    private var boardSection: some View {
        VStack(alignment: .leading, spacing: 12) {
            if !tonightCarouselPicks.isEmpty {
                // Tonight's board — swipeable, one card at a time: the top 3 plays
                // per sport with the marquee FREE pick leading. (Replaces the old
                // vertically-stacked free pick + prop.)
                tonightPicksHeader
                tonightPicksCarousel
            } else {
                VStack(alignment: .leading, spacing: 6) {
                    if !loading, let yPick = yesterdayTopPick {
                        // Until today's pick posts, yesterday's free pick holds
                        // the slot — wearing its W/L stamp, so it reads as the
                        // last result, never as tonight's play.
                        Text("LAST NIGHT'S FREE PICK")
                            .font(GaryFonts.mono(9.5, bold: true)).tracking(1)
                            .foregroundStyle(.white.opacity(0.4))
                        FlippablePickCard(pick: yPick, gameResult: yesterdayTopPickResult,
                                          finalScore: yesterdayTopPickScore, showSportBadge: true)
                    } else if !loading {
                        Text("Tonight's plays post closer to first pitch.")
                            .font(.system(size: 13))
                            .foregroundStyle(.white.opacity(0.45))
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .padding(.vertical, 22).padding(.horizontal, 18)
                            .quantPanel()
                    } else if loading {
                        HStack(spacing: 10) {
                            ProgressView().controlSize(.small).tint(GaryColors.gold.opacity(0.7))
                            Text("Loading tonight's plays…")
                                .font(.system(size: 13))
                                .foregroundStyle(.white.opacity(0.45))
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .padding(.vertical, 26).padding(.horizontal, 18)
                        .quantPanel()
                        .accessibilityLabel("Loading tonight's plays")
                    }
                    // The lone graded prop only when there's no fresh pick at all.
                    if !loading, freePick == nil, let yProp = yesterdayTopProp {
                        FlippablePropCard(prop: yProp, gameResult: yesterdayTopPropResult, showSportBadge: true)
                    }
                }
                .padding(.horizontal, 16)
            }
        }
    }

    private var tonightPicksHeader: some View {
        HStack {
            Text("TONIGHT'S TOP PLAYS")
                .font(GaryFonts.mono(9.5, bold: true)).tracking(1.2)
                .foregroundStyle(.white.opacity(0.5))
            Spacer()
            if tonightCarouselPicks.count > 1 {
                Text("SWIPE \u{2192}")
                    .font(GaryFonts.mono(8.5, bold: true)).tracking(1.2)
                    .foregroundStyle(GaryColors.gold.opacity(0.55))
            }
        }
        .padding(.horizontal, 16)
    }

    /// Tonight's swipeable board: the top 3 game picks per sport (by confidence),
    /// the marquee FREE pick pulled to the front. Sports lead with the free pick's
    /// league, then follow first-appearance order.
    private var tonightCarouselPicks: [GaryPick] {
        // Selection (unchanged): the strongest few per league, by confidence.
        var groups: [String: [GaryPick]] = [:]
        for p in todayPicks { groups[p.league ?? "", default: []].append(p) }
        var selected: [GaryPick] = []
        for (_, ps) in groups {
            selected.append(contentsOf: ps.sorted { ($0.confidence ?? 0) > ($1.confidence ?? 0) }.prefix(3))
        }
        // Order (user call, Jun 18): LIVE games first, then upcoming by start time
        // (earliest game up next), and GRADED/FINAL games sink to the very back —
        // so as each game kicks off it stays in front, then finishes and drops back,
        // surfacing the next game's picks. No free-pick-first override; a finished
        // free pick belongs at the back like any other.
        let live = LiveScoreCache.shared
        func bucket(_ p: GaryPick) -> Int {
            let mu = "\(p.awayTeam ?? "") @ \(p.homeTeam ?? "")"
            guard let ls = live.status(forMatchup: mu) else { return 1 } // unknown → treat as upcoming
            if ls.isFinal { return 2 }
            if ls.isLive { return 0 }
            return 1
        }
        func start(_ p: GaryPick) -> Date {
            if let iso = p.commence_time, let d = parseISO8601(iso) { return d }
            return .distantFuture
        }
        return selected.sorted {
            let (a, b) = (bucket($0), bucket($1))
            return a != b ? a < b : start($0) < start($1)
        }
    }

    @ViewBuilder private var tonightPicksCarousel: some View {
        let cardW = UIScreen.main.bounds.width - 44   // a sliver of the next card peeks
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(alignment: .top, spacing: 12) {
                ForEach(tonightCarouselPicks) { pick in
                    FlippablePickCard(pick: pick,
                                      eyebrowOverride: pick.id == freePick?.id ? "FREE PICK" : nil,
                                      gameResult: nil, showSportBadge: true)
                        .frame(width: cardW)
                }
                if let prop = freeProp {
                    FlippablePropCard(prop: prop, showSportBadge: true)
                        .frame(width: cardW)
                }
            }
            .padding(.horizontal, 16)
        }
    }

    // MARK: - ⑥ Footer

    private var footer: some View {
        SocialLinksBar()
            .padding(.horizontal, 16)
    }

    // MARK: - Front-page builders (template-only, no AI)

    private static func recordLine(_ w: Int, _ l: Int, _ p: Int) -> String {
        p > 0 ? "\(w)–\(l)–\(p)" : "\(w)–\(l)"
    }

    /// Gary's recent form — last 10 graded game picks as W/L/P pips
    /// (oldest→newest), the current streak, flat-stake net, and hit rate.
    /// Uses BillfoldCompute so the math matches the Billfold exactly.
    /// Nil until at least three results have settled.
    private static func buildForm(games: [GameResult]) -> HomeGarysForm.Model? {
        let graded = games
            .filter { ["won", "lost", "push"].contains($0.result ?? "") }
            .sorted { ($0.game_date ?? "") > ($1.game_date ?? "") }   // newest first
        guard graded.count >= 3 else { return nil }
        let window = Array(graded.prefix(10))                          // newest first
        let net = window.reduce(0.0) { $0 + BillfoldCompute.units(for: $1.result, odds: $1.effectiveOdds) }
        let winRate = Int(BillfoldCompute.winRate(from: window.map { $0.result }).rounded())
        let pips = window.reversed().map { r -> String in              // oldest → newest
            switch r.result {
            case "won":  return "W"
            case "lost": return "L"
            case "push": return "P"
            default:     return "·"
            }
        }
        // Current streak over decisive results (pushes skipped).
        let decisive = window.compactMap { $0.result }.filter { $0 == "won" || $0 == "lost" }
        var streak = ""
        var streakWin = false
        if let top = decisive.first {
            streakWin = (top == "won")
            var count = 0
            for r in decisive { if r == top { count += 1 } else { break } }
            streak = (streakWin ? "W" : "L") + "\(count)"
        }
        _ = pips; _ = winRate
        // The editorial headline — the card decides what the data MEANS
        // instead of rendering the same dataset four ways. Streak + last-10
        // net resolve into one sentence in Gary's frame.
        let decisiveCount = { () -> Int in
            guard let top = decisive.first else { return 0 }
            var c = 0
            for r in decisive { if r == top { c += 1 } else { break } }
            return c
        }()
        let story: String
        if streakWin && decisiveCount >= 3 {
            story = net < 0 ? "Cold week, hot hand — \(decisiveCount) straight wins."
                            : "\(decisiveCount) straight wins, in the green."
        } else if !streak.isEmpty && !streakWin && decisiveCount >= 3 {
            story = net >= 0 ? "\(decisiveCount) down in a row, still up on the week."
                             : "Cold stretch — \(decisiveCount) straight losses."
        } else if streakWin && decisiveCount == 2 {
            story = "Finding it — back-to-back wins."
        } else {
            story = net >= 0 ? "Choppy week, but green." : "Choppy week, in the red."
        }
        // The rail carries the whole graded history (drag left for older).
        let allPips = graded.prefix(46).reversed().map { r -> String in
            switch r.result {
            case "won":  return "W"
            case "lost": return "L"
            case "push": return "P"
            default:     return "·"
            }
        }
        return HomeGarysForm.Model(pips: Array(allPips), story: story,
                                   net: net, total: graded.count)
    }

    /// "2026-06-02" -> "Jun 2"
    private static func prettyDate(_ s: String) -> String {
        let months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun",
                      "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"]
        let parts = s.split(separator: "-")
        guard parts.count == 3, let m = Int(parts[1]), (1...12).contains(m), let d = Int(parts[2]) else { return s }
        return "\(months[m - 1]) \(d)"
    }

    private static func shiftDate(_ s: String, by days: Int) -> String? {
        let f = DateFormatter()
        f.dateFormat = "yyyy-MM-dd"
        f.timeZone = TimeZone(identifier: "America/New_York")
        guard let d = f.date(from: s),
              let shifted = Calendar.current.date(byAdding: .day, value: days, to: d) else { return nil }
        return f.string(from: shifted)
    }

    /// Days until the 2026 World Cup opener (June 11, EST). Nil after kickoff.
    private static func daysUntilWorldCup() -> Int? {
        var cal = Calendar(identifier: .gregorian)
        if let tz = TimeZone(identifier: "America/New_York") { cal.timeZone = tz }
        let kickoff = DateComponents(calendar: cal, year: 2026, month: 6, day: 11).date ?? Date()
        let days = cal.dateComponents([.day], from: cal.startOfDay(for: Date()), to: kickoff).day ?? 0
        return days > 0 ? days : nil
    }

    /// Flat-stake units P/L for one graded play (1u to win odds-implied).
    private static func unitsDelta(odds: Double, result: String) -> Double {
        switch result {
        case "won": return odds > 0 ? odds / 100.0 : (odds < 0 ? 100.0 / abs(odds) : 0)
        case "lost": return -1
        default: return 0
        }
    }

    /// "+270" / "-110" — odds as bettors read them.
    private static func oddsLabel(_ o: Double) -> String {
        o > 0 ? "+\(Int(o))" : "\(Int(o))"
    }

    private static func resultOdds(_ odds: StringOrNumber?, pickText: String?) -> Double {
        if let v = Double(odds?.value ?? "") { return v }
        return Double(Formatters.splitPickAndOdds(pickText).1) ?? -110
    }

    /// Standard abbreviation for a team name via the league keyword maps.
    private static func teamAbbrev(_ name: String, league: String?) -> String {
        let lower = name.lowercased()
        let maps: [[String: [String]]]
        switch (league ?? "").uppercased() {
        case "MLB": maps = [mlbTeamKeywords]
        case "NBA": maps = [nbaTeamKeywords]
        case "NHL": maps = [nhlTeamKeywords]
        case "WC": maps = [wcTeamKeywords]
        default: maps = [mlbTeamKeywords, nbaTeamKeywords, nhlTeamKeywords, wcTeamKeywords]
        }
        for map in maps {
            for (ab, kws) in map where kws.contains(where: { lower.contains($0) }) { return ab }
        }
        let last = lower.split(separator: " ").last.map(String.init) ?? lower
        return String(last.prefix(3)).uppercased()
    }

    /// One pass over the latest settled night: the marquee story (biggest
    /// cash, or the owned miss), the Biggest Cashes rows, and net units.
    /// All template — honesty is the brand, so the net includes the losses.
    private static func buildLastNight(games: [GameResult], props: [PropResult])
        -> (story: HomeMarqueeHero.Story?, marqueeGame: GameResult?, cashes: [HomeCashesSection.Row], beat: HomeCashesSection.Row?, net: Double, graded: Int, bestOdds: Double?, record: (w: Int, l: Int, p: Int)) {

        let settledGames = games.filter { $0.result == "won" || $0.result == "lost" || $0.result == "push" }
        let settledProps = props.filter { $0.result == "won" || $0.result == "lost" || $0.result == "push" }
        let days = settledGames.compactMap { $0.game_date } + settledProps.compactMap { $0.game_date }
        guard !days.isEmpty else { return (nil, nil, [], nil, 0, 0, nil, (0, 0, 0)) }
        // "Last night" = the most recent COMPLETED EST slate day. game_date already carries
        // the ET slate day a game STARTED on — a late west-coast game that finishes after
        // midnight UTC still keeps its ET day (verified Jun 18: Angels@Athletics graded
        // 10:34 UTC Jun 19, yet game_date = 2026-06-18). So we take exactly ONE day, no UTC-
        // rollover merge. Exclude TODAY so this morning's early games (a WC dawn kickoff)
        // never leak into yesterday's recap; an empty/off day falls back to the prior slate.
        let today = SupabaseAPI.todayEST()
        let prior = Set(days).filter { $0 < today }
        guard let anchor = prior.max() else { return (nil, nil, [], nil, 0, 0, nil, (0, 0, 0)) }
        let nightSet: Set<String> = [anchor]
        let nightGames = settledGames.filter { nightSet.contains($0.game_date ?? "") }
        let nightProps = settledProps.filter { nightSet.contains($0.game_date ?? "") }

        // Net units + cash rows across games AND props.
        var net = 0.0
        var bestOdds: Double? = nil
        var cashes: [HomeCashesSection.Row] = []
        for g in nightGames {
            let o = resultOdds(g.odds, pickText: g.pick_text)
            net += unitsDelta(odds: o, result: g.result ?? "")
            if g.result == "won" {
                bestOdds = max(bestOdds ?? -Double.infinity, o)
                cashes.append(.init(id: "g-\(g.matchup ?? "")-\(g.pick_text ?? "")",
                                    title: Self.gameCashTitle(g),
                                    sub: Formatters.splitPickAndOdds(g.pick_text).0,
                                    units: unitsDelta(odds: o, result: "won"),
                                    odds: Self.oddsLabel(o), league: g.league))
            }
        }
        for p in nightProps {
            let o = resultOdds(p.odds, pickText: p.pick_text)
            net += unitsDelta(odds: o, result: p.result ?? "")
            if p.result == "won" {
                bestOdds = max(bestOdds ?? -Double.infinity, o)
                // Sub = the NIGHT ("3 TB on the night"), never the player's
                // name again — the title already says who.
                let actual = Self.trimNum(p.actual_value?.value ?? "")
                let unit = Self.propUnit(p.prop_type)
                cashes.append(.init(id: "p-\(p.player_name ?? "")-\(p.pick_text ?? "")",
                                    title: Formatters.propResultTitle(p),
                                    sub: actual.isEmpty ? (p.matchup ?? "") : "\(actual) \(unit) on the night",
                                    units: unitsDelta(odds: o, result: "won"),
                                    odds: Self.oddsLabel(o), league: p.league))
            }
        }
        cashes.sort { $0.units > $1.units }
        // Sport variety — keep the biggest cash PER league so one hot sport can't
        // sweep the whole Hits & heartbreakers rail (user ask).
        var seenLeagues = Set<String>()
        cashes = cashes.filter { seenLeagues.insert($0.league ?? "?").inserted }
        let graded = nightGames.count + nightProps.count
        // ONE ledger for the scorecard: record, net, and best cash all count
        // the same set (games + props) — three cells, one truth.
        var recW = 0, recL = 0, recP = 0
        for r in (nightGames.map { $0.result } + nightProps.map { $0.result }) {
            switch r { case "won": recW += 1; case "lost": recL += 1; case "push": recP += 1; default: break }
        }
        let record = (w: recW, l: recL, p: recP)

        // The worst beat — the loss that stung most: the biggest favorite that
        // didn't hold (most-negative odds among the night's graded game losses).
        let beat: HomeCashesSection.Row? = nightGames
            .filter { $0.result == "lost" }
            .min { resultOdds($0.odds, pickText: $0.pick_text) < resultOdds($1.odds, pickText: $1.pick_text) }
            .map { g in
                let o = resultOdds(g.odds, pickText: g.pick_text)
                return HomeCashesSection.Row(
                    id: "beat-\(g.matchup ?? "")-\(g.pick_text ?? "")",
                    title: Self.gameCashTitle(g),
                    sub: Formatters.splitPickAndOdds(g.pick_text).0,
                    units: unitsDelta(odds: o, result: "lost"),
                    odds: Self.oddsLabel(o), league: g.league)
            }

        // The marquee — the priority league leads (a Finals game outranks
        // the MLB slate whatever the odds said), biggest odds break ties.
        func pri(_ r: GameResult) -> Int { LeaguePriority.rank(r.effectiveLeague) }
        let wins = nightGames.filter { $0.result == "won" }
        let star = wins.min { a, b in
            if pri(a) != pri(b) { return pri(a) < pri(b) }
            return resultOdds(a.odds, pickText: a.pick_text) > resultOdds(b.odds, pickText: b.pick_text)
        }
        let subject = star ?? nightGames.filter { $0.result == "lost" }
            .min { a, b in
                if pri(a) != pri(b) { return pri(a) < pri(b) }
                return abs(resultOdds(a.odds, pickText: a.pick_text)) > abs(resultOdds(b.odds, pickText: b.pick_text))
            }
        guard let r = subject else { return (nil, nil, Array(cashes.prefix(3)), beat, net, graded, bestOdds, record) }

        let cashed = r.result == "won"
        let o = resultOdds(r.odds, pickText: r.pick_text)
        let pickLine = Formatters.splitPickAndOdds(r.pick_text).0
        let story = HomeMarqueeHero.Story(
            league: r.effectiveLeague ?? "",
            headline: Self.gameHeadline(r, cashed: cashed),
            sub: Self.gameSubLine(r),
            receiptLead: cashed ? "Gary Cashed ·" : "Gary Had ·",
            receiptPick: pickLine.uppercased(),
            verdict: cashed ? (o > 0 ? "CASHED +\(Int(o))" : "CASHED") : "LOST",
            cashed: cashed)
        return (story, r, Array(cashes.prefix(3)), beat, net, graded, bestOdds, record)
    }

    /// "Knicks over the Spurs, 105–95" — a real game headline from facts.
    private static func gameHeadline(_ r: GameResult, cashed: Bool) -> String {
        if let (away, home, a, h) = Self.scoreParts(r) {
            let winner = a > h ? away : home
            let loser = a > h ? home : away
            return "\(winner) over the \(loser), \(max(a, h))–\(min(a, h))"
        }
        let pick = Formatters.splitPickAndOdds(r.pick_text).0
        return cashed ? "\(pick) cashed" : "\(pick) didn't land"
    }

    /// "Knicks @ Spurs · Final 105–95"
    private static func gameSubLine(_ r: GameResult) -> String {
        var bits: [String] = []
        if let (away, home, _, _) = Self.scoreParts(r) { bits.append("\(away) @ \(home)") }
        else if let m = r.matchup { bits.append(m) }
        if let fs = r.final_score, !fs.isEmpty { bits.append("Final \(fs)") }
        return bits.joined(separator: " · ")
    }

    /// "PHI 6 – 4 NYM · Final" cash-row title, falling back to short names.
    private static func gameCashTitle(_ g: GameResult) -> String {
        if let (away, home, a, h) = Self.scoreParts(g) {
            let lg = g.effectiveLeague
            return "\(teamAbbrev(away, league: lg)) \(a) – \(h) \(teamAbbrev(home, league: lg))"
        }
        return g.matchup ?? "Graded win"
    }

    /// Split "Away Team @ Home Team" + "5-4" into short names + scores.
    private static func scoreParts(_ r: GameResult) -> (away: String, home: String, a: Int, h: Int)? {
        guard let m = r.matchup else { return nil }
        let teams = m.components(separatedBy: " @ ")
        guard teams.count == 2 else { return nil }
        let away = Formatters.shortTeamName(teams[0], league: r.effectiveLeague)
        let home = Formatters.shortTeamName(teams[1], league: r.effectiveLeague)
        let nums = (r.final_score ?? "").components(separatedBy: CharacterSet(charactersIn: "-–"))
            .compactMap { Int($0.trimmingCharacters(in: .whitespaces)) }
        guard nums.count == 2 else { return nil }
        return (away, home, nums[0], nums[1])
    }

    /// Per-lane records from the graded ledger — HR Threats lead when present
    /// (the flagship fun lane), the rest by graded volume. Capped at 4.
    private static func buildReceiptLanes(_ rows: [SupabaseAPI.InsightLedgerRow]) -> [HomeReceiptsSection.LaneRecord] {
        let meta: [String: (String, String)] = [
            "gary_hr_threats": ("HR Threats", "flame"),
            "heat_check": ("Heat Checks", "chart.line.uptrend.xyaxis"),
            "platoon_edge": ("Platoon Edges", "arrow.left.arrow.right"),
            "regression_watch": ("Regression Watch", "chart.line.downtrend.xyaxis"),
            "ballpark": ("Ballpark Shifts", "building.columns"),
            "ballpark_shift": ("Ballpark Shifts", "building.columns"),
            "cooling_off": ("Cooling Off", "snowflake"),
            "owned": ("Owned Matchups", "person.fill.checkmark"),
            "beneficiary": ("Beneficiaries", "arrow.triangle.2.circlepath"),
            "rest_fatigue": ("Rest & Fatigue", "zzz"),
            "streak": ("Streaks", "bolt"),
            "tournament": ("Tournament Stakes", "trophy"),
            "situational": ("Situational", "scope"),
        ]
        var agg: [String: (hit: Int, miss: Int)] = [:]
        for r in rows {
            guard let c = r.category, let res = r.result else { continue }
            var a = agg[c] ?? (0, 0)
            if res == "hit" { a.hit += 1 } else if res == "miss" { a.miss += 1 }
            agg[c] = a
        }
        var lanes: [HomeReceiptsSection.LaneRecord] = agg.compactMap { key, rec in
            guard rec.hit + rec.miss > 0 else { return nil }
            let m = meta[key] ?? (key.split(separator: "_").map { $0.capitalized }.joined(separator: " "), "circle.grid.2x2")
            return .init(id: key, name: m.0, icon: m.1, hits: rec.hit, misses: rec.miss)
        }
        lanes.sort { a, b in
            if (a.id == "gary_hr_threats") != (b.id == "gary_hr_threats") { return a.id == "gary_hr_threats" }
            return (a.hits + a.misses) > (b.hits + b.misses)
        }
        return Array(lanes.prefix(4))
    }
}

// MARK: - Front Page Blocks (Home)

/// ③ The Marquee — last night's story as a static hero (no footage, no
/// logos: facts are free). League chip up top, the game headline, and the
/// receipt bar: "Gary had it · Phillies TT over 4.5 — CASHED +145".
struct HomeMarqueeHero: View {
    struct Story {
        let league: String
        var headline: String
        let sub: String
        let receiptLead: String   // "Gary had it" / "Gary was on" — prose voice
        let receiptPick: String   // "ANGELS ML" — data voice, rendered mono
        let verdict: String
        let cashed: Bool
        // The flip side — what Gary CALLED before the game played. Enriched
        // from that night's daily picks after the story is built; nil = the
        // card doesn't flip (no matching pick found).
        var take: String? = nil
        var tier: String? = nil
        /// The betting recap body (game_recaps) — the ESPN-style story of
        /// how the bet lived and died, under the headline.
        var recap: String? = nil
        /// Graded claims from the rationale (right/wrong only — "unclear"
        /// stays off the card). Empty = no fact check yet.
        var claims: [FactClaim] = []
        /// The night's stat lines, real prop prices attached (game_recaps
        /// bullets). Rendered mono under the recap.
        var bullets: [String] = []
    }
    let story: Story
    /// Carousel cards disable the flip (fixed-height pages); tap falls
    /// through to onTap instead.
    var flipEnabled: Bool = true
    /// Carousel pages fill a fixed frame so the receipt pins to the same
    /// bottom edge on every slide — the section below never jumps.
    var fillsHeight: Bool = false
    let onTap: () -> Void
    /// Carousel expand: when a toggle is provided, the card shows a MORE/LESS
    /// affordance and tapping it expands the full recap inline — the carousel
    /// grows the card and pauses auto-advance — instead of flipping/navigating.
    var isExpanded: Bool = false
    var onToggleExpand: (() -> Void)? = nil

    @State private var flipped = false
    @State private var frontH: CGFloat = 0

    private var tint: Color { Sport.from(league: story.league).accentColor }
    /// The league reads in its own accent — MLB in its white-green-brown field
    /// gradient (user call, Jun 17); every other league in its flat accent color.
    private var leagueStyle: AnyShapeStyle {
        (story.league == "MLB" || story.league == "MLB HR")
            ? AnyShapeStyle(GaryColors.mlbFieldText)
            : AnyShapeStyle(tint)
    }
    private var canFlip: Bool { flipEnabled && story.take != nil }
    private var verdictColor: Color { story.cashed ? GaryColors.win : GaryColors.lostTint }

    var body: some View {
        ZStack {
            front
                // In the carousel (fillsHeight) DON'T fix the vertical size — let the
                // card fill the uniform page height so every slide matches (a fixedSize
                // here shrank each card to its content, making the short-headline lead
                // card smaller than the rest). Single-card use still sizes to content.
                .fixedSize(horizontal: false, vertical: !fillsHeight)
                .background(GeometryReader { g in
                    Color.clear.preference(key: PickCardHeightKey.self, value: g.size.height)
                })
                .opacity(flipped ? 0 : 1)

            if canFlip {
                back
                    .opacity(flipped ? 1 : 0)
                    .rotation3DEffect(.degrees(180), axis: (x: 0, y: 1, z: 0))
            }
        }
        // fillsHeight (carousel): fill the parent's fixed frame so every slide is the
        // same height and the receipt pins to one bottom edge — no per-card measuring.
        .frame(height: flipped ? max(frontH + 150 + CGFloat(min(story.claims.count, 4)) * 38, 320) : (fillsHeight ? nil : (frontH > 0 ? frontH : nil)))
        .rotation3DEffect(.degrees(flipped ? 180 : 0), axis: (x: 0, y: 1, z: 0), perspective: 0.55)
        .onPreferenceChange(PickCardHeightKey.self) { frontH = $0 }
        .padding(.horizontal, 16)
        .contentShape(Rectangle())
        .onTapGesture {
            if let toggle = onToggleExpand {
                toggle()                              // grow/collapse the recap inline
            } else if canFlip {
                withAnimation(.spring(response: 0.6, dampingFraction: 0.82)) { flipped.toggle() }
            } else {
                onTap()
            }
        }
    }

    // MARK: Front — the news + the receipt stub

    private var front: some View {
        VStack(alignment: .leading, spacing: 0) {
            VStack(alignment: .leading, spacing: 0) {
                // The headline LEADS — full width, tight, at the very top (user call,
                // Jun 17). Nothing crowds it; the brand cues sit in the byline below.
                // The headline LEADS, with room on the right for the league chip
                // that now lives in the top-right corner (user call, Jun 18).
                Text(story.headline)
                    .font(GaryFonts.display(26))
                    .foregroundStyle(.white.opacity(0.96))
                    .fixedSize(horizontal: false, vertical: true)
                    .padding(.trailing, 40)
                    .padding(.bottom, 9)
                if let recap = story.recap, !recap.isEmpty {
                    if isExpanded {
                        // Expanded: the whole recap, no truncation — the carousel grows.
                        Text(recap)
                            .font(GaryFonts.text(12.5))
                            .foregroundStyle(.white.opacity(0.82))
                            .lineSpacing(2)
                            .fixedSize(horizontal: false, vertical: true)
                            .frame(maxWidth: .infinity, alignment: .topLeading)
                            .padding(.top, 8)
                    } else {
                        // A short, fixed recap (3 lines) so the bullets sit right beneath it —
                        // the old greedy fill stretched to the card height and left an unnatural
                        // gap above the bullets. The full recap is one tap away via MORE.
                        Text(recap)
                            .font(GaryFonts.text(12.5))
                            .foregroundStyle(.white.opacity(0.82))
                            .lineSpacing(2)
                            .lineLimit(3)
                            .truncationMode(.tail)
                            .fixedSize(horizontal: false, vertical: true)
                            .frame(maxWidth: .infinity, alignment: .topLeading)
                            .padding(.top, 8)
                    }
                }
                if !story.bullets.isEmpty {
                    bulletList.padding(.top, 10)
                }
                if onToggleExpand != nil, story.recap?.isEmpty == false {
                    HStack(spacing: 4) {
                        Text(isExpanded ? "LESS" : "MORE")
                            .font(GaryFonts.mono(8.5, bold: true)).tracking(1)
                        Image(systemName: "chevron.down")
                            .font(.system(size: 7, weight: .bold))
                            .rotationEffect(.degrees(isExpanded ? 180 : 0))
                    }
                    .foregroundStyle(GaryColors.gold.opacity(0.65))
                    .padding(.top, 8)
                }
            }
            .frame(maxWidth: .infinity, maxHeight: fillsHeight ? .infinity : nil, alignment: .topLeading)
            .padding(14)
            // The bear is an overlaid corner stamp now — it no longer takes a layout
            // row that crowds the story (user call, Jun 18). The text may run beneath
            // it; that's intended (no fight for space, no awkward gap).
            .overlay(alignment: .bottomTrailing) {
                Image(GaryBrand.mark)
                    .resizable().scaledToFit()
                    .frame(width: 38, height: 38)
                    .padding(.trailing, 10)
                    .padding(.bottom, 8)
                    .allowsHitTesting(false)
            }
            // The sport accent (WC / MLB) sits in the top-right corner — its own
            // league color, mirroring the bear stamp in the opposite corner.
            .overlay(alignment: .topTrailing) {
                HStack(spacing: 5) {
                    Circle().fill(tint.opacity(0.9)).frame(width: 5, height: 5)
                    Text(story.league)
                        .font(GaryFonts.mono(11, bold: true)).tracking(1.2)
                        .foregroundStyle(leagueStyle)
                }
                .padding(.trailing, 14)
                .padding(.top, 16)
            }
            if !story.receiptPick.isEmpty || !story.verdict.isEmpty {
                receiptStub(lead: story.receiptLead, pick: story.receiptPick,
                            trailing: story.verdict, hint: nil)
            }
        }
        .frame(maxHeight: fillsHeight ? .infinity : nil, alignment: .top)
        // Clean, sharp, simple black — no glow, no watermark (user call, Jun 17).
        // Branding lives in the gold GARY'S CALL eyebrow + the small corner bear mark.
        .background(RoundedRectangle(cornerRadius: 16, style: .continuous).fill(Color(hex: "#181616")))
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
        .overlay(RoundedRectangle(cornerRadius: 16, style: .continuous).stroke(Color.white.opacity(0.08), lineWidth: 1))
    }

    /// The night's stat lines — gold tick + mono, the data voice.
    private var bulletList: some View {
        VStack(alignment: .leading, spacing: 8) {
            ForEach(Array(story.bullets.prefix(3)), id: \.self) { (b: String) in
                HStack(alignment: .center, spacing: 9) {
                    Rectangle()
                        .fill(GaryColors.gold.opacity(0.8))
                        .frame(width: 10, height: 1.5)
                    Text(b)
                        .font(GaryFonts.mono(13))
                        .foregroundStyle(.white.opacity(0.96))
                        .lineLimit(1)
                        .minimumScaleFactor(0.88)
                }
            }
        }
    }

    // MARK: Back — what Gary called vs what the game did

    private var back: some View {
        VStack(alignment: .leading, spacing: 0) {
            VStack(alignment: .leading, spacing: 0) {
                HStack {
                    Text("THE CALL")
                        .font(GaryFonts.mono(10, bold: true)).tracking(1)
                        .foregroundStyle(GaryColors.gold)
                    Spacer()
                    Text("BEFORE THE GAME")
                        .font(GaryFonts.mono(9, bold: true)).tracking(1)
                        .foregroundStyle(.white.opacity(0.35))
                }
                .padding(.bottom, 14)

                // Gary's voice — gold rule (the app-wide quote marker).
                if let take = story.take {
                    HStack(alignment: .top, spacing: 10) {
                        RoundedRectangle(cornerRadius: 1)
                            .fill(GaryColors.gold.opacity(0.7))
                            .frame(width: 2)
                        Text(take)
                            .font(GaryFonts.text(13.5))
                            .foregroundStyle(.white.opacity(0.85))
                            .lineSpacing(3)
                            .lineLimit(8)
                            .minimumScaleFactor(0.85)
                    }
                }

                // The fact check — the rationale's claims, graded by the game.
                if !story.claims.isEmpty {
                    VStack(alignment: .leading, spacing: 7) {
                        Text("THE FACT CHECK")
                            .font(GaryFonts.mono(8.5, bold: true)).tracking(1.2)
                            .foregroundStyle(.white.opacity(0.35))
                        ForEach(Array(story.claims.prefix(4).enumerated()), id: \.offset) { _, c in
                            HStack(alignment: .top, spacing: 8) {
                                Text(c.verdict == "right" ? "✓" : "✗")
                                    .font(GaryFonts.mono(11, bold: true))
                                    .foregroundStyle(c.verdict == "right" ? Color(hex: "#3FB950") : Color(hex: "#E5484D"))
                                Text(c.claim ?? "")
                                    .font(.system(size: 12))
                                    .foregroundStyle(.white.opacity(0.7))
                                    .lineLimit(2)
                                    .fixedSize(horizontal: false, vertical: true)
                            }
                        }
                    }
                    .padding(.top, 12)
                }

                HStack(spacing: 14) {
                    if let tier = story.tier {
                        HStack(spacing: 6) {
                            Text("CONVICTION")
                                .font(GaryFonts.mono(8.5, bold: true)).tracking(1.2)
                                .foregroundStyle(.white.opacity(0.35))
                            Text(tier)
                                .font(GaryFonts.mono(11, bold: true))
                                .foregroundStyle(.white.opacity(0.85))
                        }
                    }
                    Spacer()
                    Button(action: onTap) {
                        Text("FULL CARD ›")
                            .font(GaryFonts.mono(9.5, bold: true)).tracking(1)
                            .foregroundStyle(.white.opacity(0.45))
                    }
                    .buttonStyle(.plain)
                }
                .padding(.top, 12)

                Spacer(minLength: 8)

                Text("tap to flip back  ↺")
                    .font(GaryFonts.mono(9, bold: false))
                    .foregroundStyle(.white.opacity(0.3))
                    .frame(maxWidth: .infinity, alignment: .center)
                    .padding(.bottom, 8)
            }
            .padding(14)

            receiptStub(lead: "How it played ·", pick: story.sub.uppercased(),
                        trailing: story.verdict, hint: nil)
        }
        .background(RoundedRectangle(cornerRadius: 16, style: .continuous).fill(Color(hex: "#181616")))
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
        .overlay(RoundedRectangle(cornerRadius: 16, style: .continuous).stroke(Color.white.opacity(0.08), lineWidth: 1))
    }

    // MARK: Shared pieces

    /// The ticket stub: dashed stitch perforation + full-bleed darker band.
    /// Prose lead, mono data, and the verdict as the row's ONLY color moment.
    private func receiptStub(lead: String, pick: String, trailing: String, hint: String?) -> some View {
        VStack(spacing: 0) {
            StitchLine()
                .stroke(Color.white.opacity(0.14), style: StrokeStyle(lineWidth: 1, dash: [4, 5]))
                .frame(height: 1)
            HStack(spacing: 6) {
                Text(lead)
                    .font(.system(size: 14))
                    .foregroundStyle(.white.opacity(0.72))
                Text(pick)
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(.white.opacity(0.95))
                    .lineLimit(1)
                    .minimumScaleFactor(0.7)
                Spacer(minLength: 8)
                if let hint {
                    Text(hint)
                        .font(GaryFonts.mono(10, bold: true)).tracking(0.8)
                        .foregroundStyle(.white.opacity(0.4))
                }
                Text(trailing)
                    .font(GaryFonts.mono(12.5, bold: true)).tracking(0.6)
                    .foregroundStyle(verdictColor)
            }
            .padding(.horizontal, 14)
            .padding(.vertical, 12)
            .background(Color.black.opacity(0.32))
        }
    }

}

