                            if let tag = r.tag {
                                Text(tag)
                                    .font(GaryFonts.mono(10, bold: true)).tracking(0.6)
                                    .foregroundStyle(r.tagWin ? Color(hex: "#3FB950") : Color(hex: "#E5484D"))
                            }
                        }
                        Text(r.headline)
                            .font(.system(size: 14.5, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.92))
                            .lineSpacing(2.5)
                            .fixedSize(horizontal: false, vertical: true)
                    }
                    .padding(.horizontal, 14).padding(.vertical, 11)
                    if i < rows.count - 1 {
                        Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
                    }
                }
            }
            .quantPanel()
            .padding(.horizontal, 16)
        }
    }
}

/// 7-DAY FORM — Gary's last-7-days GAME-pick record per sport, scoreboard style:
/// the title carries the window, each box shows only the sport and the record
/// (no units, no "7D" suffix). User pick, Jun 16 (the scoreboard-block direction).
struct HomeFormSection: View {
    let records: [SupabaseAPI.SportRecord]
    let yesterday: (wins: Int, losses: Int, pushes: Int)
    let onYesterday: () -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("7-DAY FORM")
                .font(GaryFonts.mono(10.5, bold: true)).tracking(1.6)
                .foregroundStyle(GaryColors.gold)
                .padding(.horizontal, 16)
            HStack(spacing: 10) {
                ForEach(records.prefix(2)) { r in
                    formBox(label: r.league == "WC" ? "WORLD CUP" : r.league,
                            record: r.pushes > 0 ? "\(r.wins)-\(r.losses)-\(r.pushes)" : "\(r.wins)-\(r.losses)",
                            labelStyle: leagueStyle(r.league))
                }
                // Yesterday's result as a MATCHING box (not a strip), minimal words —
                // taps into Winners (user call, Jun 17).
                if yesterday.wins + yesterday.losses + yesterday.pushes > 0 {
                    Button(action: onYesterday) {
                        formBox(label: "YESTERDAY",
                                record: yesterday.pushes > 0 ? "\(yesterday.wins)-\(yesterday.losses)-\(yesterday.pushes)" : "\(yesterday.wins)-\(yesterday.losses)",
                                labelStyle: AnyShapeStyle(GaryColors.gold))
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 16)
        }
    }

    /// MLB reads in its white-green-brown field gradient (user call, Jun 17); every
    /// other league in its flat accent color.
    private func leagueStyle(_ league: String) -> AnyShapeStyle {
        (league == "MLB" || league == "MLB HR")
            ? AnyShapeStyle(GaryColors.mlbFieldText)
            : AnyShapeStyle(Sport.from(league: league).accentColor)
    }

    private func formBox(label: String, record: String, labelStyle: AnyShapeStyle) -> some View {
        VStack(spacing: 6) {
            Text(label)
                .font(GaryFonts.mono(10, bold: true)).tracking(1.2)
                .foregroundStyle(labelStyle)
                .lineLimit(1).minimumScaleFactor(0.7)
            Text(record)
                .font(GaryFonts.display(34))
                .foregroundStyle(.white)
                .lineLimit(1).minimumScaleFactor(0.6)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 14)
        .background(RoundedRectangle(cornerRadius: 12, style: .continuous).fill(Color.white.opacity(0.02)))
        .overlay(RoundedRectangle(cornerRadius: 12, style: .continuous).stroke(Color.white.opacity(0.08), lineWidth: 1))
    }
}

struct HomeGarysForm: View {
    struct Model {
        let pips: [String]      // oldest → newest, the WHOLE graded history
        let story: String       // the editorial headline — what the data means
        let net: Double         // last-10 net units — the one colored number
        let total: Int          // graded count, for the footer affordance
    }
    let model: Model
    let onTap: () -> Void

    private let win = Color(hex: "#3FB950")
    private let loss = Color(hex: "#E5484D")

    /// Fills only — no outlines (fill contrast and weight carry the
    /// difference); older picks fade as they recede left, so the rail
    /// itself shows time direction.
    private func pip(_ p: String, age: Double) -> some View {
        let base: Color = p == "W" ? win : p == "L" ? loss : GaryColors.gold
        let isWin = p == "W"
        return Text(p)
            .font(GaryFonts.mono(10.5, bold: isWin))
            .foregroundStyle(base.opacity(isWin ? 0.95 : 0.6))
            .frame(width: 20, height: 24)
            .background(
                RoundedRectangle(cornerRadius: 5, style: .continuous)
                    .fill(base.opacity(isWin ? 0.16 : 0.09))
            )
            .opacity(0.35 + 0.65 * age)   // oldest 0.35 → newest 1.0
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            HubSectionHeader(eyebrow: "Gary's form", sub: "Newest on the right — drag for history")
            Button(action: onTap) {
                VStack(alignment: .leading, spacing: 0) {
                    // The headline: one sentence with a point of view, and the
                    // net as the single number the eye should land on.
                    HStack(alignment: .firstTextBaseline, spacing: 10) {
                        Text(model.story)
                            .font(GaryFonts.text(15, .semibold))
                            .foregroundStyle(.white.opacity(0.92))
                            .lineLimit(2)
                            .fixedSize(horizontal: false, vertical: true)
                        Spacer(minLength: 8)
                        Text(String(format: "%+.1fu", model.net))
                            .font(GaryFonts.mono(15, bold: true))
                            .foregroundStyle(model.net >= 0 ? win : loss)
                    }
                    .padding(.horizontal, 14).padding(.top, 13).padding(.bottom, 11)

                    // The rail — every graded pick, anchored at NOW.
                    ScrollViewReader { proxy in
                        ScrollView(.horizontal, showsIndicators: false) {
                            HStack(spacing: 4) {
                                ForEach(Array(model.pips.enumerated()), id: \.offset) { i, p in
                                    pip(p, age: model.pips.count > 1 ? Double(i) / Double(model.pips.count - 1) : 1)
                                        .id(i)
                                }
                            }
                            .padding(.horizontal, 14)
                        }
                        .onAppear { proxy.scrollTo(model.pips.count - 1, anchor: .trailing) }
                    }
                    .padding(.bottom, 12)
                    .accessibilityElement(children: .ignore)
                    .accessibilityLabel("Form, oldest to newest: \(model.pips.joined(separator: " "))")

                    Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1)

                    HStack {
                        Text("ALL \(model.total) GRADED")
                            .font(GaryFonts.mono(9.5, bold: true)).tracking(1)
                            .foregroundStyle(.white.opacity(0.45))
                        Spacer()
                        Image(systemName: "chevron.right")
                            .font(.system(size: 10, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.3))
                    }
                    .padding(.horizontal, 14).padding(.vertical, 10)
                }
                .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
            .quantPanel()
            .padding(.horizontal, 16)
        }
    }
}

/// League-wide market scoreboard for the settled night — overs, ML
/// favorites, dog flat-stake units. Data only, no commentary.
struct HomeMarketPulseStrip: View {
    let rows: [SupabaseAPI.MarketPulseRow]
    private var oversW: Int { rows.reduce(0) { $0 + ($1.overs_wins ?? 0) } }
    private var oversL: Int { rows.reduce(0) { $0 + ($1.overs_losses ?? 0) } }
    private var favW: Int { rows.reduce(0) { $0 + ($1.fav_wins ?? 0) } }
    private var favL: Int { rows.reduce(0) { $0 + ($1.fav_losses ?? 0) } }
    private var dogNet: Double { rows.reduce(0) { $0 + ($1.dog_net_units ?? 0) } }

    private func stat(_ v: String, _ k: String, _ color: Color = .white.opacity(0.92)) -> some View {
        VStack(alignment: .leading, spacing: 3) {
            Text(v).font(GaryFonts.mono(13.5, bold: true)).foregroundStyle(color)
            Text(k).font(GaryFonts.mono(8.5)).tracking(1.1).foregroundStyle(.white.opacity(0.35))
        }
    }

    var body: some View {
        HStack {
            stat("OVERS \(oversW)–\(oversL)", "LAST NIGHT")
            Spacer()
            stat("FAVES \(favW)–\(favL)", "ML")
            Spacer()
            stat(String(format: "DOGS %+.1fU", dogNet), "FLAT STAKES",
                 dogNet >= 0 ? Color(hex: "#3FB950") : Color(hex: "#E5484D"))
        }
        .padding(.vertical, 12).padding(.horizontal, 14)
        .quantPanel()
    }
}

/// The Wire — around-the-league items written from the bettor's seat:
/// results vs the closing number, line moves, injuries with the market
/// consequence, curated X voices (quoted behind a hairline rule).
struct HomeWireSection: View {
    let items: [SupabaseAPI.WireItem]
    let sub: String
    var pulse: [SupabaseAPI.MarketPulseRow] = []
    var limit: Int = 4
    /// The one open row — tap expands IN PLACE (no sheet, no overlay).
    @State private var expandedId: Int? = nil

    private func kindLabel(_ k: String?) -> String {
        switch k {
        case "result": return "FINAL"
        case "line_move": return "LINE MOVE"
        case "injury": return "INJURY"
        case "pace": return "PACE"
        default: return "WIRE"
        }
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            HubSectionHeader(eyebrow: "The Wire", sub: sub)
            if !pulse.isEmpty {
                HomeMarketPulseStrip(rows: pulse).padding(.horizontal, 16)
            }
            let shown = Array(items.prefix(limit))
            if !shown.isEmpty {
                VStack(spacing: 0) {
                    ForEach(Array(shown.enumerated()), id: \.element.id) { i, item in
                        wireRow(item)
                        if i < shown.count - 1 {
                            Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
                        }
                    }
                }
                .quantPanel()
                .padding(.horizontal, 16)
            }
        }
    }

    @ViewBuilder private func wireRow(_ item: SupabaseAPI.WireItem) -> some View {
        let isVoice = item.kind == "voice"
        let rid = item.id ?? -1
        let expanded = expandedId == rid
        VStack(alignment: .leading, spacing: 6) {
            HStack(spacing: 7) {
                if isVoice {
                    Text("𝕏")
                        .font(.system(size: 10, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.5))
                    Text((item.source_handle ?? "").uppercased())
                        .font(GaryFonts.mono(9, bold: true)).tracking(0.5)
                        .foregroundStyle(.white.opacity(0.35))
                } else {
                    // The league word IS the color chip — no status dot.
                    Text((item.league ?? "").uppercased())
                        .font(GaryFonts.mono(9, bold: true)).tracking(0.5)
                        .foregroundStyle(Sport.from(league: item.league ?? "").accentColor.opacity(0.95))
                    Text("· \(kindLabel(item.kind))")
                        .font(GaryFonts.mono(9, bold: true)).tracking(0.5)
                        .foregroundStyle(.white.opacity(0.35))
                }
                Spacer(minLength: 6)
                Image(systemName: "chevron.down")
                    .font(.system(size: 9, weight: .semibold))
                    .foregroundStyle(.white.opacity(0.3))
                    .rotationEffect(.degrees(expanded ? 180 : 0))
            }
            Text(item.headline ?? "")
                .font(.system(size: 14.5, weight: .semibold))
                .foregroundStyle(.white.opacity(0.92))
                .lineSpacing(2.5)
                .fixedSize(horizontal: false, vertical: true)
                .padding(.leading, isVoice ? 11 : 0)
                .overlay(alignment: .leading) {
                    if isVoice {
                        Rectangle().fill(Color.white.opacity(0.14)).frame(width: 2)
                    }
                }
            if let subline = item.subline, !subline.isEmpty {
                // Sentence-length text in the reading face, not tracked mono
                // (four horsemen #2) — and bright enough to actually read.
                Text(subline)
                    .font(.system(size: 12))
                    .foregroundStyle(.white.opacity(0.5))
                    .lineSpacing(2)
                    .lineLimit(expanded ? nil : 2)
                    .fixedSize(horizontal: false, vertical: true)
            }
            // The deeper read, unfolded in place — never a sheet.
            if expanded, let body = item.meta?.body, !body.isEmpty {
                Text(body)
                    .font(.system(size: 12))
                    .foregroundStyle(.white.opacity(0.66))
                    .lineSpacing(2.5)
                    .fixedSize(horizontal: false, vertical: true)
                    .padding(.top, 2)
            }
        }
        .padding(.vertical, 12).padding(.horizontal, 14)
        .frame(maxWidth: .infinity, alignment: .leading)
        .contentShape(Rectangle())
        .onTapGesture {
            withAnimation(.spring(response: 0.35, dampingFraction: 0.85)) {
                expandedId = expanded ? nil : rid
            }
        }
    }
}

/// The World Cup front-page module — a bettor's first look during the
/// tournament window. Leads with the day's headline storyline, then today's
/// OPENER (the first match, where bettors get their action in), then the rest
/// of the day's board. From the run-up it carries the countdown + storylines;
/// once matches post it carries the opener + board. WC teal stays a small
/// accent — gold remains the signature pick colour.
struct HomeWorldCupModule: View {
    let countdownDays: Int?
    let headline: SupabaseAPI.WireItem?
    let storylines: [SupabaseAPI.WireItem]
    let opener: GaryPick?
    let board: [GaryPick]
    let onOpenHub: () -> Void
    let onOpenWinners: () -> Void

    private let teal = Color(hex: "#14B8A6")
    private var hasMatches: Bool { opener != nil || !board.isEmpty }

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            HubSectionHeader(eyebrow: "The World Cup", sub: "")
            VStack(spacing: 0) {
                if let h = headline {
                    Button(action: onOpenHub) { headlineRow(h) }.buttonStyle(.plain)
                }
                if let op = opener {
                    divider
                    Button(action: onOpenWinners) { matchRow(op, isOpener: true) }.buttonStyle(.plain)
                }
                ForEach(board) { p in
                    divider
                    Button(action: onOpenWinners) { matchRow(p, isOpener: false) }.buttonStyle(.plain)
                }
                // Run-up: no matches yet — carry a couple more storylines so the
                // module still reads as a living front page before the slate posts.
                if !hasMatches {
                    ForEach(storylines) { s in
                        divider
                        Button(action: onOpenHub) { headlineRow(s, compact: true) }.buttonStyle(.plain)
                    }
                }
            }
            .quantPanel()
            .padding(.horizontal, 16)
        }
    }

    private var divider: some View {
        Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
    }

    // The lead storyline — the sneak-peek headline a bettor opens to.
    @ViewBuilder private func headlineRow(_ item: SupabaseAPI.WireItem, compact: Bool = false) -> some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(spacing: 7) {
                Circle().fill(teal).frame(width: 6, height: 6)
                Text(compact ? "WORLD CUP · WIRE" : "TODAY'S HEADLINE")
                    .font(GaryFonts.mono(9, bold: true)).tracking(1.2)
                    .foregroundStyle(.white.opacity(0.35))
            }
            Text(item.headline ?? "")
                .font(.system(size: compact ? 14.5 : 17, weight: compact ? .semibold : .bold))
                .foregroundStyle(.white.opacity(compact ? 0.9 : 0.96))
                .lineSpacing(2)
                .fixedSize(horizontal: false, vertical: true)
            if !compact, let sub = item.subline, !sub.isEmpty {
                Text(sub)
                    .font(.system(size: 12))
                    .foregroundStyle(.white.opacity(0.5))
                    .lineSpacing(2)
                    .fixedSize(horizontal: false, vertical: true)
            }
        }
        .padding(.vertical, 13).padding(.horizontal, 14)
        .frame(maxWidth: .infinity, alignment: .leading)
        .contentShape(Rectangle())
    }

    // A match row — the opener gets a teal ⭐ and larger type (the first game,
    // ready to bet); board games are compact.
    @ViewBuilder private func matchRow(_ p: GaryPick, isOpener: Bool) -> some View {
        HStack(spacing: 12) {
            VStack(spacing: 2) {
                Text(kickoffTime(p))
                    .font(GaryFonts.mono(isOpener ? 12 : 11, bold: true))
                    .foregroundStyle(teal)
                if isOpener {
                    Image(systemName: "star.fill").font(.system(size: 8)).foregroundStyle(teal.opacity(0.8))
                }
            }
            .frame(width: 58, alignment: .leading)

            VStack(alignment: .leading, spacing: 3) {
                Text(matchupLabel(p))
                    .font(.system(size: isOpener ? 17 : 14, weight: isOpener ? .bold : .semibold))
                    .foregroundStyle(.white.opacity(0.95))
                    .lineLimit(1).minimumScaleFactor(0.8)
                if isOpener, let ctx = p.soccerContext {
                    Text(ctx.uppercased())
                        .font(GaryFonts.mono(9)).tracking(0.8)
                        .foregroundStyle(.white.opacity(0.4))
                }
                if let pick = p.pick, !pick.isEmpty {
                    Text(pick)
                        .font(GaryFonts.mono(isOpener ? 12 : 11, bold: true))
                        .foregroundStyle(GaryColors.gold)
                        .lineLimit(1).minimumScaleFactor(0.8)
                }
            }
            Spacer(minLength: 6)
            Image(systemName: "chevron.right").font(.system(size: 11, weight: .semibold))
                .foregroundStyle(.white.opacity(0.25))
        }
        .padding(.vertical, isOpener ? 13 : 11).padding(.horizontal, 14)
        .frame(maxWidth: .infinity, alignment: .leading)
        .contentShape(Rectangle())
    }

    /// "USA vs MEX" — nations read cleanly already; away-at-home order.
    private func matchupLabel(_ p: GaryPick) -> String {
        let away = (p.awayTeam ?? "").trimmingCharacters(in: .whitespaces)
        let home = (p.homeTeam ?? "").trimmingCharacters(in: .whitespaces)
        if away.isEmpty || home.isEmpty { return away.isEmpty ? home : away }
        return "\(away) vs \(home)"
    }

    /// Display kickoff: the pick's `time` if present, else derived from the ISO.
    private func kickoffTime(_ p: GaryPick) -> String {
        if let t = p.time, !t.isEmpty { return t }
        guard let iso = p.commence_time, let d = ISO8601DateFormatter().date(from: iso) else { return "—" }
        let f = DateFormatter()
        f.timeZone = TimeZone(identifier: "America/New_York")
        f.dateFormat = "h:mm a"
        return f.string(from: d)
    }
}

/// A box score where the columns are props: PLAYER / LINE / RESULT / grade.
struct HomePropBoxSection: View {
    struct Row: Identifiable {
        let id = UUID()
        let player: String   // "BETTS"
        let line: String     // "O 1.5 TB"
        let actual: String   // "3 TB"
        let state: String?   // won | lost | push
        /// Team color for the middle column — official colors carry the
        /// legibility the small grey mono couldn't.
        var tint: Color? = nil
    }
    /// One read on the night (THE BOX / HR / 2+ HITS / K SHOW).
    struct Tab {
        let label: String
        let title: String
        let status: String
        let cols: (String, String, String)
        let rows: [Row]
        /// THE BOX only: a game picker (ALL = 2 winners + 2 losers, then one entry
        /// per game Gary had props in). nil on the night-board tabs.
        var gameOptions: [GameOption]? = nil
    }
    /// One choice in THE BOX's game dropdown.
    struct GameOption: Identifiable {
        let id = UUID()
        let label: String     // "ALL" or "Angels 9 · Athletics 7"
        let status: String    // "LAST NIGHT" (ALL) or "FINAL" (a game)
        let rows: [Row]
    }
    let tabs: [Tab]
    let onOpen: () -> Void
    @State private var selectedTab = 0
    @State private var selectedGame = 0

    init(tabs: [Tab], onOpen: @escaping () -> Void) {
        self.tabs = tabs
        self.onOpen = onOpen
    }

    private var tab: Tab { tabs[min(selectedTab, tabs.count - 1)] }

    /// Plain mono text tabs — active wears gold, the rest dim (the app-wide
    /// colored-when-active rule; no capsules).
    private var tabStrip: some View {
        HStack(spacing: 18) {
            ForEach(Array(tabs.enumerated()), id: \.offset) { i, t in
                Button {
                    withAnimation(.easeInOut(duration: 0.15)) { selectedTab = i }
                } label: {
                    Text(t.label)
                        .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                        .foregroundStyle(i == selectedTab ? GaryColors.gold : .white.opacity(0.4))
                        .frame(minHeight: 30)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
            }
            Spacer()
        }
        .padding(.horizontal, 2)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HubSectionHeader(eyebrow: "Prop box", sub: "")
            if tabs.count > 1 { tabStrip.padding(.horizontal, 16) }
            VStack(spacing: 0) {
                titleRow   // game dropdown on THE BOX, static label elsewhere
                Rectangle().fill(Color.white.opacity(0.1)).frame(height: 1)
                gridHeader
                Button(action: onOpen) {
                    VStack(spacing: 0) {
                        ForEach(currentRows) { row in
                            Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
                            boxRow(row)
                        }
                    }
                    .frame(maxWidth: .infinity)
                    .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
            }
            .background(Color(hex: "#181616"))
            .clipShape(RoundedRectangle(cornerRadius: 12))
            .overlay(RoundedRectangle(cornerRadius: 12).stroke(Color.white.opacity(0.07), lineWidth: 1))
            .padding(.horizontal, 16)
        }
    }

    /// The title line — a game DROPDOWN for THE BOX (default ALL → 2 winners + 2
    /// losers; pick a game for its props), a static label on the other tabs.
    @ViewBuilder private var titleRow: some View {
        HStack {
            if let opts = tab.gameOptions, !opts.isEmpty {
                let sel = opts[min(selectedGame, opts.count - 1)]
                Menu {
                    ForEach(Array(opts.enumerated()), id: \.offset) { i, o in
                        Button(o.label) { selectedGame = i }
                    }
                } label: {
                    HStack(spacing: 5) {
                        Text(sel.label)
                            .font(GaryFonts.mono(13, bold: true))
                            .foregroundStyle(.white.opacity(0.92))
                            .lineLimit(1).minimumScaleFactor(0.7)
                        Image(systemName: "chevron.down")
                            .font(.system(size: 9, weight: .bold))
                            .foregroundStyle(GaryColors.gold.opacity(0.85))
                    }
                }
            } else {
                Text(tab.title)
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(.white.opacity(0.92))
                    .lineLimit(1).minimumScaleFactor(0.7)
            }
            Spacer()
            Text(currentStatus)
                .font(GaryFonts.mono(9, bold: true)).tracking(1.4)
                .foregroundStyle(.white.opacity(0.35))
        }
        .padding(.vertical, 11).padding(.horizontal, 14)
    }

    /// Rows + status follow the selected game on THE BOX, the tab otherwise.
    private var currentRows: [Row] {
        if let opts = tab.gameOptions, !opts.isEmpty {
            return opts[min(selectedGame, opts.count - 1)].rows
        }
        return tab.rows
    }
    private var currentStatus: String {
        if let opts = tab.gameOptions, !opts.isEmpty {
            return opts[min(selectedGame, opts.count - 1)].status
        }
        return tab.status
    }

    private var gridHeader: some View {
        HStack(spacing: 8) {
            Text(tab.cols.0).frame(width: 108, alignment: .leading)
            Text(tab.cols.1).frame(width: 64, alignment: .leading)
            Text(tab.cols.2).frame(maxWidth: .infinity, alignment: .trailing)
            Text("✓").frame(width: 22, alignment: .center)
        }
        .font(GaryFonts.mono(8.5)).tracking(1.2)
        .foregroundStyle(.white.opacity(0.45))
        .padding(.vertical, 8).padding(.horizontal, 14)
    }

    private func boxRow(_ row: Row) -> some View {
        HStack(spacing: 8) {
            Text(row.player)
                .font(GaryFonts.mono(12, bold: true))
                .foregroundStyle(Color(hex: "#CCC7C7"))
                .lineLimit(1).minimumScaleFactor(0.7)
                .frame(width: 108, alignment: .leading)
            Text(row.line)
                .font(GaryFonts.mono(10.5, bold: row.tint != nil))
                .foregroundStyle(row.tint ?? .white.opacity(0.45))
                .lineLimit(1).minimumScaleFactor(0.7)
                .frame(width: 64, alignment: .leading)
            Text(row.actual)
                .font(GaryFonts.mono(11.5, bold: true))
                .foregroundStyle(.white.opacity(0.92))
                .lineLimit(1).minimumScaleFactor(0.75)
                .frame(maxWidth: .infinity, alignment: .trailing)
            Group {
                switch row.state {
                case "won":  Text("✓").foregroundStyle(Color(hex: "#3FB950"))
                case "lost": Text("✗").foregroundStyle(Color(hex: "#E5484D"))
                default:     Text("–").foregroundStyle(.white.opacity(0.35))
                }
            }
            .font(.system(size: 11, weight: .bold))
            .frame(width: 22, alignment: .center)
        }
        .padding(.vertical, 9).padding(.horizontal, 14)
    }
}

/// Horizontal live ticker: score + state for every game Gary has a side in,
/// edged green/red by where the pick stands.
struct HomeLiveTape: View {
    struct Cell: Identifiable {
        let id: String
        let eyebrow: String
        let line: String
        let status: String
        let tone: HomeLiveVerdict
        let isLive: Bool
    }
    let cells: [Cell]
    let onTap: () -> Void

    private func toneColor(_ t: HomeLiveVerdict) -> Color? {
        switch t {
        case .covering: return Color(hex: "#3FB950")
        case .trailing: return Color(hex: "#E5484D")
        case .neutral: return nil
        }
    }

    var body: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 8) {
                ForEach(cells) { cell in
                    Button(action: onTap) {
                        VStack(alignment: .leading, spacing: 5) {
                            HStack(spacing: 6) {
                                if cell.isLive {
                                    HomeStatusDot(color: toneColor(cell.tone) ?? GaryColors.gold)
                                }
                                Text(cell.eyebrow)
                                    .font(GaryFonts.mono(8.5, bold: true)).tracking(0.5)
                                    .foregroundStyle(.white.opacity(0.35))
                            }
                            Text(cell.line)
                                .font(GaryFonts.mono(13, bold: true))
                                .foregroundStyle(.white.opacity(0.92))
                            Text(cell.status)
                                .font(GaryFonts.mono(9, bold: true)).tracking(0.8)
                                .foregroundStyle(.white.opacity(0.45))
                                .lineLimit(1)
                        }
                        .padding(.vertical, 10).padding(.horizontal, 12)
                        .frame(minWidth: 124, alignment: .leading)
                        .background(Color(hex: "#181616"))
                        .clipShape(RoundedRectangle(cornerRadius: 10))
                        .overlay(RoundedRectangle(cornerRadius: 10).stroke(Color.white.opacity(0.07), lineWidth: 1))
                        .overlay(alignment: .leading) {
                            if let c = toneColor(cell.tone) {
                                RoundedRectangle(cornerRadius: 1.5).fill(c)
                                    .frame(width: 2.5).padding(.vertical, 1)
