    private func openCheckout(_ league: String, surface: String = "storefront") {
        // Subscriptions need an owner — no checkout without an account
        // (cancel/manage requires identity; device-bound subs are a trap).
        guard authManager.isAuthenticated else {
            SupabaseAPI.logEvent("checkout_blocked_signin", ["sport": league, "surface": surface])
            showAuthSheet = true; return
        }
        guard let base = Self.checkoutLinks[league],
              let url = URL(string: "\(base)?client_reference_id=\(SupabaseAPI.identityId)") else { return }
        SupabaseAPI.logEvent("checkout_started", [
            "plan": league == "ALL" ? "all_access"
                  : (league == "ALL_ANNUAL" ? "all_access_annual"
                  : (league == "WC" ? "world_cup" : "single")),
            "sport": league, "surface": surface,
        ])
        checkoutItem = CheckoutItem(url: url)
    }
    @State private var sportRecords: [String: (w: Int, l: Int)] = [:]
    @Namespace private var tabNS

    // In-season / imminent sports shown as rows (placeholders when a sport has no pick yet).
    // Any extra league present in the data is appended automatically.
    // Every sport Gary actually covers — lanes hold placeholders off-slate.
    private let canonicalSports = ["MLB", "NBA", "NHL", "WC", "NFL", "NCAAF", "NCAAB"]
    // Sports with a props product (WC + college are game picks only).
    private let propSports = ["MLB", "NBA", "NHL", "NFL"]

    // MARK: - Terminal status / tab counts (all derived from loaded view state)

    private var gameCount: Int { gameShelves.filter { !$0.settled }.reduce(0) { $0 + $1.picks.count } }
    private var propCount: Int { propShelves.filter { !$0.settled }.reduce(0) { $0 + $1.props.count } }

    struct GameShelf: Identifiable {
        let league: String
        let picks: [GaryPick]   // empty => placeholder row
        let settled: Bool       // true => last result (show W/L stamps)
        var id: String { league }
    }
    struct PropShelf: Identifiable {
        let league: String
        let props: [PropPick]
        let settled: Bool       // true => yesterday's props (show W/L stamps)
        var id: String { league }
    }

    private var hasContent: Bool {
        gameShelves.contains { !$0.picks.isEmpty } || propShelves.contains { !$0.props.isEmpty }
    }
    /// Fresh = a pick for TODAY (settled == false, non-empty). Yesterday's
    /// last-result fallback (settled == true) and empty slate placeholders don't count.
    private var todayHasFreshPicks: Bool {
        gameShelves.contains { !$0.settled && !$0.picks.isEmpty }
        || propShelves.contains { !$0.settled && !$0.props.isEmpty }
    }
    /// On TODAY with nothing fresh yet, show the "board drops soon" state (blurred
    /// placeholder cards) instead of yesterday's results — those live under the date
    /// menu's Yesterday. A chosen past date always renders its own graded board.
    private var isTodayComingSoon: Bool {
        selectedDate == nil && !todayHasFreshPicks
    }

    var body: some View {
        ZStack {
            LiquidGlassBackground(grainDensity: 0)

            ScrollViewReader { proxy in
                ScrollView(showsIndicators: false) {
                    // Toggle scrolls WITH the page (unpinned) — pinning forced an
                    // opaque fill that could never match the gradient behind it.
                    LazyVStack(alignment: .leading, spacing: 0) {
                        header

                        if loading {
                            HStack { Spacer(); ProgressView().tint(GaryColors.gold).scaleEffect(1.2); Spacer() }
                                .padding(.top, 80)
                        } else if isTodayComingSoon {
                            comingSoonState
                        } else if !hasContent {
                            emptyState
                        } else {
                            Section {
                                jumpBar(proxy)
                                modeContent
                                    .padding(.top, 16)
                                    .padding(.bottom, 120)
                            } header: {
                                toggleBar
                            }
                        }
                    }
                }
                .refreshable { await reload() }
            }
        }
        .task { await reload() }
        .onChange(of: selectedDate) { _ in Task { await reload() } }
        .onChange(of: scenePhase) { phase in
            // Returning from Stripe checkout — pick up new grants; and silently
            // re-pull today's board (a chosen past date stays static).
            if phase == .active {
                Task { entitledSports = await SupabaseAPI.fetchEntitlements() }
                if selectedDate == nil { Task { await reload() } }
            }
        }
        .onChange(of: authManager.isAuthenticated) { _ in
            // Sign-in/out swaps the identity entitlements key on — refetch.
            Task { entitledSports = await SupabaseAPI.fetchEntitlements() }
        }
        .sheet(isPresented: $showAuthSheet) { AuthView(startInSignUp: true) }
        .sheet(isPresented: $showPlansSheet, onDismiss: {
            if pendingAuth { pendingAuth = false; showAuthSheet = true }
            if let lg = pendingCheckout { pendingCheckout = nil; openCheckout(lg, surface: "paywall_sheet") }
            if let bundle = pendingBundle { pendingBundle = nil; openBundleCheckout(bundle) }
        }) {
            PlansSheetView(focus: plansFocus,
                           signedIn: authManager.isAuthenticated,
                           onSelect: { lg in pendingCheckout = lg; showPlansSheet = false },
                           onBundle: { lgs in pendingBundle = lgs; showPlansSheet = false },
                           onAccount: { pendingAuth = true; showPlansSheet = false })
        }
        .sheet(item: $checkoutItem, onDismiss: {
            // In-app checkout doesn't background the app, so scenePhase never
            // fires — pick up fresh grants the moment the sheet closes.
            Task { entitledSports = await SupabaseAPI.fetchEntitlements() }
        }) { item in
            SafariView(url: item.url).ignoresSafeArea()
        }
        .onAppear {
            // Debug arg (-previewPlans 1): jump straight to the plans sheet —
            // same family as -forceTab / -previewPhase. DEBUG-only: in a
            // release build the plans sheet (external Stripe checkout) must
            // be unreachable while freeLaunch is on (App Store 3.1.1).
            #if DEBUG
            if UserDefaults.standard.bool(forKey: "previewPlans") { showPlansSheet = true }
            #endif
        }
    }

    /// Identifiable URL wrapper for the in-app checkout sheet.
    fileprivate struct CheckoutItem: Identifiable {
        let url: URL
        var id: String { url.absoluteString }
    }

    /// Bundle checkout goes through the create-checkout edge function — the
    /// picked sports ride in session metadata. Same sign-in gate as links.
    private func openBundleCheckout(_ leagues: [String]) {
        guard authManager.isAuthenticated else { showAuthSheet = true; return }
        Task {
            if let url = await SupabaseAPI.createCheckout(leagues: leagues) {
                await MainActor.run { checkoutItem = CheckoutItem(url: url) }
            }
        }
    }

    /// Sport chips that jump the page to a league's shelf in the active mode.
    /// Left-aligned with fixed 24pt gaps (elastic columns made optically
    /// unequal gaps); rhymes with GAMES/PROPS above. Scrolls if it overflows.
    /// A chip wears its sport color only when it's the one you jumped to.
    private func jumpBar(_ proxy: ScrollViewProxy) -> some View {
        let leagues = mode == .games ? gameShelves.map(\.league) : propShelves.map(\.league)
        return ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 24) {
                ForEach(leagues, id: \.self) { lg in
                    Button {
                        withAnimation(.easeInOut(duration: 0.2)) { jumpedLeague = lg }
                        withAnimation(.easeInOut(duration: 0.35)) {
                            proxy.scrollTo((mode == .games ? "g-" : "p-") + lg, anchor: .top)
                        }
                    } label: {
                        Text(lg)
                            .font(GaryFonts.mono(12, bold: true)).tracking(0.8)
                            .foregroundStyle(jumpChipStyle(lg))
                            .lineLimit(1)
                            .frame(minHeight: 44)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 16)
        }
    }

    private func jumpChipStyle(_ lg: String) -> AnyShapeStyle {
        guard jumpedLeague == lg else { return AnyShapeStyle(Color.white.opacity(0.38)) }
        if lg == "MLB" { return AnyShapeStyle(GaryColors.mlbFieldText) }
        return AnyShapeStyle(Sport.from(league: lg).accentColor)
    }

    // MARK: - Header / states

    // The locked masthead formula — the last header in the app to adopt it.
    // One commanding title, the date as quiet meta, yesterday's record as a
    // single labeled badge (tap -> Billfold), gold stitch. PREMIUM pill,
    // AWAITING SLATE, and league chips all retired: the body owns its states
    // and the shelves announce their own leagues.
    private var header: some View {
        GaryPageHeader(title: "Winners", accentMenu: AnyView(
            Menu {
                ForEach(0..<8, id: \.self) { offset in
                    Button(daySelectorLabel(offset)) {
                        withAnimation { selectedDate = offset == 0 ? nil : dayDateString(offset) }
                    }
                }
            } label: {
                HStack(spacing: 5) {
                    Text(headerDateLabel)
                        .font(GaryFonts.mono(10)).foregroundStyle(.white.opacity(0.55)).lineLimit(1)
                    Image(systemName: "chevron.down")
                        .font(.system(size: 8, weight: .bold)).foregroundStyle(.white.opacity(0.4))
                }
            }
        ))
            .padding(.bottom, 8)
    }

    /// Long-form date for the header dropdown trigger — "Thursday, June 18" today,
    /// or the chosen day. Replaces the old "TODAY ▾" pill.
    private var headerDateLabel: String {
        guard let d = selectedDate else { return GaryPageHeader<EmptyView>.dateLabel() }
        let inF = DateFormatter(); inF.dateFormat = "yyyy-MM-dd"
        inF.timeZone = TimeZone(identifier: "America/New_York")
        guard let date = inF.date(from: d) else { return d }
        let outF = DateFormatter(); outF.dateFormat = "EEEE, MMMM d"; outF.timeZone = inF.timeZone
        return outF.string(from: date)
    }

    private var emptyState: some View {
        VStack(spacing: 12) {
            Image(systemName: selectedDate == nil ? "lock.badge.clock" : "calendar.badge.exclamationmark")
                .font(.system(size: 42)).foregroundStyle(.white.opacity(0.25))
            Text(selectedDate == nil
                 ? "Gary's best bets post a few hours before first pitch."
                 : "No graded picks on this day.")
                .font(GaryFonts.text(14)).foregroundStyle(.white.opacity(0.5))
                .multilineTextAlignment(.center)
        }
        .frame(maxWidth: .infinity).padding(.horizontal, 30).padding(.top, 60)
    }

    /// TODAY, before Gary's board posts: real-looking pick cards with ONLY the
    /// pick fields (the call, the matchup, the time) blurred — the card chrome,
    /// eyebrow, Gary mark and affordances stay SHARP so the design reads through.
    /// The "drops soon" message floats centered in the foreground; the cards sit
    /// behind it, and the date menu in the header still opens past graded days.
    private var comingSoonState: some View {
        VStack(spacing: 0) {
            if comingSoonDismissed { comingSoonStrip.padding(.horizontal, 16).padding(.bottom, 4) }
            VStack(spacing: 14) {
                comingSoonCard
                comingSoonCard
                comingSoonCard
            }
            .padding(.horizontal, 16)
            .padding(.top, comingSoonDismissed ? 6 : 16)
            .padding(.bottom, 120)
            .opacity(comingSoonDismissed ? 1 : 0.9)
            .allowsHitTesting(false)
        }
        .overlay(alignment: .center) {
            if !comingSoonDismissed {
                comingSoonPopup.padding(.horizontal, 30)
                    .transition(.scale(scale: 0.92).combined(with: .opacity))
            }
        }
    }

    /// The dismissible "drops soon" pop-up — readable over the cards behind it.
    /// Tapping the X collapses it to `comingSoonStrip` so the cards open up.
    private var comingSoonPopup: some View {
        VStack(spacing: 10) {
            Image(systemName: "clock.badge")
                .font(.system(size: 30)).foregroundStyle(GaryColors.gold)
            Text("Tonight's board drops soon")
                .font(GaryFonts.text(18, .semibold)).foregroundStyle(.white)
            Text("It's still early — Gary posts his picks a few hours before the games start. Pull to refresh, or use the date menu up top for past days' results.")
                .font(GaryFonts.text(13)).foregroundStyle(.white.opacity(0.7))
                .multilineTextAlignment(.center).lineSpacing(2)
        }
        .padding(.vertical, 24).padding(.horizontal, 22)
        .background(RoundedRectangle(cornerRadius: 20).fill(Color.black.opacity(0.9)))
        .overlay(RoundedRectangle(cornerRadius: 20).stroke(GaryColors.gold.opacity(0.18), lineWidth: 1))
        .overlay(alignment: .topTrailing) {
            Button {
                withAnimation(.spring(response: 0.4, dampingFraction: 0.85)) { comingSoonDismissed = true }
            } label: {
                Image(systemName: "xmark")
                    .font(.system(size: 11, weight: .bold))
                    .foregroundStyle(.white.opacity(0.55))
                    .padding(8)
                    .background(Circle().fill(Color.white.opacity(0.08)))
                    .padding(10)
            }
            .buttonStyle(.plain)
        }
        .shadow(color: .black.opacity(0.5), radius: 24, y: 10)
    }

    /// The collapsed reminder — one compact strip at the top once dismissed.
    private var comingSoonStrip: some View {
        HStack(spacing: 9) {
            Image(systemName: "clock.badge").font(.system(size: 13)).foregroundStyle(GaryColors.gold)
            Text("Tonight's board drops soon — Gary posts a few hours before games. Date menu up top has past results.")
                .font(GaryFonts.text(12)).foregroundStyle(.white.opacity(0.6))
                .fixedSize(horizontal: false, vertical: true)
            Spacer(minLength: 0)
        }
        .padding(.vertical, 10).padding(.horizontal, 13)
        .background(RoundedRectangle(cornerRadius: 12).fill(Color.white.opacity(0.04)))
        .overlay(RoundedRectangle(cornerRadius: 12).stroke(GaryColors.gold.opacity(0.12), lineWidth: 1))
    }

    /// A pick card with the design intact — eyebrow, Gary mark, divider and
    /// affordances stay SHARP; only the call, matchup and time blur (the data
    /// that isn't posted yet). Same footprint as a real Winners card.
    private var comingSoonCard: some View {
        VStack(alignment: .leading, spacing: 0) {
            // Eyebrow + Gary mark — sharp chrome
            HStack(alignment: .top) {
                Text("GARY'S PICK")
                    .font(GaryFonts.mono(12, bold: true)).tracking(0.5)
                    .foregroundStyle(GaryColors.gold)
                Spacer()
                Image(GaryBrand.mark).resizable().scaledToFit().frame(width: 36, height: 36)
            }
            // The call — blurred
            VStack(alignment: .leading, spacing: 8) {
                RoundedRectangle(cornerRadius: 5).fill(.white.opacity(0.18)).frame(width: 188, height: 22)
                RoundedRectangle(cornerRadius: 5).fill(.white.opacity(0.18)).frame(width: 128, height: 22)
            }
            .blur(radius: 4).padding(.top, 16)
            // Matchup · odds — blurred; share affordance sharp
            HStack(spacing: 8) {
                RoundedRectangle(cornerRadius: 4).fill(.white.opacity(0.13)).frame(width: 172, height: 13).blur(radius: 3.5)
                Spacer()
                Image(systemName: "square.and.arrow.up").font(.system(size: 15)).foregroundStyle(.white.opacity(0.45))
            }
            .padding(.top, 16)
            // Divider — sharp
            Rectangle().fill(.white.opacity(0.08)).frame(height: 1).padding(.top, 14)
            // Time + chevron — time blurred, chevron sharp
            HStack {
                RoundedRectangle(cornerRadius: 4).fill(GaryColors.gold.opacity(0.55)).frame(width: 70, height: 12).blur(radius: 3)
                Spacer()
                Image(systemName: "chevron.right").font(.system(size: 14, weight: .semibold)).foregroundStyle(.white.opacity(0.45))
            }
            .padding(.top, 13)
        }
        .padding(18)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(RoundedRectangle(cornerRadius: 18).fill(Color.white.opacity(0.04)))
        .overlay(RoundedRectangle(cornerRadius: 18).stroke(.white.opacity(0.08), lineWidth: 1))
    }

    // MARK: - Content

    // MARK: - Toggle bar (Terminal Tape) + mode content

    private var toggleBar: some View {
        HStack(spacing: 0) {
            tabSegment("GAMES", count: gameCount, active: mode == .games) { mode = .games }
            Spacer().frame(width: 28)
            tabSegment("PROPS", count: propCount, active: mode == .props) { mode = .props }
            Spacer(minLength: 0)
        }
        .padding(.horizontal, 16)
        .padding(.top, 10)
        .padding(.bottom, 8)
        // No fill, no hairline — the underline marks the active tab and
        // proximity does the separating (8 inside the nav group, 24+ after).
    }

    private func tabSegment(_ label: String, count: Int, active: Bool, action: @escaping () -> Void) -> some View {
        Button {
            withAnimation(.spring(response: 0.3, dampingFraction: 0.85)) { action() }
        } label: {
            VStack(alignment: .leading, spacing: 7) {
                HStack(spacing: 6) {
                    Text(label)
                        .font(GaryFonts.mono(13, bold: true))
                        .foregroundStyle(active ? .white : .white.opacity(0.45))
                    // Counts earn their place — a morning of zeros is not a stat.
                    if count > 0 {
                        Text("\(count)")
                            .font(GaryFonts.mono(13, bold: true))
                            .foregroundStyle(active ? GaryColors.gold : .white.opacity(0.3))
                    }
                }
                Group {
                    if active {
                        Capsule().fill(GaryColors.gold).frame(height: 2)
                            .matchedGeometryEffect(id: "tabUnderline", in: tabNS)
                    } else {
                        Capsule().fill(Color.clear).frame(height: 2)
                    }
                }
            }
        }
        .buttonStyle(.plain)
    }

    @ViewBuilder private var modeContent: some View {
        VStack(alignment: .leading, spacing: 22) {
            if mode == .games {
                // Paid boards lead with full cards. Locked boards with content
                // follow as blurred previews — the user sees the real board
                // exactly as members do, just unreadable (tap = checkout).
                // The storefront menu (records, the honest hook) closes it out.
                ForEach(gameShelves.filter { sportUnlocked($0.league) }) { shelf in
                    gameShelfView(shelf)
                        .id("g-\(shelf.league)")
                }
                ForEach(gameShelves.filter { !sportUnlocked($0.league) && !$0.picks.isEmpty }) { shelf in
                    gameShelfView(shelf)
                        .id("g-\(shelf.league)")
                }
                if !lockedGameBoards.isEmpty {
                    storefrontTail(lockedGameBoards)
                }
            } else {
                if propShelves.isEmpty {
                    propsEmptyState
                } else {
                    ForEach(propShelves.filter { sportUnlocked($0.league) }) { shelf in
                        propShelfView(shelf)
                            .id("p-\(shelf.league)")
                    }
                    ForEach(propShelves.filter { !sportUnlocked($0.league) && !$0.props.isEmpty }) { shelf in
                        propShelfView(shelf)
                            .id("p-\(shelf.league)")
                    }
                    if !lockedPropBoards.isEmpty {
                        storefrontTail(lockedPropBoards)
                    }
                }
            }

            if !isPremium {
                // The whole-house CTA — per-sport sales live in the storefront
                // rows above; this sells everything at once, for real money.
                if !Self.freeLaunch && !entitledSports.contains("ALL") {
                    allAccessSection
                        .padding(.top, 6)
                }
                if Self.freeLaunch {
                    plansComingCard
                        .padding(.top, 6)
                }
                accountRow
            } else {
                Button { withAnimation { isPremium = false } } label: {
                    Text("✓ Premium active · tap to reset preview")
                        .font(GaryFonts.mono(10)).tracking(1).foregroundStyle(.white.opacity(0.3))
                }
                .frame(maxWidth: .infinity).padding(.top, 12)
            }
        }
    }

    /// Free-launch announcement — paid plans land June 18, in the exact slot
    /// the storefront will occupy. Informational only: no prices and no
    /// purchase path in-app (the App Store 3.1.1 fence stays up).
