                                    Button { plansFocus = shelf.league; showPlansSheet = true } label: {
                                        ZStack {
                                            if group.count == 1 {
                                                CompactPropRow(prop: group[0], showSportBadge: false)
                                                    .blur(radius: 4.5).opacity(0.7).allowsHitTesting(false)
