    // MARK: - Data

    private func sortedBest(_ picks: [GaryPick]) -> [GaryPick] {
        picks.sorted { a, b in
            let at = a.is_top_pick ?? false, bt = b.is_top_pick ?? false
            if at != bt { return at }
            return (a.confidence ?? 0) > (b.confidence ?? 0)
        }
    }

    /// World Cup shelf ordering: a match ships TWO plays (a side + a total).
    /// Keep them adjacent — matches in kickoff order, and within a match the
    /// side card sits before the total card.
    private func sortedWC(_ picks: [GaryPick]) -> [GaryPick] {
        picks.sorted { a, b in
            let ta = a.commence_time ?? "", tb = b.commence_time ?? ""
            if ta != tb { return ta < tb }
            let ma = "\(a.awayTeam ?? "")@\(a.homeTeam ?? "")"
            let mb = "\(b.awayTeam ?? "")@\(b.homeTeam ?? "")"
            if ma != mb { return ma < mb }
            let aTotal = (a.type ?? "") == "total", bTotal = (b.type ?? "") == "total"
            if aTotal != bTotal { return !aTotal }          // side before total
            return (a.confidence ?? 0) > (b.confidence ?? 0)
        }
    }

    /// W/L for a settled (last-result) game pick, matched by normalized teams AND
    /// the pick's own signature — so a game's side and total (the WC two-pick) read
    /// their OWN result instead of colliding on a matchup-only key.
    private func gamePickResult(_ pick: GaryPick) -> String? {
        let away = gpTeamKey(pick.awayTeam), home = gpTeamKey(pick.homeTeam)
        guard !away.isEmpty, !home.isEmpty else { return nil }
        return gameResultsMap[garyGameResultKey(matchupKey: "\(away)@\(home)", pickText: pick.pick)]
    }
    private func gpTeamKey(_ value: String?) -> String {
        (value ?? "").lowercased().components(separatedBy: CharacterSet.alphanumerics.inverted).joined()
    }
    private func gpKey(from matchup: String?) -> String? {
        guard let matchup else { return nil }
        for sep in [" @ ", " vs ", " v "] {
            let parts = matchup.components(separatedBy: sep)
            if parts.count == 2 {
                let a = gpTeamKey(parts[0]), h = gpTeamKey(parts[1])
                if !a.isEmpty && !h.isEmpty { return "\(a)@\(h)" }
            }
        }
        return nil
    }

    private func leagueKey(_ p: GaryPick) -> String { (p.league ?? "OTHER").uppercased() }
    private func propLeagueKey(_ p: PropPick) -> String {
        let key = (p.effectiveLeague ?? p.sport ?? p.league ?? "OTHER").uppercased()
        // The MLB HR lane is Home Run Threats only. Guard against non-HR props that
        // were mislabeled "MLB HR" upstream (e.g. total_bases/strikeouts) — route them
        // to the regular MLB shelf so the HR lane never shows a non-HR prop.
        if key == "MLB HR" {
            let prop = (p.prop ?? "").lowercased()
            if !prop.contains("home_run") && !prop.contains("home run") {
                return "MLB"
            }
        }
        return key
    }

    /// Premium props: the top 5 by confidence across the sport — no per-game
    /// cap, so a game whose props BOTH qualify forms a slip and a game with
    /// one qualifier stands as a single card. The mix falls out of the data.
    private func selectPremiumProps(_ props: [PropPick]) -> [PropPick] {
        Array(props.sorted { ($0.confidence ?? 0) > ($1.confidence ?? 0) }.prefix(5))
    }

    // MARK: - Date browser (Winners history)

    /// Today's live board, or a chosen past day.
    private func reload() async {
        if let d = selectedDate { await loadHistorical(d) } else { await load() }
    }

    private func sportRank(_ lg: String) -> Int {
        switch lg {
        case "WC":  return 0
        case "NBA": return 1
        case "NHL": return 2
        case "MLB": return 3
        default:    return 4 + (canonicalSports.firstIndex(of: lg) ?? canonicalSports.count)
        }
    }

    /// Browse a past day — every game + prop pick Gary made that date, all settled
    /// (flip-backs + CASHED/LOST stamps), ordered by sport. No live/slate logic.
    private func loadHistorical(_ date: String) async {
        await MainActor.run { loading = true; gameShelves = []; propShelves = [] }
        async let gamesF = SupabaseAPI.fetchDailyPicks(date: date)
        async let propsF = SupabaseAPI.fetchPropPicks(date: date)
        async let resultsF = SupabaseAPI.fetchAllGameResults(since: date)
        async let propResF = SupabaseAPI.fetchRecentPropResults(limit: 200)
        let games = (try? await gamesF) ?? []
        let props = (try? await propsF) ?? []
        let results = (try? await resultsF) ?? []
        let propResults = (try? await propResF) ?? []

        var rMap: [String: String] = [:]
        for r in results where r.game_date == date {
            guard let k = gpKey(from: r.matchup), let o = r.result else { continue }
            rMap[garyGameResultKey(matchupKey: k, pickText: r.pick_text)] = o.lowercased()
        }
        var pMap: [String: String] = [:]
        for r in propResults where r.game_date == date {
            if let n = r.player_name?.lowercased(), !n.isEmpty, let res = r.result { pMap[n] = res.lowercased() }
        }

        let byLeague = Dictionary(grouping: games, by: { leagueKey($0) })
        let propsByLeague = Dictionary(grouping: props, by: { propLeagueKey($0) })
        var order: [String] = []
        for lg in (canonicalSports + Array(byLeague.keys) + Array(propsByLeague.keys))
        where !order.contains(lg) && !Sport.from(league: lg).isPropsOnly {
            order.append(lg)
        }
        order.sort { sportRank($0) < sportRank($1) }

        var gShelves: [GameShelf] = []
        for lg in order {
            guard let gp = byLeague[lg], !gp.isEmpty else { continue }
            let cap = lg == "WC" ? Int.max : 3
            let ordered: ([GaryPick]) -> [GaryPick] = lg == "WC" ? sortedWC : sortedBest
            gShelves.append(GameShelf(league: lg, picks: Array(ordered(gp).prefix(cap)), settled: true))
        }
        var pShelves: [PropShelf] = []
        for lg in order {
            guard let ps = propsByLeague[lg], !ps.isEmpty else { continue }
            pShelves.append(PropShelf(league: lg, props: selectPremiumProps(ps), settled: true))
        }

        await MainActor.run {
            gameResultsMap = rMap
            propResultsMap = pMap
            gameShelves = gShelves
            propShelves = pShelves
            loading = false
        }
    }

    // MARK: - Date selector UI

    // The date selector moved into the page header (see `header` / `headerDateLabel`):
    // the date next to the "WINNERS" wordmark is now the day dropdown. The old "TODAY ▾"
    // pill and its `dateChipLabel`/`dateSelector` were retired here.

    /// "yyyy-MM-dd" (EST) for today minus `offset` days.
    private func dayDateString(_ offset: Int) -> String {
        var cal = Calendar(identifier: .gregorian)
        if let tz = TimeZone(identifier: "America/New_York") { cal.timeZone = tz }
        let f = DateFormatter(); f.dateFormat = "yyyy-MM-dd"; f.timeZone = cal.timeZone
        return f.string(from: cal.date(byAdding: .day, value: -offset, to: Date()) ?? Date())
    }

    /// Dropdown row label: Today / Yesterday / "Sun, Jun 15".
    private func daySelectorLabel(_ offset: Int) -> String {
        if offset == 0 { return "Today" }
        if offset == 1 { return "Yesterday" }
        var cal = Calendar(identifier: .gregorian)
        if let tz = TimeZone(identifier: "America/New_York") { cal.timeZone = tz }
        let f = DateFormatter(); f.dateFormat = "EEE, MMM d"; f.timeZone = cal.timeZone
        return f.string(from: cal.date(byAdding: .day, value: -offset, to: Date()) ?? Date())
    }

    private func load() async {
        let today = SupabaseAPI.todayEST()
        let yesterday = SupabaseAPI.yesterdayEST()

        async let todayGameF = SupabaseAPI.fetchAllPicks(date: today)
        async let yGameF = SupabaseAPI.fetchDailyPicks(date: yesterday)
        async let resultsF = SupabaseAPI.fetchAllGameResults(since: yesterday)
        async let todayPropsF = SupabaseAPI.fetchPropPicks(date: today)
        async let slateF = SupabaseAPI.fetchDailySlate(date: today)
        // Storefront records: a wider graded window, trimmed to last 10 per sport.
        let recordWindowStart: String = {
            var cal = Calendar(identifier: .gregorian)
            if let tz = TimeZone(identifier: "America/New_York") { cal.timeZone = tz }
            let f = DateFormatter(); f.dateFormat = "yyyy-MM-dd"; f.timeZone = cal.timeZone
            return f.string(from: cal.date(byAdding: .day, value: -12, to: Date()) ?? Date())
        }()
        async let recordResultsF = SupabaseAPI.fetchAllGameResults(since: recordWindowStart)

        let todayGame = (try? await todayGameF) ?? []
        let yGame = (try? await yGameF) ?? []
        let results = (try? await resultsF) ?? []
        let todayProps = (try? await todayPropsF) ?? []
        // Leagues with a GAME on today's slate = in-season. Off-season sports
        // (NBA/NHL once their season ends) have no game today, so we skip their
        // empty placeholder lane instead of showing a misleading "next slate
        // posts ~90 min before tip" message for a sport that isn't playing.
        let slateLeagues = Set((await slateF).compactMap { $0.league?.uppercased() })

        // Yesterday's result map for settled (last-result) shelves.
        var rMap: [String: String] = [:]
        for r in results.filter({ $0.game_date == yesterday }) {
            guard let k = gpKey(from: r.matchup), let outcome = r.result else { continue }
            rMap[garyGameResultKey(matchupKey: k, pickText: r.pick_text)] = outcome.lowercased()
        }

        let todayByLeague = Dictionary(grouping: todayGame, by: { leagueKey($0) })
        let yByLeague = Dictionary(grouping: yGame, by: { leagueKey($0) })

        // Board order (user call, Jun 11): lead with what's playing tonight.
        // A league with picks TODAY outranks one without; among tonight's
        // slates the World Cup / NBA / NHL bump the everyday MLB slate down,
        // and the rest hold canonical order. Props-only categories (MLB HR,
        // NFL TDs) are never game shelves.
        func boardRank(_ lg: String) -> Int {
            switch lg {
            case "WC":  return 0
            case "NBA": return 1
            case "NHL": return 2
            case "MLB": return 3
            default:    return 4 + (canonicalSports.firstIndex(of: lg) ?? canonicalSports.count)
            }
        }
        var order: [String] = []
        for lg in (canonicalSports + Array(todayByLeague.keys) + Array(yByLeague.keys))
        where !order.contains(lg) && !Sport.from(league: lg).isPropsOnly {
            order.append(lg)
        }
        order.sort { a, b in
            let aToday = todayByLeague[a]?.isEmpty == false
            let bToday = todayByLeague[b]?.isEmpty == false
            if aToday != bToday { return aToday }      // tonight's slates lead
            let ra = boardRank(a), rb = boardRank(b)
            return ra != rb ? ra < rb : a < b
        }

        var gShelves: [GameShelf] = []
        for lg in order {
            // Most leagues show their top 3 plays. World Cup ships TWO plays per
            // match (a side + a total) across every game on the slate, so its
            // shelf shows ALL of them — the lane is a horizontal scroll.
            let shelfCap = lg == "WC" ? Int.max : 3
            let ordered: ([GaryPick]) -> [GaryPick] = lg == "WC" ? sortedWC : sortedBest
            if let tp = todayByLeague[lg], !tp.isEmpty {
                gShelves.append(GameShelf(league: lg, picks: Array(ordered(tp).prefix(shelfCap)), settled: false))
            } else if let yp = yByLeague[lg], !yp.isEmpty {
                gShelves.append(GameShelf(league: lg, picks: Array(ordered(yp).prefix(shelfCap)), settled: true))
            } else if slateLeagues.contains(lg) {
                // In-season (a game on today's slate) but picks haven't posted —
                // hold the lane with a placeholder. Off-season sports (no game
                // today) are skipped entirely, not shown as an empty "coming" lane.
                gShelves.append(GameShelf(league: lg, picks: [], settled: false))
            }
        }

        // Bump empty game shelves BELOW the sports that actually have picks, so an
        // empty lane (e.g. NBA during an outage) never sits between populated ones.
        // Stable partition: populated shelves keep their ranked order; empties trail.
        gShelves = gShelves.filter { !$0.picks.isEmpty } + gShelves.filter { $0.picks.isEmpty }

        // Premium props from today's slate: best prop per game, capped at 4 per
        // sport. A league with no props yet falls back to YESTERDAY's props as
        // LAST RESULT — graded stamps on, flips intact (mirrors the game shelves).
        let yProps = (try? await SupabaseAPI.fetchPropPicks(date: yesterday)) ?? []
        let recentPropResults = (try? await SupabaseAPI.fetchRecentPropResults(limit: 60)) ?? []
        var pMap: [String: String] = [:]
        for r in recentPropResults where r.game_date == yesterday {
            if let n = r.player_name?.lowercased(), !n.isEmpty, let res = r.result {
                pMap[n] = res.lowercased()
            }
        }
        let propsByLeague = Dictionary(grouping: todayProps, by: { propLeagueKey($0) })
        let yPropsByLeague = Dictionary(grouping: yProps, by: { propLeagueKey($0) })
        var pShelves: [PropShelf] = []
        for lg in order {
            if let ps = propsByLeague[lg], !ps.isEmpty {
                pShelves.append(PropShelf(league: lg, props: selectPremiumProps(ps), settled: false))
            } else if let yps = yPropsByLeague[lg], !yps.isEmpty {
                pShelves.append(PropShelf(league: lg, props: selectPremiumProps(yps), settled: true))
            } else if propSports.contains(lg) && slateLeagues.contains(lg) {
                // In-season prop sport (a game on today's slate) holds its lane
                // with a placeholder until props post. Off-season → skipped.
                pShelves.append(PropShelf(league: lg, props: [], settled: false))
            }
        }

        // Same rule for prop shelves: empty prop lanes trail the populated ones.
        pShelves = pShelves.filter { !$0.props.isEmpty } + pShelves.filter { $0.props.isEmpty }

        // Last-10 graded record per sport (newest first) for the storefront tail.
        var sRec: [String: (w: Int, l: Int)] = [:]
        let recordRows = (try? await recordResultsF) ?? []
        let byLeague = Dictionary(grouping: recordRows.filter { $0.result == "won" || $0.result == "lost" },
                                  by: { $0.effectiveLeague ?? "?" })
        for (lg, rows) in byLeague {
            let last10 = rows.sorted { ($0.game_date ?? "") > ($1.game_date ?? "") }.prefix(10)
            sRec[lg] = (last10.filter { $0.result == "won" }.count,
                        last10.filter { $0.result == "lost" }.count)
        }

        let entitlements = await SupabaseAPI.fetchEntitlements()

        await MainActor.run {
            gameResultsMap = rMap
            propResultsMap = pMap
            gameShelves = gShelves
            propShelves = pShelves
            sportRecords = sRec
            entitledSports = entitlements
            loading = false
        }
    }
}

/// SFSafariViewController wrapper — the in-app checkout browser. The Safari
/// engine gives Stripe Checkout Apple Pay + autofill without leaving the
/// app (US App Store 3.1.1 permits external purchases for digital goods,
/// including in-app web views — post-Epic rules, verified June 2026).
struct SafariView: UIViewControllerRepresentable {
    let url: URL
    func makeUIViewController(context: Context) -> SFSafariViewController {
        let vc = SFSafariViewController(url: url)
        vc.preferredBarTintColor = UIColor(red: 0.043, green: 0.043, blue: 0.047, alpha: 1)   // ink #0C0B0B
        vc.preferredControlTintColor = UIColor(red: 0.788, green: 0.635, blue: 0.153, alpha: 1) // brand gold
        vc.dismissButtonStyle = .close
        return vc
    }
    func updateUIViewController(_ vc: SFSafariViewController, context: Context) {}
}

/// The pricing page — every plan in one place, in the terminal's own
/// language. Opened from blurred board previews (focused on that sport)
/// and from the All-Access section's "All plans" row.
// MARK: - Plans / Pricing sheet (the paywall)
//
// A two-state conversion paywall, not a flat price list. State 1 (the default)
// sells: hero → benefits → a LIVE graded-results receipt → two featured plans
// (All-Access pre-selected, World Cup Pass during its window) → an "all plans"
// link. State 2 is the full menu (single sports, bundles, the free tier). One
// dominant gold CTA at the bottom follows the current selection and discloses
// the Stripe/Safari hand-off; everything else is quiet. Checkout still rides
// the same callbacks the storefront uses (onSelect / onBundle / onAccount).
struct PlansSheetView: View {
    let focus: String?               // league context from a blurred-board tap
    let signedIn: Bool
    var onSelect: (String) -> Void   // league key ("MLB", "ALL", "WC") -> checkout
    var onBundle: ([String]) -> Void // picked bundle sports -> server checkout
    var onAccount: () -> Void        // open sign-in / create account
    @Environment(\.dismiss) private var dismiss
    @Environment(\.accessibilityReduceMotion) private var reduceMotion
    @AppStorage("selectedTab") private var selectedTab: Int = 0

    /// What the single dominant CTA acts on.
    /// One selection model: tap sports and the plan derives itself —
    /// 1 = single pass, 2-3 = bundle, automatically. No separate bundle UI.
    private enum PlanSelection: Equatable { case allAccess, allAccessAnnual, sports, worldCup }

    /// The annual card unhides itself once a build flavor carries an
    /// ALL_ANNUAL checkout link (DEBUG today; RELEASE after the live swap).
    private var annualAvailable: Bool { PremiumPicksView.checkoutLinks["ALL_ANNUAL"] != nil }

    @State private var selection: PlanSelection
    /// The sports the user has tapped (max 3 — past that All-Access wins on
    /// price). 1 checks out as a single pass, 2-3 as the bundle.
    @State private var pickedSports: Set<String> = []
    /// Set when a 4th tap gets blocked — the caption explains the better deal.
    @State private var capHint = false
    /// Per-sport last-30 records — the sport tiles carry proof, not filler.
    @State private var sportRecords: [String: (w: Int, l: Int)] = [:]
    /// THE RECORD — the website's trust block, ported. All-time W–L across
    /// games and props, last 30 days, current streak. nil = hidden (never
    /// fabricated; the block waits for real graded results).
    @State private var ledger: LedgerStats? = nil
    struct LedgerStats {
        let allW: Int; let allL: Int
        let last30W: Int; let last30L: Int
        let streakChar: String; let streakLen: Int
    }
    @State private var appeared = false

    /// Real, current graded record — never fabricated. Pulled from the same
    /// game_results source as the Results tab; the strip hides entirely if the
    /// fetch fails or comes back empty rather than showing a made-up number.

    private static let sports = ["MLB", "NBA", "NHL", "NFL", "NCAAF", "NCAAB"]
    private static let winColor = Color(hex: "#3FB950")
    private static let lossColor = Color(hex: "#E5484D")
    private static let ink = Color(hex: "#0C0B0B")   // text on the gold CTA / chips

    /// A focused sport (from a blurred board) respects intent: open the full
    /// menu with that board already picked, All-Access still on top as the
    /// anchor. A generic open leads with the conversion paywall.
    init(focus: String?, signedIn: Bool,
         onSelect: @escaping (String) -> Void,
         onBundle: @escaping ([String]) -> Void,
         onAccount: @escaping () -> Void) {
        self.focus = focus
        self.signedIn = signedIn
        self.onSelect = onSelect
        self.onBundle = onBundle
        self.onAccount = onAccount
        if let f = focus, Self.sports.contains(f) {
            _selection = State(initialValue: .sports)
            _pickedSports = State(initialValue: [f])
        } else if focus == "WC", Self.worldCupWindowActive() {
            _selection = State(initialValue: .worldCup)
        } else {
            _selection = State(initialValue: .allAccess)
        }
    }

    /// Focused sport leads the single-sport grid.
    private var orderedSports: [String] {
        guard let f = focus, Self.sports.contains(f) else { return Self.sports }
        return [f] + Self.sports.filter { $0 != f }
    }

    /// The World Cup pass is featured only inside the tournament window (run-up
    /// through the final) — outside it the pass would be dead, confusing inventory.
    private static func worldCupWindowActive() -> Bool {
        var cal = Calendar(identifier: .gregorian)
        if let tz = TimeZone(identifier: "America/New_York") { cal.timeZone = tz }
        let start = DateComponents(calendar: cal, year: 2026, month: 6, day: 4).date ?? Date()
        let end = DateComponents(calendar: cal, year: 2026, month: 7, day: 20).date ?? Date()
        let now = Date()
        return now >= start && now < end
    }
    private var wcActive: Bool { Self.worldCupWindowActive() }

    // MARK: Body

    var body: some View {
        ZStack {
            LiquidGlassBackground(grainDensity: 0)
            ScrollView(showsIndicators: false) {
                VStack(alignment: .leading, spacing: 22) {
                    topBar
                    allPlansScreen
                }
                .padding(.top, 8)
                .padding(.bottom, 28)
                .opacity(appeared ? 1 : 0)
                .offset(y: appeared ? 0 : 8)
            }
        }
        .safeAreaInset(edge: .bottom) { ctaBar }
        .preferredColorScheme(.dark)
        .task { await loadRecord() }
        .onAppear {
            withAnimation(reduceMotion ? nil : .easeOut(duration: 0.35)) { appeared = true }
            SupabaseAPI.logEvent("paywall_viewed", [
                "surface": "ios",
                "trigger": focus == nil ? "all_access" : (focusedSport != nil ? "winners_tap" : "wc_tap"),
                "sport_focus": focus ?? "none",
            ])
        }
    }

    private var topBar: some View {
        HStack(spacing: 4) {
            Spacer()
            Button { dismiss() } label: {
                Image(systemName: "xmark")
                    .font(.system(size: 14, weight: .semibold))
                    .foregroundStyle(.white.opacity(0.45))
                    .frame(width: 44, height: 44, alignment: .trailing)
            }
            .buttonStyle(.plain)
            .accessibilityLabel("Close")
        }
        .padding(.horizontal, 16)
    }

    /// The single-sport context this paywall was opened from (nil = generic).
    /// WC is excluded — it isn't one of the per-sport Winners boards.
    private var focusedSport: String? {
        guard let f = focus, Self.sports.contains(f) else { return nil }
        return f
    }

    /// The pitch isn't "more picks" — the free slate already has every game.
    /// It's Gary's *card*: the few plays a night he'd actually back, per sport.
    /// One stat card of the record trio — WIN PCT / LAST 30 / STREAK.
    private func ledgerStat(_ label: String, _ value: String, _ sub: String?, tint: Color = .white) -> some View {
        VStack(alignment: .leading, spacing: 4) {
            Text(label)
                .font(GaryFonts.mono(8.5, bold: true)).tracking(1.2)
                .foregroundStyle(.white.opacity(0.45))
            Text(value)
                .font(GaryFonts.mono(19, bold: true))
                .foregroundStyle(tint)
                .lineLimit(1).minimumScaleFactor(0.7)
            if let sub, !sub.isEmpty {
                Text(sub)
                    .font(GaryFonts.mono(8.5))
                    .foregroundStyle(.white.opacity(0.4))
                    .lineLimit(1).minimumScaleFactor(0.8)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(12)
        .background(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .fill(Color(hex: "#0F0D0D"))
                .overlay(RoundedRectangle(cornerRadius: 12, style: .continuous)
                    .stroke(Color.white.opacity(0.07), lineWidth: 1))
        )
    }

    @ViewBuilder private var recordBlock: some View {
        if let s = ledger {
            let graded = s.allW + s.allL
            let pct = graded > 0 ? Int((Double(s.allW) / Double(graded) * 100).rounded()) : 0
            let l30 = s.last30W + s.last30L
            let l30pct = l30 > 0 ? Int((Double(s.last30W) / Double(l30) * 100).rounded()) : 0
            VStack(alignment: .leading, spacing: 12) {
                Text("THE RECORD")
                    .font(GaryFonts.mono(10, bold: true)).tracking(1.6)
                    .foregroundStyle(GaryColors.gold.opacity(0.92))
                (Text("\(s.allW.formatted())")
                    + Text("–").foregroundColor(.white.opacity(0.3))
                    + Text("\(s.allL.formatted())"))
                    .font(GaryFonts.mono(42, bold: true))
                    .foregroundStyle(.white.opacity(0.96))
                    .lineLimit(1).minimumScaleFactor(0.6)
                Text("Every game pick Gary has made, graded against final scores the next morning. No deletions, no restatements — losses stay on the books with the wins.")
                    .font(.system(size: 13))
                    .foregroundStyle(.white.opacity(0.6))
                    .lineSpacing(3)
                    .fixedSize(horizontal: false, vertical: true)
                HStack(spacing: 10) {
                    ledgerStat("WIN PCT", "\(pct)%", "\(graded.formatted()) graded")
                    ledgerStat("LAST 30", "\(s.last30W)–\(s.last30L)", "\(l30pct)% win")
                    ledgerStat("STREAK", "\(s.streakChar)\(s.streakLen)", nil,
                               tint: s.streakChar == "W" ? Self.winColor : Self.lossColor)
                }
                Button {
                    selectedTab = 4   // Results / Billfold tab
                    dismiss()
                } label: {
                    Text("The full ledger")
                        .font(GaryFonts.text(13, .semibold))
                        .foregroundStyle(GaryColors.gold)
                        .padding(.vertical, 10).padding(.horizontal, 18)
                        .background(
                            RoundedRectangle(cornerRadius: 10, style: .continuous)
                                .stroke(GaryColors.gold.opacity(0.45), lineWidth: 1)
                        )
                }
                .buttonStyle(.plain)
            }
            .padding(.horizontal, 16)
            .accessibilityElement(children: .combine)
        }
    }

    // MARK: The pricing page — ONE screen. The two-state paywall is dead:
    // every entry point lands here; the proof strip is the only sales asset
    // that earned its keep.

    private var allPlansScreen: some View {
        VStack(alignment: .leading, spacing: 22) {
            VStack(alignment: .leading, spacing: 3) {
                Text("Gary's card.").font(GaryFonts.display(30)).foregroundStyle(.white)
                Text("One board or every board — every result graded in public.")
                    .font(.system(size: 13.5)).foregroundStyle(.white.opacity(0.5))
            }
            .padding(.horizontal, 16)

            recordBlock

            // All-Access leads as the anchor / best value.
            VStack(alignment: .leading, spacing: 10) {
                HubSectionHeader(eyebrow: "All-Access", sub: "")
                planCard(selected: selection == .allAccess,
                         ribbon: "Best value · " + GaryPricing.trialDaysFree, ribbonTeal: false,
                         title: "ALL-ACCESS",
                         sub: "All 7 Winners boards · ~$4 a board",
                         price: GaryPricing.allAccessMonthly, per: "PER MONTH",
                         a11y: "All-Access. \(GaryPricing.allAccessMonthly) a month. All seven boards. \(GaryPricing.trialDaysFree)." + (selection == .allAccess ? " Selected." : "")) {
                    select(.allAccess)
                }
                .padding(.horizontal, 16)
                if annualAvailable {
                    planCard(selected: selection == .allAccessAnnual,
                             ribbon: "Save 50% vs monthly", ribbonTeal: false,
                             title: "ALL-ACCESS — ANNUAL",
                             sub: "Every board, all year · works out to \(GaryPricing.allAccessAnnualMonthly)/mo",
                             price: GaryPricing.allAccessAnnual, per: "PER YEAR",
                             a11y: "All-Access annual. \(GaryPricing.allAccessAnnual) a year — about \(GaryPricing.allAccessAnnualMonthly) a month. \(GaryPricing.trialDaysFree)." + (selection == .allAccessAnnual ? " Selected." : "")) {
                        select(.allAccessAnnual)
                    }
                    .padding(.horizontal, 16)
                }
            }

            sportGridSection
            if wcActive { wcRowSection }
            includedFreeSection
            if !signedIn { createAccountSection }
            legalFooter
        }
    }

    private var sportGridSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            HubSectionHeader(eyebrow: "Pick your sports",
                             sub: "One \(GaryPricing.single)/mo · two \(GaryPricing.twoSport) · three \(GaryPricing.threeSport) — bundles itself")
            LazyVGrid(columns: [GridItem(.flexible(), spacing: 10), GridItem(.flexible(), spacing: 10)], spacing: 10) {
                ForEach(orderedSports, id: \.self) { sportCard($0) }
            }
            .padding(.horizontal, 16)
        }
    }

    private var wcRowSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            HubSectionHeader(eyebrow: "Limited", sub: "One-time, no renewal")
            planCard(selected: selection == .worldCup,
                     ribbon: "Kicks off June 11", ribbonTeal: true,
                     title: "WORLD CUP PASS",
                     sub: "All 104 matches · one-time, no renewal",
                     price: GaryPricing.worldCup, per: "ONE-TIME",
                     a11y: "World Cup Pass. \(GaryPricing.worldCup), one time. All 104 matches." + (selection == .worldCup ? " Selected." : "")) {
                select(.worldCup)
            }
            .padding(.horizontal, 16)
        }
    }

    /// The bundle sits between $9.99 single and $34.99 All-Access as the smart
    /// middle. Picking 2–3 chips makes the bundle the active selection so the
    /// one CTA carries it; dropping below two reverts to All-Access.
    private var includedFreeSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            HubSectionHeader(eyebrow: "Free, always", sub: "")
            VStack(spacing: 0) {
                infoRow(icon: "list.bullet.rectangle", title: "THE FULL SLATE",
                        sub: "Every game's pick + the reasoning, every sport", tag: "FREE")
                hairline
                infoRow(icon: "rectangle.grid.1x2", title: "THE HUB",
                        sub: "Edges, trends & receipts — graded daily", tag: "FREE")
            }
            .quantPanel()
            .padding(.horizontal, 16)
        }
    }

    private var createAccountSection: some View {
        Button { onAccount() } label: {
            HStack(spacing: 12) {
                Image(systemName: "person.crop.circle")
                    .font(.system(size: 13, weight: .semibold))
                    .foregroundStyle(GaryColors.gold).frame(width: 20)
                VStack(alignment: .leading, spacing: 2) {
                    Text("CREATE ACCOUNT")
                        .font(GaryFonts.mono(12, bold: true)).tracking(0.8)
                        .foregroundStyle(.white.opacity(0.9))
                    Text("Plans and unlocks follow your account")
                        .font(.system(size: 11)).foregroundStyle(.white.opacity(0.45))
                }
                Spacer(minLength: 8)
                Text("Sign up ›")
