            Spacer()
            
            if !pickParts.odds.isEmpty {
                Text(pickParts.odds)
                    .font(.system(size: 15, weight: .medium))
                    .foregroundStyle(Color.white.opacity(0.75))
                    .padding(.horizontal, 12)
                    .padding(.vertical, 6)
                    .goldGlass(cornerRadius: 8)
            }
        }
    }
    
    @ViewBuilder
    private var confidenceBar: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack {
                Image(systemName: "chart.line.uptrend.xyaxis")
                    .font(.caption)
                Text("Confidence")
                    .font(.caption)
                Spacer()
            }
            .foregroundStyle(.secondary)
            
            // iOS 16+: Use GeometryReader for precise sizing
            // iOS 15 and below: Use scaleEffect to avoid layout recalculations
            if PerformanceMode.current.useExpensiveEffects {
                GeometryReader { geo in
                    ZStack(alignment: .leading) {
                        RoundedRectangle(cornerRadius: 4)
                            .fill(accentColor.opacity(isNFL ? 0.05 : 0.25))
                        RoundedRectangle(cornerRadius: 4)
                            .fill(accentColor)
                            .frame(width: geo.size.width * CGFloat(pick.confidence ?? 0))
                    }
                }
                .frame(height: 6)
            } else {
                ZStack(alignment: .leading) {
                    RoundedRectangle(cornerRadius: 4)
                        .fill(accentColor.opacity(isNFL ? 0.05 : 0.25))
                        .frame(height: 6)
                    RoundedRectangle(cornerRadius: 4)
                        .fill(accentColor)
                        .frame(height: 6)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .scaleEffect(x: CGFloat(pick.confidence ?? 0), y: 1, anchor: .leading)
                }
                .frame(height: 6)
            }
        }
    }
    
    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            // Header Row - Icon left, Time right
            headerRow
            
            // Teams section
            teamsSection
            
            // Divider
            Rectangle()
                .fill(accentColor.opacity(0.3))
                .frame(height: 1)
            
            // Pick Text with Odds
            pickTextSection

            // Sportsbook Odds Comparison (expandable)
            if let odds = pick.sportsbook_odds, !odds.isEmpty {
                VStack(spacing: 8) {
                    Button {
                        withAnimation(.spring(response: 0.3, dampingFraction: 0.8)) {
                            showSportsbookOdds.toggle()
                        }
                    } label: {
                        HStack(spacing: 6) {
                            Image(systemName: "chart.bar.doc.horizontal")
                                .font(.system(size: 11, weight: .semibold))
                            Text("View Sportsbook Odds")
                                .font(.system(size: 12, weight: .semibold))
                            Spacer()
                            Image(systemName: showSportsbookOdds ? "chevron.up" : "chevron.down")
                                .font(.system(size: 10, weight: .bold))
                        }
                        .foregroundStyle(.white.opacity(0.9))
                        .padding(.vertical, 8)
                        .padding(.horizontal, 12)
                        .background(accentColor.opacity(0.25))
                        .clipShape(RoundedRectangle(cornerRadius: 8))
                        .overlay(RoundedRectangle(cornerRadius: 8).stroke(accentColor.opacity(0.4), lineWidth: 0.5))
                    }
                    .buttonStyle(.plain)

                    if showSportsbookOdds {
                        SportsbookOddsTable(odds: odds)
                            .transition(.opacity.combined(with: .scale(scale: 0.95, anchor: .top)))
                    }
                }
            }

            // Confidence Bar
            confidenceBar
            
            // Analysis Button - soft white, unbold
            Button {
                showAnalysis.toggle()
            } label: {
                HStack(spacing: 8) {
                    Image(systemName: "doc.text.magnifyingglass")
                        .font(.system(size: 14, weight: .medium))
                        .foregroundStyle(Color.white.opacity(0.75))
                    Text("View Analysis")
                        .font(.system(size: 15, weight: .medium))
                }
                .foregroundStyle(Color.white.opacity(0.75))
                .frame(maxWidth: .infinity)
                .padding(.vertical, 12)
                .goldGlass(cornerRadius: 12)
            }
            .sheet(isPresented: $showAnalysis) {
                AnalysisSheet(title: "Gary's Analysis", pick: pick, accentColor: accentColor)
            }
        }
        .padding(18)
        .background {
            if PerformanceMode.current.useExpensiveEffects {
                // Full design for iOS 16+
                RoundedRectangle(cornerRadius: 20)
                    .fill(GaryColors.cardBg)
                    .overlay(
                        RoundedRectangle(cornerRadius: 20)
                            .stroke(
                                // MLB: baseball field gradient border
                                Sport.from(league: pick.league).accentGradient ??
                                LinearGradient(
                                    colors: [accentColor.opacity(0.6), accentColor.opacity(0.2)],
                                    startPoint: .topLeading,
                                    endPoint: .bottomTrailing
                                ),
                                lineWidth: Sport.from(league: pick.league).accentGradient != nil ? 2.5 : 2
                            )
                    )
                    .shadow(color: .black.opacity(0.45), radius: 20, y: 10)
                    .shadow(color: .black.opacity(0.3), radius: 10, y: 5)
            } else {
                // Lighter version for iOS 15 and below
                RoundedRectangle(cornerRadius: 20)
                    .fill(GaryColors.cardBg)
                    .overlay(
                        RoundedRectangle(cornerRadius: 20)
                            .stroke(
                                Sport.from(league: pick.league).accentGradient ??
                                LinearGradient(colors: [accentColor.opacity(0.4)], startPoint: .top, endPoint: .bottom),
                                lineWidth: Sport.from(league: pick.league).accentGradient != nil ? 2 : 1.5
                            )
                    )
                    .shadow(color: .black.opacity(0.2), radius: 6, y: 4)
            }
        }
        .modifier(PerformanceOptimizer()) // Applies drawingGroup only on older iOS
        .overlay(alignment: .center) {
            // Result stamp overlay for yesterday's picks
            if let result = gameResult?.lowercased(), !result.isEmpty {
                ResultStampOverlay(result: result)
                    .offset(y: -50)
            }
        }
        .opacity(gameResult != nil ? 0.75 : 1.0)
        .scaleEffect(isPressed ? 0.98 : 1.0)
        .onLongPressGesture(minimumDuration: .infinity, pressing: { pressing in
            withAnimation(.spring(response: 0.3, dampingFraction: 0.6)) {
                isPressed = pressing
            }
        }, perform: {})
        .accessibilityElement(children: .combine)
        .accessibilityLabel("\(pick.league ?? "") pick: \(pick.homeTeam ?? "") vs \(pick.awayTeam ?? ""). \(pick.pick ?? "")")
    }
}

/// 3D metallic emblem overlay for yesterday's pick results
struct ResultStampOverlay: View {
    let result: String

    private var stampText: String {
        switch result {
        case "won": return "CASHED"
        case "push": return "PUSH"
        default: return "NO CASH"
        }
    }

    private var stampColor: Color {
        switch result {
        case "won": return GaryColors.gold
        case "push": return .yellow
        default: return Color(hex: "#4A4A4C")
        }
    }

    var body: some View {
        Text(stampText)
            .font(.system(size: 52, weight: .black))
            .tracking(6)
            .foregroundStyle(stampColor)
            .padding(.horizontal, 24)
            .padding(.vertical, 8)
            .frame(minWidth: 200)
            .overlay(
                RoundedRectangle(cornerRadius: 8)
                    .stroke(stampColor, lineWidth: 4)
            )
            .overlay(
                RoundedRectangle(cornerRadius: 8)
                    .stroke(stampColor, lineWidth: 1.5)
                    .padding(5)
            )
            .rotationEffect(.degrees(-18))
            .opacity(0.85)
            .allowsHitTesting(false)
    }
}

// MARK: - Pick Text Helper (shared spread-sign fix)

extension GaryPick {
    /// Formatted pick text with spread sign correction from sportsbook odds
    var formattedPickParts: (pick: String, odds: String) {
        var parts = Formatters.splitPickAndOdds(self.pick)
        // Spread sign fix using sportsbook odds (picked team perspective)
        if let pickType = self.type, pickType == "spread",
           let books = self.sportsbook_odds, let firstSpread = books.compactMap({ $0.spread }).first {
            var text = parts.0
            if let regex = try? NSRegularExpression(pattern: #"([+-]?)(\d{1,2}\.?\d*)\s*$"#),
               let match = regex.firstMatch(in: text, range: NSRange(text.startIndex..., in: text)),
               let signRange = Range(match.range(at: 1), in: text),
               let fullRange = Range(match.range(at: 0), in: text) {
                let sign = String(text[signRange])
                let correctSign = firstSpread >= 0 ? "+" : "-"
                if sign.isEmpty || sign != correctSign {
                    let num = abs(firstSpread)
                    let s = num.truncatingRemainder(dividingBy: 1) == 0 ? String(Int(num)) : String(num)
                    text = text.replacingCharacters(in: fullRange, with: "\(correctSign)\(s)")
                    parts = (text, parts.1)
                }
            }
        }
        return parts
    }
}

// MARK: - Gary brand mark (single source of truth)
//
// One place for the logo. Change `mark` (and add the asset to Assets.xcassets)
// once and every surface — navbar, pick cards, auth, settings, changelog — updates.
enum GaryBrand {
    static let mark = "GaryIconBG"
}

// MARK: - Compact Pick Row (Scoreboard-style)

struct CompactPickRow: View {
    let pick: GaryPick
    var gameResult: String? = nil
    var finalScore: String? = nil   // settled cards: shown in place of GARY'S LEAN
    var showSportBadge: Bool = false
    /// Game pages carry the score in the page hero (LiveScoreStrip), so their
    /// cards keep the plain start time in the slot. Everywhere else stays state-aware.
    var liveInSlot: Bool = true
    /// Billfold's recent picks are static (no flip) — they hide the affordance.
    var showTakeAffordance: Bool = true
    /// Overrides the eyebrow label (e.g. "FREE PICK" on the Tonight page).
    var eyebrowOverride: String? = nil
    /// Winners keeps the start time visible even on settled cards (it sorts by start time).
    var alwaysShowStartTime: Bool = false
    /// When set, the card renders at this EXACT height so every pick card in a
    /// rail/list is the same size regardless of headline length or footer (the
    /// flip-card wrappers pass it; Billfold/share leave it nil for natural size).
    var fixedHeight: CGFloat? = nil
    /// App-wide uniform headline-card height — game and prop cards share it.
    static let uniformHeight: CGFloat = 232

    private var sport: Sport { Sport.from(league: pick.league) }
    private var accentColor: Color { sport.accentColor }
    /// Accent for the odds chip in the meta line — MLB reads on its grass green,
    /// every other sport on its own accent.
    private var metaAccent: Color { (sport == .mlb || sport == .mlbHR) ? GaryColors.mlbGrass : accentColor }
    private var accentGradient: LinearGradient {
        sport.accentGradient
            ?? LinearGradient(colors: [accentColor, accentColor], startPoint: .leading, endPoint: .trailing)
    }
    private var hasCustomGradient: Bool { sport.accentGradient != nil }
    private var awayName: String { Formatters.shortTeamName(pick.awayTeam, league: pick.league) }
    private var homeName: String { Formatters.shortTeamName(pick.homeTeam, league: pick.league) }
    private var isNCAAB: Bool { (pick.league ?? "").uppercased() == "NCAAB" }
    private var isCFP: Bool { pick.isCFP }
    private var pickParts: (pick: String, odds: String) { pick.formattedPickParts }

    /// Picked team's standard abbreviation (PHI, NYK, VGK, ...) via the league
    /// keyword maps, with a mascot-initials fallback for other leagues.
    private func teamAbbrev(_ shortName: String) -> String {
        let lower = shortName.lowercased()
        let lg = (pick.league ?? "").uppercased()
        let maps: [[String: [String]]] = lg == "NBA" ? [nbaTeamKeywords]
            : lg == "MLB" ? [mlbTeamKeywords]
            : lg == "NHL" ? [nhlTeamKeywords]
            : lg == "WC" ? [wcTeamKeywords]
            : [mlbTeamKeywords, nbaTeamKeywords, nhlTeamKeywords, wcTeamKeywords]
        for map in maps {
            for (abbr, kws) in map where kws.contains(where: { lower.contains($0) }) { return abbr }
        }
        let last = lower.split(separator: " ").last.map(String.init) ?? lower
        return String(last.prefix(3)).uppercased()
    }
    /// The pick with the team name collapsed to its abbreviation (e.g. "PHI ML",
    /// "VGK ML"). The pick text may carry the full name, the short name, or a
    /// display-truncated fragment ("Vegas Golden ML", "Columbus ML", "Red Wings
    /// ML") — so strip the LEADING RUN of team-name words and put the standard
    /// abbreviation in its place; no fragment can survive.
    private var compactPick: String {
        let raw = pickParts.pick
        guard homeIsPicked || awayIsPicked else { return raw.uppercased() }
        let pickedFull = homeIsPicked ? (pick.homeTeam ?? "") : (pick.awayTeam ?? "")
        let pickedShort = homeIsPicked ? homeName : awayName
        let abbrev = teamAbbrev(pickedShort.isEmpty ? pickedFull : pickedShort)
        var teamWords = Set(pickedFull.lowercased().split(separator: " ").map(String.init))
        teamWords.formUnion(pickedShort.lowercased().split(separator: " ").map(String.init))
        var words = raw.split(separator: " ").map(String.init)
        var lead = 0
        while lead < words.count, teamWords.contains(words[lead].lowercased()) { lead += 1 }
        guard lead > 0 else { return raw.uppercased() }
        words.removeFirst(lead)
        return ([abbrev] + words).joined(separator: " ").uppercased()
    }

    private var confidenceValue: CGFloat {
        CGFloat(max(0.18, min(1.0, pick.confidence ?? 0.72)))
    }
    private var resolvedResult: String? {
        guard let result = gameResult?.lowercased(), !result.isEmpty else { return nil }
        return result
    }
    private var resultStampColor: Color {
        switch displayResult {
        case "won": return Color(hex: "#3FB950")
        case "push": return GaryColors.gold
        case "lost": return Color(hex: "#E5484D")
        default: return Color(hex: "#E5484D")
        }
    }

    private var significanceTag: String? {
        // Skip generic defaults — only show meaningful game significance
        let genericLabels = ["regular season", "conference play", "regular season game"]
        if let cleaned = pick.shortGameSignificance, cleaned.count < 32 {
            if !genericLabels.contains(cleaned.lowercased()) {
                return cleaned.uppercased()
            }
        }
        if let cleaned = pick.shortTournamentContext, cleaned.count < 28 {
            if !genericLabels.contains(cleaned.lowercased()) {
                return cleaned.uppercased()
            }
        }
        // Regular games just say the sport ("MLB") — the tag only earns words
        // when the game is special (playoffs, finals, tournament rounds).
        return (pick.league ?? "").uppercased()
    }

    private var formattedTime: String {
        guard let time = pick.displayTime else { return "" }
        return Formatters.formatCommenceTime(time)
    }

    /// Live/final state for THIS matchup (shared cache; nil when scheduled
    /// or unknown). Only consulted when the card has no settled result.
    @ObservedObject private var liveCache = LiveScoreCache.shared
    /// One-tap share from the card FRONT — renders the Stack Row share card
    /// (story + square) and presents the system sheet.
    @State private var shareItem: PickShareItem? = nil
    private var liveStatus: LiveScore? {
        guard liveInSlot, resolvedResult == nil else { return nil }
        return liveCache.status(forMatchup: "\(pick.awayTeam ?? "") @ \(pick.homeTeam ?? "")")
    }

    /// FINAL board for this matchup with no stored grade yet — feeds the
    /// client-side verdict so results land the moment the game ends, not the
    /// next morning. Deliberately ignores liveInSlot: a verdict is the card's
    /// business everywhere, score-in-slot chrome is not.
    private var liveFinal: LiveScore? {
        guard resolvedResult == nil else { return nil }
        let ls = liveCache.status(forMatchup: "\(pick.awayTeam ?? "") @ \(pick.homeTeam ?? "")")
        return (ls?.isFinal == true) ? ls : nil
    }
    private var liveGraded: String? {
        guard let ls = liveFinal,
              let s = orientedFinalScores(ls, awayTeam: pick.awayTeam, homeTeam: pick.homeTeam) else { return nil }
        return liveGradeGamePick(pickText: pickParts.pick, betType: pick.type ?? "",
                                 awayPicked: awayIsPicked, homePicked: homeIsPicked,
                                 away: s.away, home: s.home)
    }
    /// Stored grade first (authoritative); else the live verdict on a FINAL board.
    private var displayResult: String? { resolvedResult ?? liveGraded }

    private static let bookDisplayNames: [String: String] = [
        "draftkings": "DraftKings",
        "fanduel": "FanDuel",
        "betmgm": "BetMGM",
        "betrivers": "BetRivers",
        "caesars": "Caesars",
        "fanatics": "Fanatics",
        "pointsbet": "PointsBet",
        "bovada": "Bovada",
    ]

    private var bestBookName: String? {
        guard let books = pick.sportsbook_odds, let first = books.first, let name = first.book, !name.isEmpty else { return nil }
        return Self.bookDisplayNames[name.lowercased()] ?? name.prefix(1).uppercased() + name.dropFirst()
    }

    // Which side did Gary take? Match the pick string against the short team
    // names so the matchup hero can brighten the picked team. Falls back to
    // "neither bright" for totals (Over/Under) where no single team is backed.
    private var pickedSideLower: String {
        pickParts.pick.lowercased()
    }
    /// Short mascot first (the common case), then any distinctive word of the
    /// full name — display truncation can strip the mascot from the pick text
    /// ("Vegas Golden Knights ML" arrives as "Vegas Golden ML", "Columbus Blue
    /// Jackets ML" as "Columbus ML"), so the mascot alone isn't reliable.
    private func sideIsPicked(full: String?, short: String, otherFull: String?) -> Bool {
        let p = pickedSideLower
        if !short.isEmpty, p.contains(short.lowercased()) { return true }
        guard let full, !full.isEmpty else { return false }
        let otherWords = Set((otherFull ?? "").lowercased().split(separator: " ").map(String.init))
        return full.lowercased().split(separator: " ").map(String.init)
            .contains { $0.count >= 4 && !otherWords.contains($0) && p.contains($0) }
    }
    private var awayIsPicked: Bool {
        sideIsPicked(full: pick.awayTeam, short: awayName, otherFull: pick.homeTeam)
    }
    private var homeIsPicked: Bool {
        sideIsPicked(full: pick.homeTeam, short: homeName, otherFull: pick.awayTeam)
    }

    private var awaySeedTag: String? {
        if isNCAAB, let r = pick.awayRanking { return "#\(r)" }
        if isCFP, let s = pick.awaySeed { return "#\(s)" }
        return nil
    }
    private var homeSeedTag: String? {
        if isNCAAB, let r = pick.homeRanking { return "#\(r)" }
        if isCFP, let s = pick.homeSeed { return "#\(s)" }
        return nil
    }

    // MARK: Headline front (June 11 2026 — THE pick card design, everywhere)
    //
    // The approved share card ("09-headline-mlb-story") IS the in-app card:
    // gold eyebrow + bear, the pick as stacked display type, sport-accent
    // league token leading one meta line, share/tier/take footer. Settled
    // picks wear the diagonal CASHED/LOST stamp, same as the export.

    /// Always "GARY'S PICK" app-wide, unless a caller overrides it (the Tonight
    /// page passes "FREE PICK", so it needs no separate section label).
    private var eyebrowLabel: String {
        eyebrowOverride ?? "GARY'S PICK"
    }

    /// Noun for a totals card's second line, by league ("TOTAL RUNS" /
    /// "TOTAL GOALS" / "TOTAL POINTS") so totals carry the same two-line shape
    /// as side picks — every card then measures to one uniform height.
    private var totalNoun: String {
        switch (pick.league ?? "").uppercased() {
        case "MLB": return "RUNS"
        case "NHL", "WC", "EPL": return "GOALS"
        default: return "POINTS"
        }
    }

    /// Hero: the picked team's short name over the bet ("NATIONALS" /
    /// "MONEYLINE", "KNICKS" / "+6.5"). Totals get a matching two-line shape
    /// ("UNDER 3.5" / "TOTAL GOALS") so every card reads at one uniform height.
    private var heroLines: String {
        var words = pickParts.pick.split(separator: " ").map(String.init)
        // The headline never shows odds or a stray "@" — those belong in the meta line.
        // Strip "@" and any American-odds integer (3+ digits) a malformed/legacy pick
        // string may carry (e.g. "Under 2.5 @ -135"); decimals (handicap/total lines) stay.
        words.removeAll { $0 == "@" || $0.range(of: #"^[+-]?\d{3,}$"#, options: .regularExpression) != nil }
        if let i = words.firstIndex(where: { $0.uppercased() == "ML" }) { words[i] = "MONEYLINE" }
        if (pick.type ?? "").lowercased() == "total" {
            return "\(words.joined(separator: " ").uppercased())\nTOTAL \(totalNoun)"
        }
        guard homeIsPicked || awayIsPicked else { return words.joined(separator: " ").uppercased() }
        let pickedShort = homeIsPicked ? homeName : awayName
        let pickedFull = homeIsPicked ? (pick.homeTeam ?? "") : (pick.awayTeam ?? "")
        var teamWords = Set(pickedFull.lowercased().split(separator: " ").map(String.init))
        teamWords.formUnion(pickedShort.lowercased().split(separator: " ").map(String.init))
        var lead = 0
        while lead < words.count, teamWords.contains(words[lead].lowercased()) { lead += 1 }
        let bet = words[lead...].joined(separator: " ")
        return bet.isEmpty ? pickedShort.uppercased()
            : "\(pickedShort.uppercased())\n\(bet.uppercased())"
    }

    /// Meta slot after the league token — opponent + time/live/final + odds.
    /// State-aware: live games show the live line, settled show the score.
    private var metaLine: String {
        let opponent = homeIsPicked ? "vs \(awayName)"
            : awayIsPicked ? "@ \(homeName)"
            : "\(awayName) @ \(homeName)"
        let parts = [opponent]
        // The final score + LIVE/FINAL state now ride the FOOTER strip on every card
        // (user call, Jun 18) — meta keeps just the matchup; odds render after it.
        // Start time moved to the eyebrow row (frontTime); meta keeps matchup + odds.
        // Odds render separately in the sport's accent color (see body) — not appended here.
        return parts.joined(separator: " · ")
    }

    /// Footer's gold state slot — the live line while the game runs, the
    /// final board before grading lands. Nil keeps the footer slim.
    private var footerStateText: String? {
        guard displayResult == nil, let live = liveStatus else { return nil }
        if live.isLive { return liveSlotText(live, label: "LIVE") }
        if live.isFinal { return liveSlotText(live, label: "FINAL") }
        return nil
    }

    private enum LiveBetTone { case covering, trailing, neutral }
    /// The numeric line in the pick text (total goals line, handicap) — for live grading.
    private var pickLineValue: Double? {
        for tok in pickParts.pick.split(separator: " ") { if let d = Double(tok) { return d } }
        return nil
    }
    /// Is Gary's pick currently covering (green) or trailing (red) live? Neutral when
    /// the game isn't live, the score's tied, or it can't be determined.
    private var liveBetTone: LiveBetTone {
        guard let ls = liveStatus, ls.isLive, let a = ls.away_score, let h = ls.home_score else { return .neutral }
        let t = (pick.type ?? "").lowercased()
        if t == "total" {
            guard let line = pickLineValue else { return .neutral }
            let total = Double(a + h)
            return pickParts.pick.lowercased().contains("under")
                ? (total < line ? .covering : .trailing)
                : (total > line ? .covering : .trailing)
        }
        if t == "draw" { return a == h ? .covering : .trailing }
        guard homeIsPicked || awayIsPicked else { return .neutral }
        let pickedScore = Double(homeIsPicked ? h : a)
        let otherScore = Double(homeIsPicked ? a : h)
        let hcap = (t == "asian_handicap" || t == "spread") ? (pickLineValue ?? 0) : 0
        let adj = pickedScore + hcap
        if adj > otherScore { return .covering }
        if adj < otherScore { return .trailing }
        return .neutral
    }
    private var liveToneColor: Color {
        switch liveBetTone {
        case .covering: return Color(hex: "#3FB950")
        case .trailing: return Color(hex: "#E5484D")
        case .neutral: return GaryColors.gold
        }
    }
    /// Footer live line — "LIVE · SD 4 · PHI 6 · COVERING": teams + score + Gary's
    /// live standing, colored green/red by `liveToneColor`.
    private var liveFooterText: String? {
        // Graded/settled card: show the FINAL SCORE in the footer (user call, Jun 18
        // — "FINAL · CAN 3 · QAT 1" beside the CASHED stamp), from the live board
        // first, then the stored final score; bare "FINAL" only when neither carries
        // a score. This is the one place the final state lives on every card now.
        if displayResult != nil {
            if let ls = liveFinal, ls.away_score != nil, ls.home_score != nil { return liveSlotText(ls, label: "FINAL") }
            if let fs = finalScore, !fs.isEmpty { return "FINAL · \(fs)" }
            if let g = liveCache.gradedScore(forMatchup: "\(pick.awayTeam ?? "") @ \(pick.homeTeam ?? "")") { return "FINAL · \(g)" }
            return "FINAL"
        }
        guard let ls = liveStatus else { return nil }
        if ls.isLive { return liveLineRich(ls, label: "LIVE") }
        if ls.isFinal { return liveLineRich(ls, label: "FINAL") }
        return nil
    }

    /// Start time, shown on the eyebrow row pre-game. Live/settled cards carry
    /// their state in the meta line / footer instead, so this returns nil for them.
    private var frontTime: String? {
        // Pre-game shows the start time. Settled cards normally hide it, but the Winners
        // page (alwaysShowStartTime) keeps it visible since that page sorts by start time.
        if displayResult != nil { return alwaysShowStartTime ? (formattedTime.isEmpty ? nil : formattedTime) : nil }
        if let live = liveStatus, live.isLive || live.isFinal { return nil }
        return formattedTime.isEmpty ? nil : formattedTime
    }

    var body: some View {
        ZStack {
            VStack(alignment: .leading, spacing: 0) {
                HStack(alignment: .top, spacing: 10) {
                    Text(eyebrowLabel)
                        .font(GaryFonts.mono(11.5, bold: true)).tracking(2.2)
                        .foregroundStyle(GaryColors.gold)
                        .padding(.top, 6)
                    Spacer()
                    Image(GaryBrand.mark)
                        .resizable().scaledToFit()
                        .frame(width: 44, height: 44)
                }

                Text(heroLines)
                    .font(GaryFonts.display(40))
                    .foregroundStyle(.white)
                    .lineSpacing(0)
                    .lineLimit(2)
                    .minimumScaleFactor(0.5)
                    .padding(.top, 10)

                HStack(alignment: .center, spacing: 8) {
                    Text(significanceTag ?? (pick.league ?? "").uppercased())
                        .font(GaryFonts.mono(11, bold: true)).tracking(1.2)
                        .foregroundStyle(metaAccent)
                        .lineLimit(1)
                        .layoutPriority(1)
                    (Text(metaLine).foregroundColor(.white.opacity(0.55))
                        + Text(pickParts.odds.isEmpty ? "" : " · ").foregroundColor(.white.opacity(0.4))
                        + Text(pickParts.odds).foregroundColor(GaryColors.gold))
                        .font(GaryFonts.text(13.5, .medium))
                        .lineLimit(1)
                        .minimumScaleFactor(0.75)
                    Spacer(minLength: 4)
                    // Share moved up here (compact) — frees the footer for the live line.
                    Button {
                        let images = renderPickShareImages(pick: pick, gameResult: displayResult)
                        if !images.isEmpty { shareItem = PickShareItem(images: images) }
                    } label: {
                        Image(systemName: "square.and.arrow.up")
                            .font(.system(size: 12, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.5))
                            .frame(width: 26, height: 22)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    .accessibilityLabel("Share this pick")
                }
                .padding(.top, 10)

                // Footer — the live line while the game runs (teams + score + COVERING/
                // TRAILING in green/red), with a tap-to-flip chevron on the right. Share
                // moved up to the meta line; "Gary's Take" is now just the chevron.
                if showTakeAffordance {
                    Rectangle()
                        .fill(.white.opacity(0.12))
                        .frame(height: 1)
                        .padding(.vertical, 12)

                    HStack(spacing: 10) {
                        if let live = liveFooterText {
                            Text(live)
                                .font(GaryFonts.mono(11, bold: true)).tracking(0.5)
                                .foregroundStyle(GaryColors.gold)
                                .lineLimit(1)
                                .minimumScaleFactor(0.8)
                        } else if let t = frontTime {
                            // Pre-game: start time anchors the footer's left corner, opposite the chevron.
                            Text(t)
                                .font(GaryFonts.mono(11, bold: true)).tracking(0.5)
                                .foregroundStyle(GaryColors.gold)
                                .lineLimit(1)
                                .minimumScaleFactor(0.8)
                        }
                        Spacer()
                        Image(systemName: "chevron.right")
                            .font(.system(size: 12, weight: .bold))
                            .foregroundStyle(GaryColors.heroAccent.opacity(0.7))
                    }
                }
            }
            .padding(18)

            // Stamp rides the empty space under the bear — clear of the hero
            // type. Gold for every verdict (the brand owns its record).
            if let verdict = displayResult {
                let stampColor = verdict == "lost" ? GaryColors.lostTint : GaryColors.gold
                Text(verdict == "won" ? "CASHED" : (verdict == "push" ? "PUSH" : "LOST"))
                    .font(GaryFonts.mono(19, bold: true)).tracking(2.5)
                    .foregroundStyle(stampColor.opacity(0.92))
                    .padding(.horizontal, 10).padding(.vertical, 4)
                    .overlay(Rectangle().stroke(stampColor.opacity(0.85), lineWidth: 2))
                    .rotationEffect(.degrees(-8))
                    .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .trailing)
                    .padding(.trailing, 16)
            }
        }
        // Uniform card height regardless of headline length / footer presence.
        // A FIXED height (not a floor) when the flip wrapper passes one — a
        // minHeight let 2-line heroes stay taller than 1-line ones (the bug).
        .frame(minHeight: fixedHeight == nil ? 210 : nil)
        .frame(height: fixedHeight)
        .background(
            RoundedRectangle(cornerRadius: 20, style: .continuous)
                .fill(Color(hex: "#121110"))
                .overlay(
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .stroke(.white.opacity(0.10), lineWidth: 1)
                )
                .shadow(color: .black.opacity(0.5), radius: 18, y: 8)
        )
        .onAppear { LiveScoreCache.shared.startIfNeeded() }
        .sheet(item: $shareItem) { ActivityShareSheet(items: $0.images) }
    }
}

// MARK: - Flippable Pick Card (front = CompactPickRow, back = Gary's case)
//
// The pick card is a "moveable object" — its front design stays exactly as
// CompactPickRow. Tapping does a true 3D flip (instead of the old popup): the
// card expands a bit squarer and rotates to reveal the rationale on the back.

private struct PickCardHeightKey: PreferenceKey {
    static var defaultValue: CGFloat = 0
    static func reduce(value: inout CGFloat, nextValue: () -> CGFloat) { value = max(value, nextValue()) }
}

// MARK: - Scoreboard Pick Card ("the pick is the headline")
//
// Two team rows like a live scoreboard — the picked side is lit, with the
// call chip anchored to it; the other side is dimmed. Sans-serif throughout.
// Chosen by the user (June 3 2026) over the serif CompactPickRow for Best Bets.
// MARK: - Sport watermarks (card texture, Fixtured-style — in Gary's ink)

/// Baseball seam sweeping the card's right side: one stitched arc, one faint
/// echo. Monochrome at whisper opacity — texture, never a tint wash.
struct BaseballSeamShape: Shape {
    var stitched: Bool = true
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width, h = rect.height
        let start = CGPoint(x: w * 0.60, y: h * 1.28)
        let ctrl  = CGPoint(x: w * 0.64, y: h * 0.30)
        let end   = CGPoint(x: w * 1.16, y: h * -0.22)
        p.move(to: start)
        p.addQuadCurve(to: end, control: ctrl)
        guard stitched else { return p }
        // Chevron stitches along the curve, pointing with the seam.
        let n = 11
        for i in 1..<n {
            let t = CGFloat(i) / CGFloat(n)
            let mt = 1 - t
            let x = mt * mt * start.x + 2 * mt * t * ctrl.x + t * t * end.x
            let y = mt * mt * start.y + 2 * mt * t * ctrl.y + t * t * end.y
            var dx = 2 * mt * (ctrl.x - start.x) + 2 * t * (end.x - ctrl.x)
            var dy = 2 * mt * (ctrl.y - start.y) + 2 * t * (end.y - ctrl.y)
            let len = max(sqrt(dx * dx + dy * dy), 0.001)
            dx /= len; dy /= len
            let nx = -dy, ny = dx
            let tip  = CGPoint(x: x + dx * 5, y: y + dy * 5)
            let left = CGPoint(x: x - dx * 4 + nx * 8, y: y - dy * 4 + ny * 8)
            let right = CGPoint(x: x - dx * 4 - nx * 8, y: y - dy * 4 - ny * 8)
            p.move(to: left); p.addLine(to: tip)
            p.move(to: right); p.addLine(to: tip)
        }
        return p
    }
}

/// Basketball seams bleeding in from the top-right corner.
struct BasketballSeamShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let c = CGPoint(x: rect.width * 0.98, y: rect.height * 0.06)
        let r = rect.height * 1.1
        p.addEllipse(in: CGRect(x: c.x - r, y: c.y - r, width: 2 * r, height: 2 * r))
        p.move(to: CGPoint(x: c.x, y: c.y - r)); p.addLine(to: CGPoint(x: c.x, y: c.y + r))
        p.move(to: CGPoint(x: c.x - r, y: c.y)); p.addLine(to: CGPoint(x: c.x + r, y: c.y))
        // The two curved channels.
        p.move(to: CGPoint(x: c.x - r * 0.92, y: c.y + r * 0.45))
        p.addQuadCurve(to: CGPoint(x: c.x - r * 0.1, y: c.y + r * 0.95),
                       control: CGPoint(x: c.x - r * 0.42, y: c.y + r * 0.88))
        p.move(to: CGPoint(x: c.x + r * 0.92, y: c.y + r * 0.45))
        p.addQuadCurve(to: CGPoint(x: c.x + r * 0.1, y: c.y + r * 0.95),
                       control: CGPoint(x: c.x + r * 0.42, y: c.y + r * 0.88))
        return p
    }
}

/// Soccer ball panel — circle off the bottom-right corner, center pentagon,
/// spokes to the surrounding panels.
struct SoccerPanelShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let c = CGPoint(x: rect.width * 1.0, y: rect.height * 1.0)
        let r = rect.height * 1.05
        p.addEllipse(in: CGRect(x: c.x - r, y: c.y - r, width: 2 * r, height: 2 * r))
        let pent = r * 0.34
        var verts: [CGPoint] = []
        for i in 0..<5 {
            let a = (CGFloat(i) * 72 - 90) * .pi / 180
            verts.append(CGPoint(x: c.x + cos(a) * pent, y: c.y + sin(a) * pent))
        }
        p.move(to: verts[0])
        for v in verts.dropFirst() { p.addLine(to: v) }
        p.closeSubpath()
        for v in verts {
            let a = atan2(v.y - c.y, v.x - c.x)
            p.move(to: v)
            p.addLine(to: CGPoint(x: c.x + cos(a) * r * 0.78, y: c.y + sin(a) * r * 0.78))
        }
        return p
    }
}

/// The sport texture layer for pick cards — Fixtured's idea in the brand's
/// monochrome: faint line art, clipped by the card, no color wash.
struct SportWatermark: View {
    let league: String?
    var body: some View {
        switch Sport.from(league: league ?? "") {
        case .mlb, .mlbHR:
            ZStack {
                BaseballSeamShape(stitched: false)
                    .stroke(Color.white.opacity(0.045), style: StrokeStyle(lineWidth: 1.3, lineCap: .round))
                    .offset(x: -34)
                BaseballSeamShape()
                    .stroke(Color.white.opacity(0.085), style: StrokeStyle(lineWidth: 1.6, lineCap: .round))
            }
        case .nba, .wnba:
            BasketballSeamShape()
                .stroke(Color.white.opacity(0.075), style: StrokeStyle(lineWidth: 1.6, lineCap: .round))
        case .worldCup, .epl:
            SoccerPanelShape()
                .stroke(Color.white.opacity(0.075), style: StrokeStyle(lineWidth: 1.6, lineCap: .round))
        default:
            EmptyView()
        }
    }
}

struct ScoreboardPickCard: View {
    let pick: GaryPick
    var gameResult: String? = nil
    var showSportBadge: Bool = true

    private var sport: Sport { Sport.from(league: pick.league) }
    private var accent: Color { sport.accentColor }
    private var awayName: String { Formatters.shortTeamName(pick.awayTeam, league: pick.league) }
    private var homeName: String { Formatters.shortTeamName(pick.homeTeam, league: pick.league) }

    private var pickedHome: Bool {
        guard let pickText = pick.pick?.lowercased() else { return true }
        let homeLower = (pick.homeTeam ?? "").lowercased()
        let homeShort = homeName.lowercased()
        if pickText.contains(homeLower) || (!homeShort.isEmpty && pickText.contains(homeShort)) { return true }
        let awayLower = (pick.awayTeam ?? "").lowercased()
        let awayShort = awayName.lowercased()
        if pickText.contains(awayLower) || (!awayShort.isEmpty && pickText.contains(awayShort)) { return false }
        return true
    }

    /// The call without the team name — "ML −154", "+1.5", "OVER 8.5".
    private var callText: String {
        var text = (pick.pick ?? "").trimmingCharacters(in: .whitespaces)
        let pickedFull = (pickedHome ? pick.homeTeam : pick.awayTeam) ?? ""
        let pickedShort = pickedHome ? homeName : awayName
        for name in [pickedFull, pickedShort] where !name.isEmpty {
            if let r = text.range(of: name, options: .caseInsensitive) {
                text.removeSubrange(r)
            }
        }
        text = text.trimmingCharacters(in: .whitespaces)
        return text.isEmpty ? "ML" : text.uppercased()
    }

    private var confidence: Double { min(max(pick.confidence ?? 0, 0), 1) }

    // W/L result stamp (shown for settled, e.g. yesterday's, picks). Mirrors CompactPickRow.
    private var resolvedResult: String? {
        guard let result = gameResult?.lowercased(), !result.isEmpty else { return nil }
        return result
    }
    private var resultStampText: String {
        switch resolvedResult {
        case "won": return "W"
        case "push": return "P"
        case "lost": return "L"
        default: return "L"
        }
    }
    private var resultStampColor: Color {
        switch resolvedResult {
        case "won": return Color(hex: "#3FB950")
        case "push": return GaryColors.gold
        case "lost": return Color(hex: "#E5484D")
        default: return Color(hex: "#E5484D")
        }
    }
    private var resultStampTextOpacity: Double {
        switch resolvedResult {
        case "lost": return 1.0
        case "won": return 0.85
        case "push": return 0.9
        default: return 0.85
        }
    }
    private var resultStampRingOpacity: Double {
        switch resolvedResult {
        case "lost": return 0.94
        case "won": return 0.79
        case "push": return 0.84
        default: return 0.79
        }
    }
    private var resultStampShadowOpacity: Double {
        switch resolvedResult {
        case "lost": return 0.34
        case "won": return 0.25
        case "push": return 0.28
        default: return 0.25
        }
    }

    private func teamRow(name: String, isPicked: Bool) -> some View {
        HStack(spacing: 8) {
            RoundedRectangle(cornerRadius: 1)
                .fill(isPicked ? accent : .clear)
                .frame(width: 3, height: 16)

            Text(name)
                .font(.system(size: isPicked ? 17 : 15, weight: isPicked ? .bold : .medium))
                .foregroundStyle(isPicked ? .white : .white.opacity(0.38))
                .lineLimit(1)
                .minimumScaleFactor(0.7)

            Spacer(minLength: 6)

            if isPicked {
                Text(callText)
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(accent)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 3.5)
                    .background(
                        RoundedRectangle(cornerRadius: 6)
                            .fill(accent.opacity(0.12))
                            .overlay(RoundedRectangle(cornerRadius: 6).stroke(accent.opacity(0.4), lineWidth: 1))
                    )
            }
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 5)
        .background(isPicked ? accent.opacity(0.07) : .clear)
    }

    var body: some View {
        ZStack {
            VStack(alignment: .leading, spacing: 0) {
                // Header: league + significance + time
                HStack(spacing: 6) {
                    if showSportBadge {
                        Text(sport.rawValue)
                            .font(GaryFonts.mono(10, bold: true))
                            .tracking(1.2)
                            .foregroundStyle(accent)
                    }
                    if let sig = pick.shortGameSignificance ?? pick.gameSignificance, !sig.isEmpty {
                        Text(sig.uppercased())
                            .font(GaryFonts.mono(9, bold: true))
                            .tracking(0.8)
                            .foregroundStyle(.white.opacity(0.35))
                            .lineLimit(1)
                    }
                    Spacer()
                    Text(Formatters.formatCommenceTime(pick.displayTime))
                        .font(GaryFonts.mono(10, bold: false))
                        .foregroundStyle(.white.opacity(0.42))
                }
                .padding(.horizontal, 12)
                .padding(.top, 11)
                .padding(.bottom, 9)

                teamRow(name: awayName, isPicked: !pickedHome)
                teamRow(name: homeName, isPicked: pickedHome)

                // The take — the rationale's opening paragraph as a front-of-
                // card quote (mock, June 2026): clamped to three lines; the
                // flip carries the full case.
                if let take = splitTake(pick.rationale).take {
                    HStack(alignment: .top, spacing: 8) {
                        RoundedRectangle(cornerRadius: 1)
                            .fill(GaryColors.gold.opacity(0.55))
                            .frame(width: 2)
                        Text(take)
                            .font(GaryFonts.text(12.5))
                            .foregroundStyle(.white.opacity(0.62))
                            .lineSpacing(2.5)
                            .lineLimit(3)
                            .frame(maxWidth: .infinity, alignment: .leading)
                    }
                    .padding(.horizontal, 12)
                    .padding(.top, 9)
                }

                // Conviction rail — tier word, not a percentage (uncles don't
                // say 82%); the bar stays as the analog read.
                HStack(spacing: 8) {
                    Text("CONVICTION")
                        .font(GaryFonts.mono(8.5, bold: true))
                        .tracking(1.2)
                        .foregroundStyle(.white.opacity(0.35))
                    GeometryReader { geo in
                        ZStack(alignment: .leading) {
                            Capsule().fill(Color.white.opacity(0.08))
                            Capsule().fill(accent).frame(width: geo.size.width * confidence)
                        }
                    }
                    .frame(height: 3)
                    Text(convictionTier(Double(confidence)))
                        .font(GaryFonts.mono(11, bold: true))
                        .foregroundStyle(accent)
                }
                .padding(.horizontal, 12)
                .padding(.top, 10)
                .padding(.bottom, 12)
            }
            .background(
                RoundedRectangle(cornerRadius: 14, style: .continuous)
                    .fill(Color.white.opacity(0.04))
                    .overlay(RoundedRectangle(cornerRadius: 14, style: .continuous).stroke(Color.white.opacity(0.08), lineWidth: 1))
            )
            .opacity(gameResult != nil ? 0.72 : 1.0)

            if resolvedResult != nil {
                Text(resultStampText)
                    .font(.system(size: 29, weight: .black, design: .default))
                    .fontWidth(.compressed)
                    .tracking(0.5)
                    .foregroundStyle(resultStampColor.opacity(resultStampTextOpacity))
                    .frame(width: 62, height: 62)
                    .background(
                        Circle()
                            .fill(Color.black.opacity(0.64))
                            .overlay(
                                Circle()
                                    .stroke(resultStampColor.opacity(resultStampRingOpacity), lineWidth: 1.8)
                            )
                    )
                    .shadow(color: resultStampColor.opacity(resultStampShadowOpacity), radius: 6, y: 0)
                    .rotationEffect(.degrees(-10))
            }
        }
    }
}

/// Flip wrapper: ScoreboardPickCard front ⟷ PickCardBack (Gary's rationale).
struct FlippableScoreboardCard: View {
    let pick: GaryPick
    var gameResult: String? = nil
    var showSportBadge: Bool = true

    @State private var flipped = false
    @State private var frontH: CGFloat = 132

    private var expandedH: CGFloat { max(frontH + 320, 480) }

    var body: some View {
        ZStack {
            // fixedSize: natural-height layout under the pinned frame (see
            // FlippablePickCard) — keeps the front from compressing.
            ScoreboardPickCard(pick: pick, gameResult: gameResult, showSportBadge: showSportBadge)
                .fixedSize(horizontal: false, vertical: true)
                .background(GeometryReader { g in
                    Color.clear.preference(key: PickCardHeightKey.self, value: g.size.height)
                })
                .opacity(flipped ? 0 : 1)

            PickCardBack(pick: pick, gameResult: gameResult)
                .opacity(flipped ? 1 : 0)
                .rotation3DEffect(.degrees(180), axis: (x: 0, y: 1, z: 0))
        }
        .frame(height: flipped ? expandedH : frontH)
        .rotation3DEffect(.degrees(flipped ? 180 : 0), axis: (x: 0, y: 1, z: 0), perspective: 0.55)
        .onPreferenceChange(PickCardHeightKey.self) { h in if h > 1, !flipped { frontH = h } }
        .animation(.spring(response: 0.6, dampingFraction: 0.82), value: flipped)
        .contentShape(Rectangle())
        .onTapGesture { flipped.toggle() }
        .accessibilityAddTraits(.isButton)
    }
}

struct FlippablePickCard: View {
    let pick: GaryPick
    var eyebrowOverride: String? = nil
    var alwaysShowStartTime: Bool = false
    var gameResult: String? = nil
    var finalScore: String? = nil
    var showSportBadge: Bool = false
    var liveInSlot: Bool = true
    /// When set, the flipped back grows to at least this height — Best Bets
    /// wants a full-page read; the default keeps the compact expansion elsewhere.
    var backHeight: CGFloat? = nil

    @State private var flipped = false
    @State private var frontH: CGFloat = CompactPickRow.uniformHeight

    private var expandedH: CGFloat {
        let base = max(frontH + 320, 480)
        return backHeight.map { max($0, base) } ?? base
    }

    var body: some View {
        ZStack {
            // Front pinned to the uniform height so every pick card in a rail is
            // the same size (fixedHeight on CompactPickRow) — no per-card measuring,
            // which is what let 2-line heroes end up taller than 1-line ones.
            CompactPickRow(pick: pick, gameResult: gameResult, finalScore: finalScore, showSportBadge: showSportBadge, liveInSlot: liveInSlot, eyebrowOverride: eyebrowOverride, alwaysShowStartTime: alwaysShowStartTime, fixedHeight: CompactPickRow.uniformHeight)
                .opacity(flipped ? 0 : 1)

            PickCardBack(pick: pick, gameResult: gameResult)
                .opacity(flipped ? 1 : 0)
                .rotation3DEffect(.degrees(180), axis: (x: 0, y: 1, z: 0))
        }
        .frame(height: flipped ? expandedH : frontH)
        .rotation3DEffect(.degrees(flipped ? 180 : 0), axis: (x: 0, y: 1, z: 0), perspective: 0.55)
        .animation(.spring(response: 0.6, dampingFraction: 0.82), value: flipped)
        .contentShape(Rectangle())
        .onTapGesture { flipped.toggle() }
        .accessibilityAddTraits(.isButton)
    }
}

/// Sportsbook brand casing — one source for every odds table. Keys are
/// normalized (lowercased, no spaces/underscores); unknown books fall back
/// to simple capitalization, never raw lowercase keys.
enum SportsbookNames {
    static let byKey: [String: String] = [
        "draftkings": "DraftKings", "fanduel": "FanDuel", "betmgm": "BetMGM",
        "betrivers": "BetRivers", "caesars": "Caesars", "fanatics": "Fanatics",
        "espnbet": "ESPN BET", "bet365": "bet365", "pointsbet": "PointsBet",
        "pinnacle": "Pinnacle", "bovada": "Bovada", "polymarket": "Polymarket",
        "kalshi": "Kalshi", "hardrockbet": "Hard Rock Bet", "hardrock": "Hard Rock Bet",
        "wynnbet": "WynnBET", "unibet": "Unibet", "ballybet": "Bally Bet",
        "barstool": "Barstool", "williamhill": "Caesars", "mybookieag": "MyBookie",
        "lowvig": "LowVig", "betonlineag": "BetOnline", "bovadalv": "Bovada"
    ]
    static func display(_ raw: String?) -> String {
        guard let raw, !raw.isEmpty else { return "—" }
        let key = raw.lowercased()
            .replacingOccurrences(of: " ", with: "")
            .replacingOccurrences(of: "_", with: "")
            .replacingOccurrences(of: ".", with: "")
        if let n = byKey[key] { return n }
        return raw.prefix(1).uppercased() + raw.dropFirst()
    }
}

/// Collapsible "Sportsbook Lines" dropdown for the back of a game-pick card —
/// the multi-book spread/ML comparison from the pick's sportsbook_odds.
struct SportsbookLinesDropdown: View {
    let odds: [SportsbookOdds]
    @State private var open = false
    var body: some View {
        VStack(alignment: .leading, spacing: 0) {
            Button { withAnimation(.easeInOut(duration: 0.2)) { open.toggle() } } label: {
                HStack {
                    Text("SPORTSBOOK LINES")
                        .font(GaryFonts.mono(9.5, bold: true)).tracking(1.4)
                        .foregroundStyle(GaryColors.gold)
                    Text("(\(odds.count))")
                        .font(GaryFonts.mono(9.5, bold: false))
                        .foregroundStyle(.white.opacity(0.35))
                    Spacer()
                    Image(systemName: "chevron.right").font(.system(size: 10, weight: .semibold))
                        .foregroundStyle(GaryColors.gold).rotationEffect(.degrees(open ? 90 : 0))
                }
                .contentShape(Rectangle())
            }
            .buttonStyle(.plain)

            if open {
                VStack(spacing: 0) {
                    // Column captions — the numbers read as data, not décor.
                    // Spread/ML are quoted from the PICKED side's perspective.
                    HStack(spacing: 8) {
                        Text("BOOK").frame(maxWidth: .infinity, alignment: .leading)
                        Text("SPREAD").frame(width: 96, alignment: .trailing)
                        Text("ML").frame(width: 56, alignment: .trailing)
                    }
                    .font(GaryFonts.mono(8)).tracking(1.2)
                    .foregroundStyle(.white.opacity(0.45))
                    .padding(.vertical, 6)
                    ForEach(odds) { o in
                        HStack(spacing: 8) {
                            Text(SportsbookNames.display(o.book))
                                .font(.system(size: 12.5, weight: .semibold))
                                .foregroundStyle(.white.opacity(0.9))
                                .lineLimit(1).minimumScaleFactor(0.8)
                                .frame(maxWidth: .infinity, alignment: .leading)
                            Group {
                                if let s = o.spread {
                                    let juice = (o.spread_odds?.isEmpty == false) ? " \(o.spread_odds!)" : ""
                                    Text(String(format: "%+.1f", s) + juice)
                                        .foregroundStyle(.white.opacity(0.75))
                                } else {
                                    Text("—").foregroundStyle(.white.opacity(0.3))
                                }
                            }
                            .font(GaryFonts.mono(11.5))
                            .frame(width: 96, alignment: .trailing)
                            Group {
                                if let ml = o.ml, !ml.isEmpty, ml != "-" {
                                    Text(ml).foregroundStyle(GaryColors.gold.opacity(0.9))
                                } else {
                                    Text("—").foregroundStyle(.white.opacity(0.3))
                                }
                            }
                            .font(GaryFonts.mono(11.5, bold: true))
                            .frame(width: 56, alignment: .trailing)
                        }
                        .padding(.vertical, 6)
                        if o.id != odds.last?.id { Rectangle().fill(.white.opacity(0.05)).frame(height: 0.5) }
                    }
                }
                .padding(.top, 2)
            }
        }
    }
}

/// The back of the pick card — Gary's reasoning. Uses the pick card's own
/// rounded/mono styling (NOT the Props serif) and matches the front's chrome.
// MARK: - Share Cards (pick → branded story/square image)
//
// "Stack Row" share card (June 2026, chosen from the design range boards):
// the pick rides a compact card on its sport's accent-color field with that
// sport's equipment seams drawn oversized behind — stacked team rows with
// team-color chips (team COLORS are free to use; logos are licensed), the
// picked side lit, and the pick itself in display type as the hero. States
// ride `gameResult`: pregame (no stamp), CASHED (gold) on wins, LOST on losses.
// HOUSE RULE: share assets carry UNITS/records only — never dollars.

/// Sport accent field behind the share card. Deeper, richer cousins of
/// `Sport.accentColor` — the flat UI accents are tuned for 11pt eyebrows,
/// not full-bleed card fields.
func shareFieldColors(for sport: Sport) -> (top: Color, bottom: Color) {
    switch sport {
    case .mlb, .mlbHR:  return (Color(hex: "#2D5A27"), Color(hex: "#1B3A17"))
    case .nba, .wnba:   return (Color(hex: "#3B82F6"), Color(hex: "#1E50C8"))
    case .ncaab:        return (Color(hex: "#EA6A12"), Color(hex: "#B54A08"))
    case .nhl:          return (Color(hex: "#0795C9"), Color(hex: "#045E84"))
    case .nfl, .nflTDs: return (Color(hex: "#1E9E4F"), Color(hex: "#136B36"))
    case .ncaaf:        return (Color(hex: "#CD2828"), Color(hex: "#8E1B1B"))
    case .epl:          return (Color(hex: "#8B5CF6"), Color(hex: "#6128D9"))
    case .worldCup:     return (Color(hex: "#14B8A6"), Color(hex: "#0D7568"))
    case .all:          return (Color(hex: "#1A1714"), Color(hex: "#0C0B0A"))
    }
}

/// The sport's ball drawn as oversized seam lines behind the card content —
/// baseball stitching, basketball channels, rink markings, soccer panels,
/// football laces. Translucent ink only: texture, not illustration.
struct SportSeamTexture: View {
    let sport: Sport

    var body: some View {
        GeometryReader { geo in
            let w = geo.size.width
            let h = geo.size.height
            switch sport {
            case .mlb, .mlbHR:
                ZStack {
                    let seam = Path { p in
                        p.move(to: CGPoint(x: w * 1.08, y: -h * 0.06))
                        p.addCurve(to: CGPoint(x: w * 1.08, y: h * 0.88),
                                   control1: CGPoint(x: w * 0.40, y: h * 0.20),
                                   control2: CGPoint(x: w * 0.40, y: h * 0.62))
                    }
                    seam.stroke(Color.black.opacity(0.15), style: StrokeStyle(lineWidth: w * 0.075, dash: [3.5, 13]))
                    seam.stroke(Color.black.opacity(0.22), style: StrokeStyle(lineWidth: 3.5, lineCap: .round))
                    let seam2 = Path { p in
                        p.move(to: CGPoint(x: -w * 0.10, y: h * 0.34))
                        p.addCurve(to: CGPoint(x: -w * 0.10, y: h * 1.08),
                                   control1: CGPoint(x: w * 0.40, y: h * 0.55),
                                   control2: CGPoint(x: w * 0.40, y: h * 0.88))
                    }
                    seam2.stroke(Color.black.opacity(0.10), style: StrokeStyle(lineWidth: w * 0.065, dash: [3.5, 13]))
                    seam2.stroke(Color.black.opacity(0.15), style: StrokeStyle(lineWidth: 3))
                }
            case .nba, .wnba, .ncaab:
                ZStack {
                    Circle()
                        .stroke(Color.black.opacity(0.18), lineWidth: 4)
                        .frame(width: w * 1.5, height: w * 1.5)
                        .position(x: w * 1.02, y: h * 0.46)
                    Path { p in
                        p.move(to: CGPoint(x: w * 1.05, y: -h * 0.04))
                        p.addCurve(to: CGPoint(x: w * 1.05, y: h * 0.92),
                                   control1: CGPoint(x: w * 0.52, y: h * 0.24),
                                   control2: CGPoint(x: w * 0.52, y: h * 0.66))
                    }
                    .stroke(Color.black.opacity(0.18), lineWidth: 4)
                    Path { p in
                        p.move(to: CGPoint(x: w * 0.28, y: h * 0.40))
                        p.addCurve(to: CGPoint(x: w * 1.30, y: h * 0.40),
                                   control1: CGPoint(x: w * 0.60, y: h * 0.29),
                                   control2: CGPoint(x: w * 0.98, y: h * 0.29))
                    }
                    .stroke(Color.black.opacity(0.15), lineWidth: 4)
                    Path { p in
                        p.move(to: CGPoint(x: w * 0.28, y: h * 0.52))
                        p.addCurve(to: CGPoint(x: w * 1.30, y: h * 0.52),
                                   control1: CGPoint(x: w * 0.60, y: h * 0.63),
                                   control2: CGPoint(x: w * 0.98, y: h * 0.63))
                    }
                    .stroke(Color.black.opacity(0.15), lineWidth: 4)
                }
            case .nhl:
                ZStack {
                    Rectangle()
                        .fill(Color.black.opacity(0.14))
                        .frame(width: w * 1.3, height: 5)
                        .position(x: w * 0.5, y: h * 0.42)
                    Circle()
                        .stroke(Color.black.opacity(0.16), lineWidth: 4)
                        .frame(width: w * 0.95, height: w * 0.95)
                        .position(x: w * 0.94, y: h * 0.42)
                    Circle()
                        .fill(Color.black.opacity(0.16))
                        .frame(width: 11, height: 11)
                        .position(x: w * 0.94, y: h * 0.42)
                }
            case .worldCup, .epl:
                ZStack {
                    Circle()
                        .stroke(Color.black.opacity(0.16), lineWidth: 4)
                        .frame(width: w * 1.25, height: w * 1.25)
                        .position(x: w * 1.04, y: h * 0.46)
                    SharePentagon()
                        .stroke(Color.black.opacity(0.16), lineWidth: 4)
                        .frame(width: w * 0.34, height: w * 0.34)
                        .position(x: w * 0.92, y: h * 0.46)
                }
            case .nfl, .ncaaf, .nflTDs:
                ZStack {
                    Rectangle()
                        .fill(Color.black.opacity(0.16))
                        .frame(width: 4, height: h * 0.52)
                        .position(x: w * 0.88, y: h * 0.45)
                    ForEach(0..<5, id: \.self) { i in
                        Rectangle()
                            .fill(Color.black.opacity(0.16))
                            .frame(width: w * 0.11, height: 4)
                            .position(x: w * 0.88, y: h * (0.26 + CGFloat(i) * 0.095))
                    }
                }
            case .all:
                EmptyView()
            }
        }
        .allowsHitTesting(false)
    }
}

/// Regular pentagon — the soccer-ball panel for the WC/EPL share texture.
struct SharePentagon: Shape {
    func path(in rect: CGRect) -> Path {
        let c = CGPoint(x: rect.midX, y: rect.midY)
        let r = min(rect.width, rect.height) / 2
        var p = Path()
        for i in 0..<5 {
            let a = (CGFloat(i) * 2 * .pi / 5) - .pi / 2
            let pt = CGPoint(x: c.x + r * cos(a), y: c.y + r * sin(a))
            if i == 0 { p.move(to: pt) } else { p.addLine(to: pt) }
        }
        p.closeSubpath()
        return p
    }
}

