/// Identifiable wrapper so the share sheet rides .sheet(item:).
struct PickShareItem: Identifiable {
    let id = UUID()
    let images: [UIImage]
}

struct ActivityShareSheet: UIViewControllerRepresentable {
    let items: [Any]
    func makeUIViewController(context: Context) -> UIActivityViewController {
        UIActivityViewController(activityItems: items, applicationActivities: nil)
    }
    func updateUIViewController(_ vc: UIActivityViewController, context: Context) {}
}

struct PickCardBack: View {
    let pick: GaryPick
    var gameResult: String? = nil
    @State private var shareItem: PickShareItem? = nil
    private var confidence: CGFloat { CGFloat(max(0.1, min(1.0, pick.confidence ?? 0.7))) }
    private var pickedHome: Bool {
        guard let h = pick.homeTeam, !h.isEmpty else { return false }
        return (pick.pick ?? "").localizedCaseInsensitiveContains(h)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 9) {
            HStack {
                Text("GARY'S CASE")
                    .font(GaryFonts.mono(11, bold: true)).tracking(1)
                    .foregroundStyle(GaryColors.gold)
                Spacer()
                Text("\(pick.awayTeam ?? "") @ \(pick.homeTeam ?? "")")
                    .font(GaryFonts.mono(10, bold: false))
                    .foregroundStyle(.white.opacity(0.4)).lineLimit(1).minimumScaleFactor(0.7)
                Button {
                    let images = renderPickShareImages(pick: pick, gameResult: gameResult)
                    if !images.isEmpty { shareItem = PickShareItem(images: images) }
                } label: {
                    Image(systemName: "square.and.arrow.up")
                        .font(.system(size: 13, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.5))
                        .frame(width: 26, height: 26)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityLabel("Share this pick")
            }

            HStack(alignment: .firstTextBaseline, spacing: 8) {
                Text(pick.pick ?? "")
                    .font(.system(size: 19, weight: .heavy))
                    .foregroundStyle(GaryColors.gold).lineLimit(1).minimumScaleFactor(0.7)
                Spacer()
                if pick.confidence != nil {
                    Text(convictionTier(Double(confidence)))
                        .font(GaryFonts.mono(12, bold: true))
                        .foregroundStyle(.white.opacity(0.55))
                }
            }

            // World Cup tournament context (e.g. "Group A · Group Stage"); nil for other sports
            if let wcContext = pick.soccerContext {
                Text(wcContext)
                    .font(GaryFonts.mono(9, bold: true))
                    .foregroundStyle(Color(hex: "#16A34A").opacity(0.9))
                    .lineLimit(1)
            }

            // Venue / stadium (BDL supplies it for WC). On the back so the front stays uncrowded.
            if let venue = pick.venue, !venue.isEmpty {
                HStack(spacing: 5) {
                    Image(systemName: "mappin.and.ellipse")
                        .font(.system(size: 10))
                        .foregroundStyle(.white.opacity(0.4))
                    Text(venue)
                        .font(GaryFonts.mono(9.5)).tracking(0.5)
                        .foregroundStyle(.white.opacity(0.45))
                        .lineLimit(1).minimumScaleFactor(0.7)
                }
            }

            if pick.confidence != nil {
                GeometryReader { geo in
                    ZStack(alignment: .leading) {
                        RoundedRectangle(cornerRadius: 1.5).fill(Color(hex: "#1E1A1A"))
                        RoundedRectangle(cornerRadius: 1.5).fill(GaryColors.gold).frame(width: geo.size.width * confidence)
                    }
                }
                .frame(height: 2)
            }

            ScrollView(showsIndicators: false) {
                VStack(alignment: .leading, spacing: 12) {
                    // The rationale's first paragraph leads at quote weight;
                    // the rest of the case follows as the receipts.
                    let parts = splitTake(pick.rationale)
                    if let take = parts.take {
                        Text(take)
                            .font(GaryFonts.text(16.5, .semibold))
                            .foregroundStyle(.white.opacity(0.92))
                            .lineSpacing(3.5)
                            .frame(maxWidth: .infinity, alignment: .leading)
                    }
                    if let rest = parts.rest {
                        Text(rest)
                            .font(.system(size: 14.5))
                            .foregroundStyle(.white.opacity(0.72))
                            .lineSpacing(3)
                            .frame(maxWidth: .infinity, alignment: .leading)
                    }

                    if let odds = pick.sportsbook_odds, !odds.isEmpty {
                        Rectangle().fill(.white.opacity(0.06)).frame(height: 0.5)
                        SportsbookLinesDropdown(odds: odds)
                    }

                    if let stats = pick.statsData, !stats.isEmpty {
                        Rectangle().fill(.white.opacity(0.06)).frame(height: 0.5)
                        TaleOfTapeSection(
                            homeTeam: pick.homeTeam ?? "",
                            awayTeam: pick.awayTeam ?? "",
                            statsData: stats,
                            injuries: pick.injuries,
                            garyPickedHome: pickedHome
                        )
                    }
                }
            }

            Text("tap to flip back  ↺")
                .font(GaryFonts.mono(9, bold: false))
                .foregroundStyle(.white.opacity(0.35))
                .frame(maxWidth: .infinity, alignment: .center)
        }
        .padding(14)
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
        .background(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .fill(Color(hex: "#1C1A1A"))
                .overlay(RoundedRectangle(cornerRadius: 12, style: .continuous).stroke(GaryColors.gold.opacity(0.32), lineWidth: 1))
        )
        .sheet(item: $shareItem) { ActivityShareSheet(items: $0.images) }
    }
}

// MARK: - Flippable Prop Card (front = CompactPropRow, back = Gary's read)
//
// Mirrors FlippablePickCard exactly so prop cards flip like the game-pick cards.

/// Prop pick text with the call wearing its direction — OVERs stay gold,
/// UNDERs go silver from the direction word on ("TOTAL BASES" gold ·
/// "UNDER 1.5" silver). Inherits the surrounding gold otherwise; props only.
func propPickStyled(_ s: String) -> Text {
    var out = Text("")
    var silver = false
    for (i, word) in s.split(separator: " ").enumerated() {
        let w = String(word)
        if w.uppercased() == "UNDER" { silver = true }
        let piece = silver ? Text(w).foregroundColor(GaryColors.silver) : Text(w)
        out = i == 0 ? piece : out + Text(" ") + piece
    }
    return out
}

/// Strip labeled section markers (HYPOTHESIS:, THE EDGE:, CONVERGENCE (x):, RISK:…)
/// out of a prop analysis blob into clean readable paragraphs.
func cleanPropAnalysis(_ text: String) -> String {
    // Raw markdown bold ("**THE PICK:**") reads as a glitch on-card — drop it.
    var cleaned = text.replacingOccurrences(of: "**", with: "")
    let labels = ["HYPOTHESIS:", "EVIDENCE:", "CONVERGENCE", "IF WRONG:", "THE EDGE:", "THE VERDICT:", "RISK:"]
    for label in labels {
        if let r = cleaned.range(of: label, options: .caseInsensitive) {
            let after = cleaned[r.upperBound...]
            if after.hasPrefix(" (") || after.hasPrefix("(") {
                if let c = after.range(of: "):") { cleaned.removeSubrange(r.lowerBound...c.upperBound) }
                else if let c = after.range(of: ")") { cleaned.removeSubrange(r.lowerBound...c.upperBound) }
                else { cleaned.removeSubrange(r) }
            } else {
                cleaned.removeSubrange(r)
            }
        }
    }
    return cleaned
        .components(separatedBy: "\n")
        .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { !$0.isEmpty }
        .joined(separator: "\n\n")
}

struct FlippablePropCard: View {
    let prop: PropPick
    var gameResult: String? = nil
    var showSportBadge: Bool = false
    var liveInSlot: Bool = true
    /// Passed straight to the front card — Winners shows the start time on settled
    /// cards (it sorts by time), mirroring the game card.
    var alwaysShowStartTime: Bool = false
    /// When set, the flipped back grows to at least this height — Best Bets
    /// wants a full-page read; the default keeps the compact expansion elsewhere.
    var backHeight: CGFloat? = nil

    @State private var flipped = false
    @State private var frontH: CGFloat = CompactPickRow.uniformHeight

    private var expandedH: CGFloat {
        let base = max(frontH + 170, 330)
        return backHeight.map { max($0, base) } ?? base
    }

    var body: some View {
        ZStack {
            // Front pinned to the shared uniform height so prop cards match the
            // game cards exactly (fixedHeight on CompactPropRow) — no per-card
            // measuring, which is what let content-length drive different sizes.
            CompactPropRow(prop: prop, gameResult: gameResult, showSportBadge: showSportBadge, liveInSlot: liveInSlot, alwaysShowStartTime: alwaysShowStartTime, fixedHeight: CompactPickRow.uniformHeight)
                .opacity(flipped ? 0 : 1)

            // ONE back design for prop cards everywhere — the slip's back
            // (GARY'S TAKE · The Numbers · The Read). Same cards, every page.
            PropSlipBack(props: [prop], current: .constant(prop)) {
                withAnimation(.spring(response: 0.6, dampingFraction: 0.82)) { flipped = false }
            }
            .opacity(flipped ? 1 : 0)
            .rotation3DEffect(.degrees(180), axis: (x: 0, y: 1, z: 0))
        }
        .frame(height: flipped ? expandedH : frontH)
        .rotation3DEffect(.degrees(flipped ? 180 : 0), axis: (x: 0, y: 1, z: 0), perspective: 0.55)
        .animation(.spring(response: 0.6, dampingFraction: 0.82), value: flipped)
        .contentShape(Rectangle())
        .onTapGesture { flipped.toggle() }
        .accessibilityAddTraits(.isButton)
    }
}

