/// Match an "AWY @ HOM" abbreviation label (a hub edge's `game`) against a
/// full-team-name matchup string. Both abbreviations must resolve (via the
/// MLB, NBA, or World Cup keyword maps) to a name present in the matchup —
/// collisions (MIN Twins vs MIN Timberwolves, COL Rockies vs COL Colombia)
/// sort themselves out because BOTH sides must match the same matchup.
/// Compact in-card status text: "LIVE 4–6 · INN 7" / "FINAL · 4–6" (away–home;
/// the card already names the teams, so no abbreviations).
func liveSlotText(_ ls: LiveScore, label: String) -> String {
    var bits: [String] = [label]
    if let a = ls.away_score, let h = ls.home_score { bits.append("\(a)–\(h)") }
    if label == "LIVE", let det = ls.detail, !det.isEmpty, det != "LIVE" { bits.append(det) }
    return bits.joined(separator: " · ")
}

/// The rich live line shared by game + prop cards so they read identically:
/// team abbrs + score + the live situation. WC/NBA/NHL carry the poller's
/// `detail` (match minute "67'" / "Q3 4:12" / period); MLB adds outs + base
/// runners. e.g. "LIVE · URU 0 · KSA 1 · 67'" or
/// "LIVE · SD 4 · PHI 6 · BOT 7 · 2 OUT · 1B·3B".
func liveLineRich(_ ls: LiveScore, label: String) -> String {
    var bits: [String] = [label]
    if let sl = ls.scoreLine { bits.append(sl) }
    else if let a = ls.away_score, let h = ls.home_score { bits.append("\(a)–\(h)") }
    guard label == "LIVE" else { return bits.joined(separator: " · ") }
    if let det = ls.detail, !det.isEmpty, det != "LIVE", det != "FINAL" { bits.append(det) }
    if (ls.league ?? "").uppercased() == "MLB" {
        if let o = ls.outs { bits.append("\(o) OUT") }
        let runners = [ls.onFirst ? "1B" : nil, ls.onSecond ? "2B" : nil, ls.onThird ? "3B" : nil].compactMap { $0 }
        if !runners.isEmpty { bits.append(runners.joined(separator: "·")) }
    }
    return bits.joined(separator: " · ")
}

/// Conviction tiers — Gary's vocabulary, not calculator language ("82%" is
/// fake precision and self-inflicted accountability). Bands set from the real
/// Apr–Jun 2026 confidence distribution so the tiers actually spread:
/// 27% SPRINKLE · 48% LEAN · 25% HAMMER.
func convictionTier(_ confidence: Double) -> String {
    confidence >= 0.80 ? "HAMMER" : confidence >= 0.70 ? "LEAN" : "SPRINKLE"
}

/// Splits a rationale into (take, rest): the opening 1–2 SENTENCES lead the
/// card back at quote weight and seed the front quote + share card. Sentence-
/// walked (not paragraph-split) because stored rationales open with a single
/// ~850-char paragraph; works for the current announcer voice and any future
/// shorter one. Strips the literal "Gary's Take" heading the JSON template
/// pastes in. Anything that doesn't split cleanly renders whole as `rest`.
func splitTake(_ rationale: String?) -> (take: String?, rest: String?) {
    guard var r = rationale?.trimmingCharacters(in: .whitespacesAndNewlines), !r.isEmpty else {
        return (nil, "No rationale available.")
    }
    if r.lowercased().hasPrefix("gary's take") {
        r = String(r.dropFirst("gary's take".count)).trimmingCharacters(in: .whitespacesAndNewlines)
    }

    // Sentence boundaries: ./!/? followed by whitespace, where the word
    // before the period isn't an abbreviation ("St. Louis", "Jr.", "vs.").
    let abbreviations: Set<String> = ["st", "jr", "sr", "dr", "vs", "mr", "mrs", "no"]
    var boundaries: [String.Index] = []
    var i = r.startIndex
    while i < r.endIndex, boundaries.count < 3 {
        let ch = r[i]
        if ch == "." || ch == "!" || ch == "?" {
            let next = r.index(after: i)
            if next == r.endIndex || r[next] == " " || r[next] == "\n" {
                let wordStart = r[..<i].lastIndex(where: { $0 == " " || $0 == "\n" })
                    .map { r.index(after: $0) } ?? r.startIndex
                if !abbreviations.contains(r[wordStart..<i].lowercased()) {
                    boundaries.append(next)
                }
            }
        }
        i = r.index(after: i)
    }

    // The take = the longest 1–2 sentence opening that stays under ~300
    // chars — enough to be a real quote, short enough to BE a quote.
    var cut: String.Index? = nil
    for end in boundaries.prefix(2) {
        if r.distance(from: r.startIndex, to: end) <= 300 { cut = end } else { break }
    }
    guard let cutIdx = cut else { return (nil, r) }
    let take = String(r[..<cutIdx]).trimmingCharacters(in: .whitespacesAndNewlines)
    let rest = String(r[cutIdx...]).trimmingCharacters(in: .whitespacesAndNewlines)
    guard take.count >= 40, !rest.isEmpty else { return (nil, r) }
    return (take, rest)
}

/// Official team colors, brightened just enough to read on the warm black.
/// Keyed by nickname; full names ("Chicago White Sox") match by containment,
/// and the color disambiguates where shortened display names collide (SOX).
enum TeamColors {
    static let mlb: [String: String] = [
        "Diamondbacks": "#C84052", "Braves": "#E0485C", "Orioles": "#E66426",
        "Red Sox": "#D94A52", "Cubs": "#5577D6", "White Sox": "#C8CDD2",
        "Reds": "#DD4053", "Guardians": "#DF4B57", "Rockies": "#9D85D6",
        "Tigers": "#ED6A3C", "Astros": "#ED7332", "Royals": "#5B8FE0",
        "Angels": "#DC4358", "Dodgers": "#4D90D9", "Marlins": "#38AEDC",
        "Brewers": "#F2C94C", "Twins": "#D5485F", "Mets": "#F47B33",
        "Yankees": "#8FA6CE", "Athletics": "#E8B021", "Phillies": "#E04A52",
        "Pirates": "#EFC23F", "Padres": "#D9B45B", "Giants": "#F26C2A",
        "Mariners": "#34B3A5", "Cardinals": "#DE4257", "Rays": "#74AEE0",
        "Rangers": "#5083DB", "Blue Jays": "#5C9AE6", "Nationals": "#D8454F"
    ]
    static func color(for team: String?) -> Color? {
        guard let t = team, !t.isEmpty else { return nil }
        // Two-word nicknames first so "White Sox" wins before "Sox"-ish hits.
        for key in ["Red Sox", "White Sox", "Blue Jays"] where t.localizedCaseInsensitiveContains(key) {
            return Color(hex: mlb[key]!)
        }
        if let hit = mlb.first(where: { t.localizedCaseInsensitiveContains($0.key) }) {
            return Color(hex: hit.value)
        }
        return nil
    }
}

/// League priority for defaults, headlines and board order while a
/// championship round is running: a Finals game outranks the nightly MLB
/// slate; the World Cup owns its own Home module but ranks above the daily
/// slate elsewhere. Static for now — revisit in the fall, when the World
/// Series vs NBA regular season flips this.
enum LeaguePriority {
    static func rank(_ league: String?) -> Int {
        switch (league ?? "").uppercased() {
        case "NBA": return 0
        case "WC", "SOCCER_WORLD_CUP", "SOCCER": return 1
        case "MLB": return 2
        default: return 3
        }
    }
}

func abbrGameMatches(_ abbrGame: String, matchup: String) -> Bool {
    let hay = matchup.lowercased()
    let abbrevs = abbrGame.uppercased()
        .components(separatedBy: CharacterSet(charactersIn: " @/"))
        .filter { $0.count >= 2 }
    guard abbrevs.count >= 2 else { return false }
    return abbrevs.allSatisfy { ab in
        let kws = (mlbTeamKeywords[ab] ?? []) + (nbaTeamKeywords[ab] ?? []) + (nhlTeamKeywords[ab] ?? []) + (wcTeamKeywords[ab] ?? [])
        return kws.contains { hay.contains($0) }
    }
}

/// Resolve a LiveScore's away/home runs into the orientation of a pick's
/// matchup. Defensive: live rows and picks come from the same slates so they
/// should already align, but a verdict grades against NAMES, never positions.
func orientedFinalScores(_ ls: LiveScore, awayTeam: String?, homeTeam: String?) -> (away: Int, home: Int)? {
    guard let a = ls.away_score, let h = ls.home_score else { return nil }
    func matches(_ abbr: String?, _ team: String?) -> Bool {
        guard let ab = abbr?.uppercased(), let hay = team?.lowercased(), !hay.isEmpty else { return false }
        let kws = (mlbTeamKeywords[ab] ?? []) + (nbaTeamKeywords[ab] ?? []) + (nhlTeamKeywords[ab] ?? []) + (wcTeamKeywords[ab] ?? [])
        return kws.contains { hay.contains($0) }
    }
    if matches(ls.away_abbr, awayTeam) || matches(ls.home_abbr, homeTeam) { return (a, h) }
    if matches(ls.away_abbr, homeTeam) || matches(ls.home_abbr, awayTeam) { return (h, a) }
    return (a, h)
}

/// Grade a game pick (spread / moneyline / total) against a FINAL score.
/// Returns "won" / "lost" / "push", or nil when the verdict can't be called
/// confidently (unparseable side, or a drawn moneyline — soccer three-ways
/// are the backend grader's call). pickText must already have odds stripped.
func liveGradeGamePick(pickText: String, betType: String = "", awayPicked: Bool, homePicked: Bool, away: Int, home: Int) -> String? {
    func firstDouble(_ pattern: String, in s: String) -> Double? {
        guard let rx = try? NSRegularExpression(pattern: pattern),
              let m = rx.firstMatch(in: s, range: NSRange(s.startIndex..., in: s)),
              let r = Range(m.range, in: s) else { return nil }
        return Double(s[r])
    }
    let lower = pickText.lowercased()
    // Totals — "OVER 8.5" / "UNDER 7".
    if lower.contains("over") || lower.contains("under") {
        guard let line = firstDouble(#"\d+(?:\.\d+)?"#, in: lower) else { return nil }
        let total = Double(away + home)
        if total == line { return "push" }
        return (total > line) == lower.contains("over") ? "won" : "lost"
    }
    // 3-way moneyline DRAW pick (soccer/WC: win · tie · lose) — Gary took the
    // tie, so it wins ONLY on a level result.
    if betType.lowercased() == "draw" || lower.contains("draw") {
        return away == home ? "won" : "lost"
    }
    // Side picks — need a side to grade.
    let picked: Int, other: Int
    if homePicked { picked = home; other = away }
    else if awayPicked { picked = away; other = home }
    else { return nil }
    let margin = Double(picked - other)
    // Spread — a signed line in the pick ("PHI -1.5", "Jazz +7").
    if let line = firstDouble(#"[-+]\d+(?:\.\d+)?"#, in: pickText) {
        let adjusted = margin + line
        if adjusted == 0 { return "push" }
        return adjusted > 0 ? "won" : "lost"
    }
    // Moneyline — a team-to-win pick LOSES on a draw (3-way market: win · tie ·
    // lose). Only soccer can finish level; 2-way sports never reach margin == 0
    // at FINAL, so this stays correct for MLB / NBA / NHL.
    return margin > 0 ? "won" : "lost"
}

enum PicksDay { case today, yesterday }

struct PicksCarouselView: View {
    @Environment(\.scenePhase) private var scenePhase
    @StateObject private var store = PropsSlateStore()
    /// Observe the live-score cache so the board re-renders the moment a game goes
    /// live or final. It was read via .shared without observing, so a running app
    /// kept showing the scheduled time ("1:00 PM ET") until the user relaunched.
    @ObservedObject private var liveCache = LiveScoreCache.shared
    /// Today vs Yesterday — the day dropdown (user call, Jun 17) replaces the old
    /// mixed matchup row + per-tab "YESTERDAY" tags. Today shows upcoming-first
    /// matchups; Yesterday shows that day's matchups + picks with CASHED/LOST tags.
    @State private var pickDay: PicksDay = .today
    @StateObject private var focusState = PicksFocusState.shared
    @State private var connections: [Signal] = []
    @State private var connLoaded = false
    @State private var sport = "ALL"
    @State private var page = 0
    @State private var selectedProp: PropPick?
    /// Shared-element namespace for the sliding gold underline under the active matchup tab.
    @Namespace private var pickTabNS

    /// Every league with content: today's props/picks plus the per-sport
    /// yesterday recaps (a sport with no picks today shows its results —
    /// the same rule the rest of the app follows).
    /// 2.16: Home-run bets live in The Hub's Home Run Threats lane now, so the
    /// Picks page no longer carries an MLB HR tab or any HR pick cards. A prop is
    /// an HR bet by its TYPE, not its league label — matching the prop name also
    /// drops genuine HR props that arrive tagged plain "MLB", while leaving non-HR
    /// props mislabeled "MLB HR" upstream to keep routing to the MLB tab.
    private func isHomeRunProp(_ p: PropPick) -> Bool {
        let t = (p.prop ?? "").lowercased()
        return t.contains("home_run") || t.contains("home run")
    }
    private var sports: [String] {
        var s = Set(store.slateProps.filter { !isHomeRunProp($0) }.compactMap { ($0.effectiveLeague ?? "").uppercased() }.filter { !$0.isEmpty })
        s.formUnion(store.gamePicks.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty })
        s.formUnion(store.yesterdayGamePicks.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty })
        // Today's slate leagues too — so a sport with games tonight but no picks
        // yet still gets a filter chip (matches the look-ahead matchups below).
        s.formUnion(store.slate.compactMap { ($0.league ?? "").uppercased() }.filter { !$0.isEmpty })
        // The MLB HR lane is retired — guarantee no HR chip even if a non-HR prop
        // arrives mislabeled "MLB HR" (its card already routes to MLB via propSportKey).
        s.remove("MLB HR")
        // Display priority — WC leads, then MLB (user call Jun 13 2026: the World
        // Cup outranks MLB while it's on, so it sits closest to ALL). Anything
        // else falls back to alphabetical.
        let priority: [String: Int] = ["WC": 0, "MLB": 1]
        return ["ALL"] + s.sorted { a, b in
            let ra = priority[a] ?? 50, rb = priority[b] ?? 50
            return ra == rb ? a < b : ra < rb
        }
    }
    /// A prop's tab key, with the MLB HR lane corrected to HOME-RUN props only.
    /// Non-HR props (total_bases, strikeouts) get mislabeled "MLB HR" upstream;
    /// route those to the regular MLB tab so the HR tab shows only HR bets
    /// (mirrors the storefront's propLeagueKey guard).
    private func propSportKey(_ p: PropPick) -> String {
        let key = (p.effectiveLeague ?? "").uppercased()
        if key == "MLB HR" {
            let t = (p.prop ?? "").lowercased()
            if !t.contains("home_run") && !t.contains("home run") { return "MLB" }
        }
        return key
    }
    private var filteredProps: [PropPick] {
        let base = store.slateProps.filter { !isHomeRunProp($0) }   // HR retired from Picks
        return sport == "ALL" ? base : base.filter { propSportKey($0) == sport }
    }
    /// TODAY's matchup rail uses today's FRESH props only. store.allProps is
    /// already freshness-filtered to games at/after the start of today (EST);
    /// slateProps additionally folds in yesterday's recap props for sports with
    /// nothing today — right for the results fallback, but it must NOT seed
    /// today's matchup tabs or yesterday's games leak into TODAY (the
    /// "Jays @ Sox · WEDNESDAY 6:45 PM" bug under a sport with no props yet).
    private var filteredTodayProps: [PropPick] {
        let today = store.allProps.filter { !$0.isTDPick && !isHomeRunProp($0) }   // HR retired from Picks
        return sport == "ALL" ? today : today.filter { propSportKey($0) == sport }
    }
    /// Yesterday's own props (sport-scoped, no TD picks) — the source for the
    /// Yesterday matchup row so every settled game shows, not just slate leftovers.
    private var filteredYesterdayProps: [PropPick] {
        let yp = store.yesterdayPropsAll.filter { !$0.isTDPick && !isHomeRunProp($0) }   // ungated: all of yesterday, HR retired
        return sport == "ALL" ? yp : yp.filter { propSportKey($0) == sport }
    }
    private var games: [(matchup: String, time: String, props: [PropPick])] {
        // The matchup row is day-scoped (the dropdown): Today groups today's slate
        // props; Yesterday groups yesterday's own props — sourcing the day directly
        // (not a fresh/stale filter on a shared list) is what makes EVERY yesterday
        // game show, not just the one that leaked into today's slate.
        let dayProps = pickDay == .today ? filteredTodayProps : filteredYesterdayProps
        var out = store.groupByMatchup(dayProps)
        var seenKeys = Set(out.map { Self.matchupKey($0.matchup) })
        func gameMatchup(_ p: GaryPick) -> String {
            let a = (p.awayTeam ?? "").trimmingCharacters(in: .whitespaces)
            let h = (p.homeTeam ?? "").trimmingCharacters(in: .whitespaces)
            return (a.isEmpty || h.isEmpty) ? "" : "\(a) @ \(h)"
        }
        func gameTime(_ p: GaryPick) -> String {
            if let iso = p.commence_time, let d = parseISO8601(iso) {
                return Formatters.dayTimeFormatterEST.string(from: d) + " ET"
            }
            return p.time ?? ""
        }
        // Merge in EVERY game pick for the day (all leagues), deduped against the
        // prop matchups by team last-words — so a game with a pick but no prop still
        // gets a tab. (Skipping prop-leagues here was what dropped most of Yesterday.)
        func merge(_ picks: [GaryPick]) {
            for p in picks {
                let lg = (p.league ?? "").uppercased()
                guard !lg.isEmpty, sport == "ALL" || lg == sport else { continue }
                let mu = gameMatchup(p)
                guard !mu.isEmpty else { continue }
                let key = Self.matchupKey(mu)
                guard !seenKeys.contains(key) else { continue }
                seenKeys.insert(key)
                out.append((matchup: mu, time: gameTime(p), props: []))
            }
        }
        merge(pickDay == .today ? store.gamePicks : store.yesterdayGamePicksAll)

        // LOOK-AHEAD (today only): include every game on today's slate so the user
        // sees tonight's matchups with a placeholder + intel before picks post.
        if pickDay == .today {
            for s in store.slate {
                let lg = (s.league ?? "").uppercased()
                guard sport == "ALL" || lg == sport else { continue }
                let a = (s.away_team ?? "").trimmingCharacters(in: .whitespaces)
                let h = (s.home_team ?? "").trimmingCharacters(in: .whitespaces)
                guard !a.isEmpty, !h.isEmpty else { continue }
                let mu = "\(a) @ \(h)"
                let key = Self.matchupKey(mu)
                guard !seenKeys.contains(key) else { continue }
                seenKeys.insert(key)
                let time: String = {
                    if let iso = s.commence_time, let d = parseISO8601(iso) {
                        return Formatters.dayTimeFormatterEST.string(from: d) + " ET"
                    }
                    return ""
                }()
                out.append((matchup: mu, time: time, props: []))
            }
        }

        // Today: LIVE games first, then upcoming by start time, then finished/graded
        // bumped to the very back — so the bar stays current as the day rolls on.
        // Yesterday is already all-settled; keep its existing time order.
        guard pickDay == .today else { return out }
        return out
            .map { (g: $0, bucket: gameStatusBucket($0), start: gameStart($0)) }
            .sorted { ($0.bucket, $0.start) < ($1.bucket, $1.start) }
            .map { $0.g }
    }

    /// Match key from team last-words ("San Diego Padres @ LA Dodgers" →
    /// "padres|dodgers") — dedups the slate's full names against the picks/props
    /// short matchup format.
    static func matchupKey(_ m: String) -> String {
        let sides = m.lowercased().components(separatedBy: " @ ")
        guard sides.count == 2 else { return m.lowercased() }
        let a = sides[0].components(separatedBy: " ").last ?? sides[0]
        let h = sides[1].components(separatedBy: " ").last ?? sides[1]
        return "\(a)|\(h)"
    }

    /// Matchup-bar order: LIVE (0) → upcoming (1) → finished/graded (2). Reads the
    /// live-score cache, so a game sinks to the back the moment it goes final.
    private func gameStatusBucket(_ g: (matchup: String, time: String, props: [PropPick])) -> Int {
        if let ls = LiveScoreCache.shared.status(forMatchup: g.matchup) {
            if ls.isFinal { return 2 }
            if ls.isLive { return 0 }
        }
        return 1
    }
    /// Kickoff/first-pitch as a Date, to order within a bucket (earliest game up
    /// next) — from the matchup's props, else today's slate row, else its game pick.
    private func gameStart(_ g: (matchup: String, time: String, props: [PropPick])) -> Date {
        if let iso = g.props.first?.commence_time, let d = parseISO8601(iso) { return d }
        let key = Self.matchupKey(g.matchup)
        if let s = store.slate.first(where: { Self.matchupKey("\($0.away_team ?? "") @ \($0.home_team ?? "")") == key }),
           let iso = s.commence_time, let d = parseISO8601(iso) { return d }
        if let p = store.gamePicksForMatchup(g.matchup, preferYesterday: false).first?.pick,
           let iso = p.commence_time, let d = parseISO8601(iso) { return d }
        return .distantFuture
    }
    private var topProps: [PropPick] {
        // The selected day's props only (dropdown): Today = fresh, Yesterday = settled.
        let dayProps = filteredProps.filter {
            pickDay == .today ? !store.isYesterdayProp($0) : store.isYesterdayProp($0)
        }
        return Array(dayProps.sorted { ($0.confidence ?? 0) > ($1.confidence ?? 0) }.prefix(2))
    }
    /// The selected day's top pick — today's (fresh) or yesterday's (stamped).
    private var topGamePick: (pick: GaryPick, isYesterday: Bool)? {
        let source = pickDay == .today ? store.gamePicks : store.yesterdayGamePicks
        let filtered = (sport == "ALL") ? source : source.filter { ($0.league ?? "").uppercased() == sport }
        guard let p = filtered.sorted(by: { ($0.confidence ?? 0) > ($1.confidence ?? 0) }).first else { return nil }
        return (p, pickDay == .yesterday)
    }
    private var hasContent: Bool { !topProps.isEmpty || topGamePick != nil || !games.isEmpty }

    var body: some View {
        ZStack {
            LiquidGlassBackground(grainDensity: 0)
            VStack(spacing: 0) {
                GaryPageHeader(title: "Picks", accent: GaryPageHeader<EmptyView>.dateLabel())
                headerBar
                content
            }
        }

        .task {
            await store.loadIfNeeded()
            consumeFocus()
            if !connLoaded { await loadConnections() }
        }
        .task {
            // Keep the SHARED live-score cache warm while this tab is on screen — the
            // matchup tabs and the cards both read LiveScoreCache.shared now (it owns
            // the dedup + its own 90s refresh loop), so this page no longer keeps its
            // own snapshot that could disagree with the cards.
            LiveScoreCache.shared.startIfNeeded()
        }
        .onChange(of: sport) { _ in page = 0 }
        .onChange(of: focusState.focusGame) { _ in consumeFocus() }
        .onChange(of: store.loading) { loading in if !loading { consumeFocus() } }
        .onChange(of: scenePhase) { phase in
            // Foreground → silently re-pull picks/props (the spinner is gated by
            // !hasContent, so existing data stays put while fresh rows load underneath).
            if phase == .active { Task { await store.refresh() } }
        }
    }

    /// Land on the matchup the Hub deep-linked ("LAD @ ARI"). Leaves the
    /// request pending while the slate is still loading; clears it once a
    /// match attempt has been made.
    private func consumeFocus() {
        guard let focus = focusState.focusGame else { return }
        // Deep links from the Hub land on TODAY's board (where the game lives).
        pickDay = .today
        guard !games.isEmpty else { return }
        focusState.focusGame = nil
        let apply = {
            if let idx = games.firstIndex(where: { abbrGameMatches(focus, matchup: $0.matchup) }) {
                withAnimation(.easeInOut(duration: 0.25)) { page = idx + 1 }
            }
        }
        if sport != "ALL" {
            // Widen the filter first; apply after the sport-change page reset.
            sport = "ALL"
            DispatchQueue.main.async { apply() }
        } else {
            apply()
        }
    }

    @ViewBuilder private var content: some View {
        if store.loading && !hasContent {
            Spacer(); ProgressView().tint(GaryColors.gold); Spacer()
        } else if !hasContent {
            emptyState
        } else {
            pager
        }
    }

    private var pager: some View {
        VStack(spacing: 0) {
            TabView(selection: $page) {
                ScrollView(showsIndicators: false) {
                    PicksTodayPage(topProps: topProps, topGamePick: topGamePick,
                                   gamePickResult: { store.gamePickResult($0, forYesterday: pickDay == .yesterday) }, resultForProp: { store.resultForProp($0, forYesterday: pickDay == .yesterday) },
                                   edges: sportConnections, onTapProp: { selectedProp = $0 })
                        .padding(.bottom, 130)
                }
                .refreshable { await store.refresh() }
                .tag(0)
                ForEach(Array(games.enumerated()), id: \.offset) { idx, g in
                    ScrollView(showsIndicators: false) {
                        PicksGamePage(group: g,
                                      // MLB HR is a HOME-RUN props lane — never show the game's
                                      // side/total pick there, only the HR bets. On Yesterday,
                                      // prefer yesterday's (graded) pick for a series matchup.
                                      entries: sport == "MLB HR" ? [] : store.gamePicksForMatchup(g.matchup, preferYesterday: pickDay == .yesterday),
                                      gamePickResult: { store.gamePickResult($0, forYesterday: pickDay == .yesterday) }, resultForProp: { store.resultForProp($0, forYesterday: pickDay == .yesterday) },
                                      edges: edges(for: g), onTapProp: { selectedProp = $0 })
                            .padding(.bottom, 130)
                    }
                    .refreshable { await store.refresh() }
                    .tag(idx + 1)
                }
            }
            .tabViewStyle(.page(indexDisplayMode: .never))
        }
    }

    /// Winners-anatomy nav: underline tabs for TODAY + each matchup (with a
    /// live-status second line), a hairline, then plain sport chips — no
    /// bubbles, no gold-filled filters.
    private var headerBar: some View {
        VStack(alignment: .leading, spacing: 0) {
            // Sport-filter pills sit ABOVE the matchup/game tabs (user-directed
            // swap, June 13 2026 — they used to render below the game tabs).
            if sports.count > 1 {
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(spacing: 18) {
                        ForEach(sports, id: \.self) { s in
                            let on = (s == sport)
                            Button { withAnimation(.easeInOut(duration: 0.2)) { sport = s } } label: {
                                Text(s)
                                    .font(GaryFonts.mono(12, bold: true)).tracking(0.8)
                                    .foregroundStyle(sportChipStyle(s, on: on))
                                    .frame(minHeight: 44)
                                    .contentShape(Rectangle())
                            }
                            .buttonStyle(.plain)
                        }
                    }
                    .padding(.horizontal, 16)
                    .padding(.top, 6)
                }
            }
            ScrollViewReader { proxy in
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(alignment: .bottom, spacing: 26) {
                        dayDropdown
                        ForEach(Array(games.enumerated()), id: \.offset) { idx, g in
                            gameTab(idx + 1, label: shortMatchup(g.matchup, league: gameLeague(g)).uppercased(), status: statusLine(for: g))
                        }
                    }
                    .padding(.horizontal, 16)
                    .padding(.top, 10)
                }
                .onChange(of: page) { p in withAnimation { proxy.scrollTo(p, anchor: .center) } }
            }
        }
    }

    /// Selected chip wears its sport accent (gold for ALL); the rest stay dim.
    private func sportChipStyle(_ s: String, on: Bool) -> AnyShapeStyle {
        guard on else { return AnyShapeStyle(Color.white.opacity(0.35)) }
        if s == "ALL" { return AnyShapeStyle(GaryColors.gold) }
        if s == "MLB" || s == "MLB HR" {
            // MLB reads in its field gradient (grass green → dirt brown → base white).
            return Sport.mlb.accentGradient.map { AnyShapeStyle($0) } ?? AnyShapeStyle(GaryColors.mlbFieldText)
        }
        return AnyShapeStyle(Sport.from(league: s).accentColor)
    }

    /// The Today/Yesterday selector — a dropdown in the first tab slot. Picking a day
    /// filters the matchup row + the top-pick page to that day (user call, Jun 17).
    private var dayDropdown: some View {
        let on = (page == 0)
        // Tap = quick flip between Today/Yesterday (the "click back to today" the
        // dropdown-only version lost); long-press = the menu, for an explicit pick.
        return Menu {
            Button("Today")     { withAnimation(.easeInOut(duration: 0.25)) { pickDay = .today; page = 0 } }
            Button("Yesterday") { withAnimation(.easeInOut(duration: 0.25)) { pickDay = .yesterday; page = 0 } }
        } label: {
            VStack(alignment: .leading, spacing: 4) {
                HStack(spacing: 4) {
                    Text(pickDay == .today ? "TODAY" : "YESTERDAY")
                        .font(GaryFonts.mono(13, bold: true)).tracking(0.5)
                        .foregroundStyle(on ? .white : .white.opacity(0.45))
                    Image(systemName: "chevron.down")
                        .font(.system(size: 8, weight: .bold))
                        .foregroundStyle(GaryColors.gold)
                }
                Text(" ")
                    .font(GaryFonts.mono(8.5, bold: true)).tracking(0.5)
                Group {
                    if on {
                        Capsule().fill(GaryColors.gold).frame(height: 2)
                            .matchedGeometryEffect(id: "pickTabUnderline", in: pickTabNS)
                    } else {
                        Capsule().fill(Color.clear).frame(height: 2)
                    }
                }
            }
            .contentShape(Rectangle())
        } primaryAction: {
            withAnimation(.easeInOut(duration: 0.25)) {
                if page != 0 {
                    // On a matchup tab — tap the day chip to return to THIS day's
                    // overview (page 0), keeping the day (Today stays Today).
                    page = 0
                } else {
                    // Already on the day tab — flip Today <-> Yesterday.
                    pickDay = (pickDay == .today ? .yesterday : .today)
                }
            }
        }
        .id(0)
    }

    /// Underline tab (the Winners GAMES/PROPS anatomy): matchup label, a
    /// status second line (LIVE/score/time), gold capsule underline on active.
    private func gameTab(_ index: Int, label: String, status: (text: String, color: Color)?) -> some View {
        let on = (index == page)
        return Button { withAnimation(.easeInOut(duration: 0.25)) { page = index } } label: {
            VStack(alignment: .leading, spacing: 4) {
                Text(label)
                    .font(GaryFonts.mono(13, bold: true)).tracking(0.5)
                    .foregroundStyle(on ? .white : .white.opacity(0.45))
                Text(status?.text ?? " ")
                    .font(GaryFonts.mono(8.5, bold: true)).tracking(0.5)
                    .foregroundStyle(status?.color ?? .clear)
                // Gold active-underline (restored, user call Jun 16) — a single capsule
                // that slides between tabs via matchedGeometry; inactive tabs hold a
                // clear spacer so every tab keeps the same height.
                Group {
                    if on {
                        Capsule().fill(GaryColors.gold).frame(height: 2)
                            .matchedGeometryEffect(id: "pickTabUnderline", in: pickTabNS)
                    } else {
                        Capsule().fill(Color.clear).frame(height: 2)
                    }
                }
            }
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .id(index)
    }

    /// Live-score row for a matchup (poller snapshots, abbr-matched).
    func liveScore(forMatchup matchup: String) -> LiveScore? {
        // Read the SHARED cache's deduped lookup (a live/scheduled row wins over a
        // bogus duplicate "final") — the exact source the pick cards read. This is
        // what keeps the matchup TAB and the CARD from disagreeing: the tab used to
        // grab `liveScores.first` (no dedup) and showed a stale "FINAL 5-3" while the
        // card showed the real "LIVE 0-0" for the same game.
        LiveScoreCache.shared.status(forMatchup: matchup)
    }

    private func statusLine(for g: (matchup: String, time: String, props: [PropPick])) -> (text: String, color: Color)? {
        // No per-tab "YESTERDAY" tag anymore — the Today/Yesterday dropdown carries
        // the day now (user call, Jun 17); the tab just shows live/final/time.
        // Yesterday's FINAL comes from the graded result, not the live-score cache
        // (which only reliably has today's games) — otherwise half of yesterday's
        // tabs fall back to the start time instead of showing the score.
        if pickDay == .yesterday, let raw = store.finalScore(forMatchup: g.matchup) {
            return ("FINAL · \(formatFinalScore(g.matchup, raw))", .white.opacity(0.35))
        }
        if let ls = liveScore(forMatchup: g.matchup) {
            if ls.isLive {
                let score = ls.scoreLine.map { " · \($0)" } ?? ""
                let det = (ls.detail?.isEmpty == false) ? " · \(ls.detail!)" : ""
                return ("▶ LIVE\(score)\(det)", GaryColors.gold)
            }
            if ls.isFinal, let score = ls.scoreLine {
                return ("FINAL · \(score)", .white.opacity(0.35))
            }
        }
        // Pre-game: the start time (restored, user call Jun 16) lives here in the
        // nav bar now that the matchup page's title/time hero is gone. Live and
        // final scores take precedence above; this is the quiet pre-game state.
        return g.time.isEmpty ? nil : (g.time.uppercased(), .white.opacity(0.5))
    }

    /// Three-letter team abbreviation from the league keyword maps (sibling of the
    /// Home view's teamAbbrev) — renders yesterday's final as "COL 6 · CHC 8",
    /// matching the live-score line format.
    private func teamAbbrev(_ name: String, league: String) -> String {
        let lower = name.lowercased()
        let maps: [[String: [String]]]
        switch league.uppercased() {
        case "MLB", "MLB HR": maps = [mlbTeamKeywords]
        case "NBA": maps = [nbaTeamKeywords]
        case "NHL": maps = [nhlTeamKeywords]
        case "WC": maps = [wcTeamKeywords]
        default: maps = [mlbTeamKeywords, nbaTeamKeywords, nhlTeamKeywords, wcTeamKeywords]
        }
        for map in maps {
            for (ab, kws) in map where kws.contains(where: { lower.contains($0) }) { return ab }
        }
        let last = lower.split(separator: " ").last.map(String.init) ?? lower
        return String(last.prefix(3)).uppercased()
    }

    /// "6-8" + "Rockies @ Cubs" -> "COL 6 · CHC 8". final_score is away-home,
    /// matching the matchup's "Away @ Home" order.
    private func formatFinalScore(_ matchup: String, _ raw: String) -> String {
        let parts = raw.components(separatedBy: CharacterSet(charactersIn: "-\u{2013}"))
            .map { $0.trimmingCharacters(in: .whitespaces) }
        let teams = matchup.components(separatedBy: " @ ")
        guard parts.count == 2, teams.count == 2 else { return raw }
        let lg = gameLeague((matchup: matchup, time: "", props: []))
        return "\(teamAbbrev(teams[0], league: lg)) \(parts[0]) \u{00B7} \(teamAbbrev(teams[1], league: lg)) \(parts[1])"
    }

    private var emptyState: some View {
        // A placeholder CARD (not a full-screen takeover) so the page layout — the day
        // dropdown + structure — stays put when there are no picks yet (user call, Jun 17).
        VStack(alignment: .leading, spacing: 0) {
            HStack(spacing: 11) {
                Image(systemName: "clock.badge")
                    .font(.system(size: 16, weight: .semibold))
                    .foregroundStyle(GaryColors.gold.opacity(0.75))
                VStack(alignment: .leading, spacing: 3) {
                    Text(pickDay == .today ? "TODAY'S PICKS ARE ON THE WAY" : "NO GRADED PICKS THIS DAY")
                        .font(GaryFonts.mono(10.5, bold: true)).tracking(1)
                        .foregroundStyle(.white.opacity(0.7))
                    Text(pickDay == .today
                         ? "Gary releases picks as lineups are confirmed — check back closer to game time."
                         : "Nothing settled for this date.")
                        .font(.system(size: 12.5)).foregroundStyle(.white.opacity(0.45))
                        .fixedSize(horizontal: false, vertical: true)
                }
                Spacer(minLength: 0)
            }
            .padding(16)
            .background(
                RoundedRectangle(cornerRadius: 16, style: .continuous)
                    .fill(Color.white.opacity(0.03))
                    .overlay(RoundedRectangle(cornerRadius: 16, style: .continuous)
                        .strokeBorder(GaryColors.gold.opacity(0.22), style: StrokeStyle(lineWidth: 1, dash: [5, 4])))
            )
            .padding(.horizontal, 16).padding(.top, 16)
            Spacer(minLength: 0)
        }
    }

    private func shortMatchup(_ m: String, league: String) -> String {
        let parts = m.components(separatedBy: " @ ")
        guard parts.count == 2 else { return m }
        // shortTeamName keeps two-word mascots whole ("Toronto Blue Jays" →
        // "Blue Jays", "Boston Red Sox" → "Red Sox") and leaves WC nations
        // ("Saudi Arabia") intact — never the bare last word.
        let a = Formatters.shortTeamName(parts[0], league: league)
        let h = Formatters.shortTeamName(parts[1], league: league)
        return "\(a) @ \(h)"
    }

    /// Best-effort league for a matchup tab so shortMatchup can pick the right
    /// shortening rule (pro mascot vs WC nation). Reads the game's own props
    /// first, then the day's picks / slate, falling back to the active filter.
    private func gameLeague(_ g: (matchup: String, time: String, props: [PropPick])) -> String {
        if let lg = g.props.first?.effectiveLeague, !lg.isEmpty { return lg.uppercased() }
        let key = Self.matchupKey(g.matchup)
        if let p = (store.gamePicks + store.yesterdayGamePicks).first(where: {
            Self.matchupKey("\($0.awayTeam ?? "") @ \($0.homeTeam ?? "")") == key }) {
            return (p.league ?? "").uppercased()
        }
        if let s = store.slate.first(where: {
            Self.matchupKey("\($0.away_team ?? "") @ \($0.home_team ?? "")") == key }) {
            return (s.league ?? "").uppercased()
        }
        return sport == "ALL" ? "" : sport
    }

    /// Best-effort: surface edges whose "ABBR @ ABBR" shares a team token with
    /// this game's matchup or its prop teams. abbrGameMatches resolves both MLB
    /// and NBA abbreviations, so either league's edges attach to their game.
    private func edges(for g: (matchup: String, time: String, props: [PropPick])) -> [Signal] {
        let hay = g.matchup + " " + g.props.compactMap { $0.team }.joined(separator: " ")
        // WC edges (the confirmed/projected XI lane) label the game with FULL nation
        // names ("Australia @ USA"), which abbrGameMatches (built for abbrev games like
        // "CHW @ DET") can't resolve — so ALSO match on the last-word matchup key.
        let key = Self.matchupKey(g.matchup)
        return connections.filter { abbrGameMatches($0.game, matchup: hay) || Self.matchupKey($0.game) == key }
    }

    /// Today-page edges respect the sport filter — an NBA tab must never
    /// show a Padres edge. Sports without a hub league (NHL) get none.
    private var sportConnections: [Signal] {
        guard sport != "ALL" else { return connections }
        guard let lg = HubLeagueSel.from(sport) else { return [] }
        return connections.filter { $0.league == lg }
    }

    private func loadConnections() async {
        let date = SupabaseAPI.todayEST()
        var out: [Signal] = []
        for lg in ["MLB", "NBA", "WC"] {
            if let conns = try? await SupabaseAPI.fetchInsightConnections(date: date, league: lg) {
                out.append(contentsOf: conns.compactMap { $0.toSignal() })
            }
        }
        await MainActor.run { connections = out; connLoaded = true }
    }
}

struct PicksTodayPage: View {
    let topProps: [PropPick]
    let topGamePick: (pick: GaryPick, isYesterday: Bool)?
    let gamePickResult: (GaryPick) -> String?
    let resultForProp: (PropPick) -> String?
    let edges: [Signal]
    let onTapProp: (PropPick) -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            topSinglePick
            EdgesSection(title: "TODAY'S EDGES", edges: edges, tabbed: true)
        }
    }

    /// The Today page is the free showcase — exactly ONE pick (user call, Jun 16):
    /// the highest-confidence play for this sport scope, game or prop, with today's
    /// fresh pick preferred over yesterday's stamped result.
    @ViewBuilder private var topSinglePick: some View {
        let gp = topGamePick
        let prop = topProps.first
        let gameFresh = gp.map { !$0.isYesterday && gamePickResult($0.pick) == nil } ?? false
        let propFresh = prop.map { resultForProp($0) == nil } ?? false
        // Prefer a fresh pick over a stamped one; within the same tier, higher
        // confidence wins. A graded yesterday card shows only if nothing fresh exists.
        let showGame: Bool = {
            guard gp != nil else { return false }
            guard prop != nil else { return true }
            if gameFresh != propFresh { return gameFresh }
            return (gp?.pick.confidence ?? 0) >= (prop?.confidence ?? 0)
        }()

        if showGame, let gp {
            freePickEyebrow   // the Today page is the free showcase — labelled for every sport
            FlippablePickCard(pick: gp.pick,
                              gameResult: gamePickResult(gp.pick),
                              showSportBadge: true)
                .padding(.horizontal, 10)
        } else if let only = prop {
            freePickEyebrow   // free showcase label on the prop too, for every sport
            FlippablePropCard(prop: only, gameResult: resultForProp(only), showSportBadge: true)
                .padding(.horizontal, 10)
        }
    }

    private var freePickEyebrow: some View {
        Text("FREE PICK")
            .font(GaryFonts.mono(9.5, bold: true)).tracking(1)
            .foregroundStyle(GaryColors.gold.opacity(0.9))
            .padding(.horizontal, 16).padding(.top, 8)
    }
}

struct PicksGamePage: View {
    let group: (matchup: String, time: String, props: [PropPick])
    let entries: [(pick: GaryPick, isYesterday: Bool)]
    let gamePickResult: (GaryPick) -> String?
    let resultForProp: (PropPick) -> String?
    let edges: [Signal]
    let onTapProp: (PropPick) -> Void

    private var topProps: [PropPick] {
        // The slip scales — show up to 5, strongest first.
        Array(group.props.sorted { ($0.confidence ?? 0) > ($1.confidence ?? 0) }.prefix(5))
    }

    /// World Cup games swap the plain GAME INTEL edges for the WC game-intel dashboard.
    private var isWorldCup: Bool {
        if (group.props.first?.effectiveLeague ?? "").uppercased() == "WC" { return true }
        if (entries.first?.pick.league ?? "").uppercased() == "WC" { return true }
        return edges.contains { $0.league == .wc }
    }
    /// The confirmed-XI edge for this WC match (carries the formation + lineup).
    private var wcXIEdge: Signal? { edges.first { $0.confirmedXI != nil } }
    /// MLB games swap the flat GAME INTEL list for the modular MLB dashboard.
    private var isMLB: Bool {
        if (group.props.first?.effectiveLeague ?? "").uppercased() == "MLB" { return true }
        if (entries.first?.pick.league ?? "").uppercased() == "MLB" { return true }
        return edges.contains { $0.league == .mlb }
    }

    /// "Blue Jays @ Red Sox" — mascot-short matchup name for the white page header.
    /// Keeps two-word mascots whole and WC nations intact (never the bare last word).
    private var matchupTitle: String {
        let parts = group.matchup.components(separatedBy: " @ ")
        guard parts.count == 2 else { return group.matchup }
        let lg = (group.props.first?.effectiveLeague ?? "").uppercased()
        return "\(Formatters.shortTeamName(parts[0], league: lg)) @ \(Formatters.shortTeamName(parts[1], league: lg))"
    }

    /// The live/final score strip ("FINAL SD 4 · PHI 6") leads the page while the
    /// game is in progress or done; pre-game opens straight to the pick.
    @ObservedObject private var liveCache = LiveScoreCache.shared
    private var heroScore: LiveScore? { liveCache.status(forMatchup: group.matchup) }

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            // The page leads STRAIGHT with Gary's pick (user call, Jun 18). The
            // matchup name + live score already live on the nav-bar tab above and
            // on each pick card's own slot (liveInSlot below), so we no longer
            // repeat a white title + LiveScoreStrip header here — the user selects
            // the game and sees the pick first, then scrolls to the intel.
            if entries.count + topProps.count > 0 {
                // All of this matchup's plays ride ONE horizontal carousel — game
                // pick(s) first (World Cup ships two: a SIDE and a TOTAL), then the
                // prop cards, strongest first. Swipe one at a time, a sliver of the
                // next peeking — the exact same full-size carousel as Home's Top
                // Plays (cardW = screen − 44). The pick cards are FULL SIZE and
                // unchanged — this only replaces the old vertical list.
                let cardW = UIScreen.main.bounds.width - 44   // a sliver of the next card peeks
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(alignment: .top, spacing: 12) {
                        ForEach(Array(entries.enumerated()), id: \.offset) { _, e in
                            FlippablePickCard(pick: e.pick,
                                              gameResult: gamePickResult(e.pick),
                                              showSportBadge: false,
                                              liveInSlot: true)
                                .frame(width: cardW)
                        }
                        ForEach(topProps) { p in
                            FlippablePropCard(prop: p, gameResult: resultForProp(p), showSportBadge: true, liveInSlot: true)
                                .frame(width: cardW)
                        }
                    }
                    .padding(.horizontal, 16)
                }
            } else if !(heroScore?.isLive ?? false) && !(heroScore?.isFinal ?? false) {
                // Look-ahead placeholder in the pick's slot — the game's on the
                // board, Gary's pick lands ~90 min out, and the intel below is
                // live now. Only for an UPCOMING game (a live/final game shows its
                // score on the LiveScoreStrip above; "drops ~90 min before" copy
                // would be wrong once the game has started).
                // No pick yet → a blurred MOCK pick card so the layout always reads
                // (paywall-style, like the Winners page). Redaction bars (never fake
                // content), unveils ~90 min before; later this same blur gates by plan.
                ZStack {
                    VStack(alignment: .leading, spacing: 12) {
                        RoundedRectangle(cornerRadius: 4).fill(GaryColors.gold.opacity(0.5)).frame(width: 92, height: 11)
                        RoundedRectangle(cornerRadius: 5).fill(Color.white.opacity(0.55)).frame(width: 210, height: 24)
                        RoundedRectangle(cornerRadius: 4).fill(Color.white.opacity(0.3)).frame(width: 150, height: 13)
                    }
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(18)
                    .background(RoundedRectangle(cornerRadius: 16, style: .continuous).fill(Color.white.opacity(0.04)))
                    .blur(radius: 5)
                    .overlay(RoundedRectangle(cornerRadius: 16, style: .continuous)
                        .strokeBorder(GaryColors.gold.opacity(0.18), lineWidth: 1))
                    VStack(spacing: 6) {
                        Image(systemName: "lock.fill").font(.system(size: 16, weight: .semibold)).foregroundStyle(GaryColors.gold)
                        Text("UNVEILS ~90 MIN BEFORE").font(GaryFonts.mono(10.5, bold: true)).tracking(1.2).foregroundStyle(.white.opacity(0.88))
                        Text("The read's below").font(.system(size: 11)).foregroundStyle(.white.opacity(0.45))
                    }
                }
                .padding(.horizontal, 10)
            }

            PlayerIntelSection(matchup: group.matchup)
            if isWorldCup {
                // World Cup: the plain GAME INTEL edges become the WC game-intel
                // dashboard (Starting XI pitch · The Read), with the existing intel
                // rows folded in beneath it.
                WCGameIntelView(matchup: group.matchup,
                                confirmedXI: wcXIEdge?.confirmedXI,
                                read: wcXIEdge ?? edges.first,
                                edges: edges,
                                showHeader: false)
            } else if isMLB {
                // MLB: the flat GAME INTEL list becomes the modular dashboard —
                // a baseball-field anchor + Pitching / Bats / Park & Weather.
                MLBGameIntelView(matchup: group.matchup, edges: edges, showHeader: false)
            } else {
                EdgesSection(title: "GAME INTEL", edges: edges)
            }
        }
        .padding(.top, 14)
        .onAppear { LiveScoreCache.shared.startIfNeeded() }
    }
}

/// PLAYER INTEL — the game page's player-level layer, between the props and
/// GAME INTEL. One row per player with a breakdown pack today (the probable
/// starters lead, then hitters); tapping a row opens the same full breakdown
/// sheet the Hub uses. Rows ride player_insight_cards (computed daily by the
/// insights pipeline) and the section hides itself entirely on days or games
/// without packs — non-MLB pages render nothing extra.
struct PlayerIntelSection: View {
    let matchup: String
    @State private var rows: [PlayerInsightCardRow] = []
    @State private var selected: PlayerInsightCardRow? = nil

    /// Keeps the page scannable — the slate page is a stack, not a roster dump.
    private static let maxRows = 8

    var body: some View {
        Group {
            if !rows.isEmpty {
                VStack(alignment: .leading, spacing: 4) {
                    Text("PLAYER INTEL")
                        .font(GaryFonts.mono(9.5, bold: true)).tracking(1)
                        .foregroundStyle(.white.opacity(0.4))
                        .padding(.horizontal, 16).padding(.top, 4)
                    VStack(spacing: 0) {
                        ForEach(Array(rows.enumerated()), id: \.element.id) { idx, row in
                            Button { selected = row } label: { intelRow(row) }
                                .buttonStyle(.plain)
                            if idx < rows.count - 1 {
                                Divider().background(Color.white.opacity(0.05)).padding(.leading, 14)
                            }
                        }
                    }
                    .quantPanel()
                    .padding(.horizontal, 16)
                }
            }
        }
        .task(id: matchup) {
            let all = await SupabaseAPI.fetchPlayerIntelRows(date: SupabaseAPI.todayEST())
            let mine = all.filter { r in
                guard let g = r.payload?.game, !g.isEmpty else { return false }
                return abbrGameMatches(g, matchup: matchup)
            }
            // Pitchers lead (they drive the matchup), then hitters by name.
            rows = Array(mine.sorted { a, b in
                let ap = a.payload?.type == "pitcher", bp = b.payload?.type == "pitcher"
                if ap != bp { return ap }
                return (a.player_name ?? "") < (b.player_name ?? "")
            }.prefix(Self.maxRows))
        }
        .sheet(item: $selected) { PlayerInsightSheet(signal: nil, prefetched: $0) }
    }

    private func intelRow(_ row: PlayerInsightCardRow) -> some View {
        let p = row.payload
        let meta = [p?.team?.uppercased(), p?.position].compactMap { $0 }.joined(separator: " · ")
        let signalLine = p?.strengths?.first ?? p?.weaknesses?.first
        return HStack(spacing: 10) {
            VStack(alignment: .leading, spacing: 3) {
                HStack(spacing: 8) {
                    Text(row.player_name ?? p?.name ?? "Player")
                        .font(GaryFonts.text(14, .semibold)).foregroundStyle(.white)
                    if !meta.isEmpty {
                        Text(meta).font(GaryFonts.mono(9.5)).foregroundStyle(.white.opacity(0.45))
                    }
                }
                if let line = signalLine {
                    Text(line)
                        .font(GaryFonts.text(12)).foregroundStyle(.white.opacity(0.55))
                        .lineLimit(2)
                }
            }
            Spacer(minLength: 8)
            Image(systemName: "chevron.right")
                .font(.system(size: 11, weight: .semibold))
                .foregroundStyle(.white.opacity(0.25))
        }
        .padding(.horizontal, 14).padding(.vertical, 11)
        .contentShape(Rectangle())
    }
}


/// The Prop Slip — one silver card, one two-line row per prop (name + team,
/// then the gold pick + odds), with a W/L letter rail that fills in as props
/// settle. Replaces stacked prop cards anywhere a game carries 1–5 props.
/// Locked-card language throughout: same frame, fonts, and gold-only-pick rule.
extension PropPick {
    /// "TOTAL BASES OVER 1.5" — the locked card's pick composition, shared by
    /// the slip rows and the condensed Take sheet.
    var slipPickText: String {
        var words = Formatters.propDisplay(prop, league: effectiveLeague)
            .split(separator: " ").map(String.init)
        if let last = words.last, Double(last) != nil { words.removeLast() }
        var name = words.joined(separator: " ").uppercased()
        name = CompactPropRow.marketAbbrevShared[name] ?? name
        var call = (bet ?? "").uppercased()
        if let raw = line?.trimmingCharacters(in: .whitespaces), !raw.isEmpty {
            let lineText = Double(raw).map { $0.truncatingRemainder(dividingBy: 1) == 0 ? String(format: "%g", $0) : String(format: "%.1f", $0) } ?? raw
            call = call.isEmpty ? lineText : "\(call) \(lineText)"
        }
        return [name, call].filter { !$0.isEmpty }.joined(separator: " ")
    }
}

struct PropSlipCard: View {
    let props: [PropPick]
    let resultForProp: (PropPick) -> String?
    /// Game pages carry the score in the page hero (LiveScoreStrip), so their
    /// slip header keeps the plain start time. The Today slip stays state-aware.
    var liveInHeader: Bool = true
    /// Winners shows each row's W/L in the row's corner (trailing); the Picks
    /// pages keep it leading, beside the name.
    var resultLetterTrailing: Bool = false

    @ObservedObject private var liveCache = LiveScoreCache.shared
    // Flip state — game-pick mechanics: tapping a row flips the whole card
    // to that prop's take; tapping the back flips home. The back carries a
    // little player toggle so one flip reads the whole slip.
    @State private var flipped = false
    @State private var backProp: PropPick? = nil
    // 0 = not yet measured — the frame stays natural until the preference
    // fires, then pins to the front's height so the hidden back face can
    // never inflate the card (it's in the tree at opacity 0 after a flip).
    @State private var frontH: CGFloat = 0
    private var expandedH: CGFloat { max(frontH + 160, 520) }

    private var leagueIcon: String {
        switch (props.first?.effectiveLeague ?? "").uppercased() {
        case "NBA", "NCAAB", "WNBA": return "basketball.fill"
        case "NFL", "NCAAF": return "football.fill"
        case "NHL": return "hockey.puck.fill"
        case "MLB": return "baseball.fill"
        case "EPL", "WC": return "soccerball"
        default: return "sportscourt.fill"
        }
    }
    private var isMLB: Bool { (props.first?.effectiveLeague ?? "").uppercased() == "MLB" }
    private var accent: Color { Sport.from(league: props.first?.effectiveLeague).accentColor }


    /// Colored W/L/P letter once graded (inlined before the name).
    private func resultLetter(_ p: PropPick) -> (String, Color)? {
        switch resultForProp(p)?.lowercased() {
        case "won": return ("W", Color(hex: "#3FB950"))
        case "lost": return ("L", Color(hex: "#E5484D"))
        case "push": return ("P", GaryColors.gold)
        default: return nil
        }
    }

    private var isSharedMatchup: Bool { Set(props.compactMap { $0.matchup }).count == 1 }

    /// Slip-level game state — only when every prop shares one matchup.
    private var sharedStatusText: String? {
        guard liveInHeader, isSharedMatchup, let m = props.first?.matchup,
              let ls = liveCache.status(forMatchup: m) else { return nil }
        if ls.isLive { return liveSlotText(ls, label: "LIVE") }
        if ls.isFinal { return liveSlotText(ls, label: "FINAL") }
        return nil
    }

    /// Header fallback when state lives in the page hero (or pre-game): the
    /// shared start time, same slot the locked card uses.
    private var sharedTimeText: String? {
        guard isSharedMatchup, let p = props.first else { return nil }
        let viaCommence = Formatters.formatCommenceTime(p.commence_time)
        if !viaCommence.isEmpty { return viaCommence.uppercased() }
        if let t = p.time, !t.isEmpty, t != "TBD" { return t.uppercased() }
        return nil
    }

    var body: some View {
        ZStack {
            // fixedSize: natural-height layout under the pinned frame (see
            // FlippablePickCard) — keeps the rows from compressing.
            front
                .fixedSize(horizontal: false, vertical: true)
                .background(GeometryReader { g in
                    Color.clear.preference(key: PickCardHeightKey.self, value: g.size.height)
                })
                .opacity(flipped ? 0 : 1)

            if backProp != nil {
                PropSlipBack(props: props, current: $backProp) {
                    withAnimation(.spring(response: 0.6, dampingFraction: 0.82)) { flipped = false }
                }
                .opacity(flipped ? 1 : 0)
                .rotation3DEffect(.degrees(180), axis: (x: 0, y: 1, z: 0))
            }
        }
        .frame(height: flipped ? expandedH : (frontH > 0 ? frontH : nil))
        .rotation3DEffect(.degrees(flipped ? 180 : 0), axis: (x: 0, y: 1, z: 0), perspective: 0.55)
        .onPreferenceChange(PickCardHeightKey.self) { h in if h > 1, !flipped { frontH = h } }
        .animation(.spring(response: 0.6, dampingFraction: 0.82), value: flipped)
        .onAppear { LiveScoreCache.shared.startIfNeeded() }
    }

    private func resultCapsule(_ r: (String, Color)) -> some View {
        // Colored mono letter, no bubble — the app-wide result-tag rule.
        Text(r.0)
            .font(GaryFonts.mono(11, bold: true))
            .tracking(0.5)
            .foregroundStyle(r.1)
    }

    private var front: some View {
        VStack(alignment: .leading, spacing: 0) {
            // Slip header — locked card's eyebrow anatomy: LEAGUE + prop count.
            HStack(spacing: 8) {
                Image(systemName: leagueIcon)
                    .font(.system(size: 12, weight: .semibold))
                    .foregroundStyle(isMLB ? GaryColors.mlbGrass : accent)
                Text((props.first?.effectiveLeague ?? "PROPS").uppercased())
                    .font(GaryFonts.mono(11, bold: true))
                    .tracking(1)
                    .foregroundStyle(isMLB ? AnyShapeStyle(GaryColors.mlbFieldText) : AnyShapeStyle(accent))
                Text("· \(props.count)")
                    .font(GaryFonts.mono(11, bold: false))
                    .foregroundStyle(.white.opacity(0.34))
                Spacer()
                // One game state for the whole slip (Today); game pages put the
                // score in the page hero, so their header keeps the start time.
                // Mixed-game slips stay quiet — their chips carry state up top.
                if let shared = sharedStatusText {
                    Text(shared)
                        .font(GaryFonts.mono(9.5, bold: false))
                        .tracking(0.5)
                        .foregroundStyle(.white.opacity(0.34))
                        .lineLimit(1)
                } else if !liveInHeader, let t = sharedTimeText {
                    Text(t)
                        .font(GaryFonts.mono(11, bold: false))
                        .tracking(1)
                        .foregroundStyle(.white.opacity(0.34))
                        .lineLimit(1)
                }
            }
            .padding(.bottom, 9)

            StitchLine()
                .stroke(GaryColors.gold.opacity(0.3), style: StrokeStyle(lineWidth: 1, dash: [4, 5]))
                .frame(height: 1)

            // Rows — each mirrors the locked card's sequence, frameless:
            // status line → name + Gary's Take → boxed gold-pick chip.
            ForEach(Array(props.enumerated()), id: \.element.id) { i, p in
                if i > 0 {
                    StitchLine()
                        .stroke(Color.white.opacity(0.12), style: StrokeStyle(lineWidth: 1, dash: [4, 5]))
                        .frame(height: 1)
                }
                Button {
                    backProp = p
                    withAnimation(.spring(response: 0.6, dampingFraction: 0.82)) { flipped = true }
                } label: {
                    VStack(alignment: .leading, spacing: 11) {
                        HStack(alignment: .firstTextBaseline, spacing: 8) {
                            // Single letter in the game-pick capsule design —
                            // leading on Picks, trailing corner on Winners.
                            if !resultLetterTrailing, let r = resultLetter(p) {
                                resultCapsule(r)
                            }
                            Text(p.player ?? p.team ?? "")
                                .font(GaryFonts.text(24, .medium))
                                .foregroundStyle(.white)
                                .lineLimit(1)
                                .minimumScaleFactor(0.65)
                            if let team = p.team, !team.isEmpty {
                                Text(Formatters.shortTeamName(team, league: p.effectiveLeague).uppercased())
                                    .font(.system(size: 10, weight: .semibold))
                                    .foregroundStyle(GaryColors.silver.opacity(0.8))
                                    .lineLimit(1)
                            }
                            Spacer(minLength: 8)
                            // Chevron only — "Gary's Take" words dropped to match the
                            // game/prop cards (user call: keep the arrow, lose the label).
                            Image(systemName: "chevron.right")
                                .font(.system(size: 12, weight: .bold))
                                .foregroundStyle(GaryColors.heroAccent.opacity(0.7))
                            .layoutPriority(1)
                            if resultLetterTrailing, let r = resultLetter(p) {
                                resultCapsule(r)
                            }
                        }
                        HStack(alignment: .firstTextBaseline, spacing: 8) {
                            propPickStyled(p.slipPickText)
                                .font(GaryFonts.mono(17, bold: true))
                                .tracking(0.8)
                                .foregroundStyle(GaryColors.heroAccent)
                                .lineLimit(1)
                                .minimumScaleFactor(0.6)
                            Spacer(minLength: 8)
                            Text(Formatters.americanOdds(p.odds))
                                .font(GaryFonts.mono(15, bold: true))
                                .foregroundStyle(GaryColors.silver.opacity(0.8))
                        }
                        .padding(.horizontal, 14)
                        .padding(.vertical, 12)
                        .frame(maxWidth: .infinity)
                        .background(
                            RoundedRectangle(cornerRadius: 10, style: .continuous)
                                .fill(Color(hex: "#1F1C1C"))
                                .overlay(
                                    RoundedRectangle(cornerRadius: 10, style: .continuous)
                                        .stroke(GaryColors.silver.opacity(0.55), lineWidth: 1)
                                )
                        )
                    }
                    .padding(.vertical, 13)
                    .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
            }
        }
        .padding(.horizontal, 12)
        .padding(.top, 12)
        .padding(.bottom, 4)
        .background(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .fill(Color(hex: "#181616"))
                .overlay(
                    RoundedRectangle(cornerRadius: 12, style: .continuous)
                        .stroke(GaryColors.silver.opacity(0.4), lineWidth: 1.0)
                )
                .shadow(color: .black.opacity(0.45), radius: 14, y: 6)
        )
    }
}

/// The slip's back face — one prop's take in the game-pick back's language:
/// gold voice header, the pick, THE NUMBERS, THE READ, tap to flip home.
/// A little player toggle hops between the slip's reads without flipping —
/// one flip reads the whole slip instead of packing it all into one view.
struct PropSlipBack: View {
    let props: [PropPick]
    @Binding var current: PropPick?
    let onFlipBack: () -> Void

    private var prop: PropPick { current ?? props[0] }

    private func toggleName(_ p: PropPick) -> String {
        let full = p.player ?? p.team ?? ""
        return (full.split(separator: " ").last.map(String.init) ?? full).uppercased()
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 9) {
            HStack {
                Text("GARY'S TAKE")
                    .font(GaryFonts.mono(11, bold: true)).tracking(1)
                    .foregroundStyle(GaryColors.gold)
                Spacer()
                if let m = prop.matchup, !m.isEmpty {
                    Text(m.uppercased())
                        .font(GaryFonts.mono(10, bold: false))
                        .foregroundStyle(.white.opacity(0.4)).lineLimit(1).minimumScaleFactor(0.7)
                }
            }

            if props.count > 1 {
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(spacing: 6) {
                        ForEach(props, id: \.id) { p in
                            let on = p.id == prop.id
                            Button {
                                withAnimation(.easeInOut(duration: 0.18)) { current = p }
                            } label: {
                                Text(toggleName(p))
                                    .font(GaryFonts.mono(10, bold: true)).tracking(0.6)
                                    .foregroundStyle(on ? Color.black.opacity(0.85) : GaryColors.silver.opacity(0.75))
                                    .padding(.horizontal, 10).padding(.vertical, 5)
                                    .background(
                                        Capsule()
                                            .fill(on ? GaryColors.silver.opacity(0.92) : Color.white.opacity(0.05))
                                            .overlay(Capsule().stroke(GaryColors.silver.opacity(on ? 0 : 0.35), lineWidth: 1))
                                    )
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
            }

            HStack(alignment: .firstTextBaseline, spacing: 8) {
                Text(prop.player ?? "")
                    .font(.system(size: 19, weight: .heavy))
                    .foregroundStyle(GaryColors.silver).lineLimit(1).minimumScaleFactor(0.7)
                Spacer()
                if let team = prop.team, !team.isEmpty {
                    Text(Formatters.shortTeamName(team, league: prop.effectiveLeague).uppercased())
                        .font(.system(size: 10, weight: .semibold))
                        .foregroundStyle(GaryColors.silver.opacity(0.7))
                }
            }

            HStack(alignment: .firstTextBaseline, spacing: 8) {
                propPickStyled(prop.slipPickText)
                    .font(GaryFonts.mono(15, bold: true)).tracking(0.6)
                    .foregroundStyle(GaryColors.heroAccent)
                    .lineLimit(1).minimumScaleFactor(0.65)
                Spacer(minLength: 6)
                Text(Formatters.americanOdds(prop.odds))
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(GaryColors.silver.opacity(0.8))
            }

            ScrollView(showsIndicators: false) {
                VStack(alignment: .leading, spacing: 10) {
                    if let stats = prop.key_stats, !stats.isEmpty {
                        VStack(alignment: .leading, spacing: 6) {
                            Text("The Numbers")
                                .font(GaryFonts.display(15))
                                .foregroundStyle(GaryColors.sectionHead)
                            ForEach(Array(stats.prefix(4).enumerated()), id: \.offset) { _, s in
                                HStack(alignment: .top, spacing: 7) {
                                    Circle().fill(GaryColors.silver.opacity(0.7))
                                        .frame(width: 4, height: 4).padding(.top, 7)
                                    Text(s)
                                        .font(.system(size: 14)).foregroundStyle(.white.opacity(0.85))
                                        .fixedSize(horizontal: false, vertical: true)
                                }
                            }
                        }
                    }
                    if let a = prop.analysis, !a.isEmpty {
                        VStack(alignment: .leading, spacing: 5) {
                            Text("The Read")
                                .font(GaryFonts.display(15))
                                .foregroundStyle(GaryColors.sectionHead)
                            Text(cleanPropAnalysis(a))
                                .font(.system(size: 14.5)).foregroundStyle(.white.opacity(0.75))
                                .lineSpacing(3)
                                .fixedSize(horizontal: false, vertical: true)
                        }
                    }
                }
            }

            Text("tap to flip back  ↺")
                .font(GaryFonts.mono(9, bold: false)).tracking(0.6)
                .foregroundStyle(.white.opacity(0.3))
                .frame(maxWidth: .infinity, alignment: .center)
        }
        .padding(14)
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
        .background(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .fill(Color(hex: "#1C1A1A"))
                .overlay(
                    RoundedRectangle(cornerRadius: 12, style: .continuous)
                        .stroke(GaryColors.silver.opacity(0.32), lineWidth: 1)
                )
        )
        .contentShape(Rectangle())
        .onTapGesture { onFlipBack() }
    }
}

/// Compact live/final score banner above a game's pick card.
struct LiveScoreStrip: View {
    let score: LiveScore
    var body: some View {
        HStack(spacing: 8) {
            if score.isLive {
                Circle().fill(GaryColors.gold).frame(width: 6, height: 6)
                Text("LIVE")
                    .font(GaryFonts.mono(9.5, bold: true)).tracking(1.4)
                    .foregroundStyle(GaryColors.gold)
            } else {
                Text("FINAL")
                    .font(GaryFonts.mono(9.5, bold: true)).tracking(1.4)
                    .foregroundStyle(.white.opacity(0.5))
            }
            if let line = score.scoreLine {
                Text(line)
                    .font(GaryFonts.mono(13, bold: true))
                    .foregroundStyle(GaryColors.gold)
            }
            if score.isLive, let det = score.detail, !det.isEmpty {
                Text(det)
                    .font(GaryFonts.mono(10, bold: true)).tracking(0.6)
                    .foregroundStyle(GaryColors.gold.opacity(0.6))
            }
            if score.hasGameState {
                BaseDiamond(onFirst: score.onFirst, onSecond: score.onSecond, onThird: score.onThird)
                    .padding(.leading, 2)
                if let o = score.outs {
                    HStack(spacing: 3) {
                        ForEach(0..<2, id: \.self) { i in
                            Circle()
                                .fill(i < min(o, 2) ? GaryColors.gold : Color.white.opacity(0.18))
                                .frame(width: 5, height: 5)
                        }
                    }
                    Text("OUT")
                        .font(GaryFonts.mono(8.5, bold: true)).tracking(0.5)
                        .foregroundStyle(.white.opacity(0.4))
                }
            }
            Spacer()
        }
        .padding(.vertical, 2)
    }
}

/// Tiny baseball diamond — a base fills gold when a runner is on. MLB live cards only.
struct BaseDiamond: View {
    let onFirst: Bool
    let onSecond: Bool
    let onThird: Bool
    var size: CGFloat = 20

    private func base(_ on: Bool) -> some View {
        let s = size * 0.34
        return RoundedRectangle(cornerRadius: 1.5, style: .continuous)
            .fill(on ? GaryColors.gold : Color.white.opacity(0.10))
            .overlay(
                RoundedRectangle(cornerRadius: 1.5, style: .continuous)
                    .stroke(on ? GaryColors.gold : Color.white.opacity(0.3), lineWidth: 0.8)
            )
            .frame(width: s, height: s)
            .rotationEffect(.degrees(45))
    }

    var body: some View {
        ZStack {
            base(onSecond).offset(y: -size * 0.28)
            base(onThird).offset(x: -size * 0.28)
            base(onFirst).offset(x: size * 0.28)
        }
        .frame(width: size, height: size)
    }
}

// MARK: - Connection -> Signal mapping
// Lets a fetched `Connection` (Models.swift) render through SignalRow/PropsHubView
// UNCHANGED. Reuses the existing SignalKind cases by matching the category string.

extension SignalKind {
    /// Map a stored category string onto an existing SignalKind case.
    /// Returns nil for unrecognized kinds so the row is dropped rather than
    /// mis-bucketed.
    static func from(_ raw: String?) -> SignalKind? {
        switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
        case "streak": return .streak
        case "h2h", "head-to-head", "head_to_head", "owned": return .h2h
        case "hot", "heat", "heat check", "heat_check": return .hot
        case "cold", "cooling", "cooling off", "cooling_off": return .cold
        case "injury", "replacement", "beneficiary": return .injury
        case "situational", "rest", "fatigue", "rest & fatigue", "rest_fatigue": return .situational
        case "platoon", "platoon edge", "platoon_edge": return .platoon
        case "ballpark", "ballpark shift", "ballpark_shift": return .ballpark
        case "regression", "regression watch", "regression_watch", "regression_tomorrow": return .regression
        case "tournament", "stakes", "group", "tournament_stakes": return .tournament
        case "gary_hr_threats", "hr_threat", "hr threats": return .hrThreat
        case "streaking": return .streak
        case "starter_form": return .starterForm
        case "first_inning": return .firstInning
        case "running_game": return .runningGame
        case "park_weather": return .parkWeather
        default: return nil
        }
    }
}

extension HubLeagueSel {
    static func from(_ raw: String?) -> HubLeagueSel? {
        switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).uppercased() {
        case "MLB": return .mlb
        case "NBA": return .nba
        case "WC", "WORLD CUP", "SOCCER_WORLD_CUP": return .wc
        default: return nil
        }
    }
}

extension HubTone {
    static func from(_ raw: String?) -> HubTone {
        switch (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
        case "good", "positive", "up": return .good
        case "bad", "negative", "down": return .bad
        default: return .neutral
        }
    }
}

extension Connection {
    /// Convert to a render-ready Signal. Returns nil when the row lacks the
    /// minimum needed to bucket/render it (unknown league or category), so the
    /// caller can decide whether the overall fetch is usable.
    func toSignal() -> Signal? {
        guard let lg = HubLeagueSel.from(league),
              let kd = SignalKind.from(category) else { return nil }
        let head = (headline ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !head.isEmpty else { return nil }

        return Signal(
            league: lg,
            kind: kd,
            headline: head,
            detail: detail ?? "",
            game: (game ?? "").trimmingCharacters(in: .whitespacesAndNewlines),
            value: value ?? "",
            tone: HubTone.from(tone),
            spark: spark ?? [],
            lineVal: line_val,
            playerId: player_id,
            result: result,
            resultNote: result_note,
            swap: (meta?.kind == "swap") ? meta : nil,
            confirmedXI: (meta?.kind == "confirmedXI") ? meta : nil,
            reg: (meta?.kind == "regression_pitcher") ? meta : nil
        )
    }
}


// MARK: - Night Board (the whole league's night, searchable — night_highlights)

/// Every homer, multi-hit night, K show, gem, RBI night and steal job from
/// last night — searchable by player or team, Gary's mark only where he had
/// the position. The Hub's morning centerpiece.
struct NightBoard: View {
    let rows: [NightHighlightRow]
    @State private var tab = 0

    static let cats: [(key: String, label: String, noun: String)] = [
        ("hr", "HR", "homered"),
        ("multi_hit", "2+ HITS", "had multi-hit nights"),
        ("k_show", "K SHOW", "struck out 7+"),
        ("gem", "GEMS", "dealt a gem"),
        ("rbi_night", "RBI", "drove in 3+"),
        ("sb_night", "SPEED", "stole 2+ bags")
    ]

    private var present: [(key: String, label: String, noun: String)] {
        Self.cats.filter { c in rows.contains { $0.category == c.key } }
    }

    private static func lead(_ d: String?) -> Int {
        Int((d ?? "").prefix(while: { $0.isNumber })) ?? 0
    }

    private func ordered(_ r: [NightHighlightRow]) -> [NightHighlightRow] {
        r.sorted {
            let (a, b) = (Self.lead($0.detail), Self.lead($1.detail))
            if a != b { return a > b }
            return ($0.gary_result != nil) && ($1.gary_result == nil)
        }
    }

    /// Player names get their own shortener — the team one takes the last
    /// word, which turns "Bobby Witt Jr." into "JR.".
    static func shortPlayer(_ name: String?) -> String {
        let suffixes: Set<String> = ["jr", "jr.", "sr", "sr.", "ii", "iii", "iv", "v"]
        let parts = (name ?? "").split(separator: " ").map(String.init)
        guard let last = parts.last else { return "" }
        if suffixes.contains(last.lowercased()), parts.count >= 2 {
            return parts.suffix(2).joined(separator: " ")
        }
        return last
    }

    private var visible: [NightHighlightRow] {
        // Page-level search covers the board now (one search per page);
        // the board itself just tabs its categories.
        guard !present.isEmpty else { return [] }
        let key = present[min(tab, present.count - 1)].key
        return ordered(rows.filter { $0.category == key })
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            if present.count > 1 { tabStrip }
            VStack(spacing: 0) {
                if visible.isEmpty {
                    Text("Nothing on the board from last night.")
                        .font(.system(size: 12))
                        .foregroundStyle(.white.opacity(0.4))
                        .padding(.horizontal, 14).padding(.vertical, 16)
                        .frame(maxWidth: .infinity, alignment: .leading)
                }
                ForEach(Array(visible.enumerated()), id: \.offset) { i, r in
                    boardRow(r, showCategory: false)
                    if i < visible.count - 1 {
                        Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
                    }
                }
            }
            .quantPanel()
        }
    }

    private var tabStrip: some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 18) {
                ForEach(Array(present.enumerated()), id: \.offset) { i, c in
                    Button {
                        withAnimation(.easeInOut(duration: 0.15)) { tab = i }
                    } label: {
                        Text(c.label)
                            .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                            .foregroundStyle(i == tab ? GaryColors.gold : .white.opacity(0.4))
                            .frame(minHeight: 30)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                }
            }
            .padding(.horizontal, 2)
        }
    }

    private func boardRow(_ r: NightHighlightRow, showCategory: Bool) -> some View {
        HStack(spacing: 8) {
            VStack(alignment: .leading, spacing: 2) {
                Text(Self.shortPlayer(r.player_name).uppercased())
                    .font(GaryFonts.mono(12, bold: true))
                    .foregroundStyle(.white.opacity(0.9))
                    .lineLimit(1).minimumScaleFactor(0.7)
                if showCategory, let c = Self.cats.first(where: { $0.key == r.category }) {
                    Text(c.label)
                        .font(GaryFonts.mono(8))
                        .foregroundStyle(GaryColors.gold.opacity(0.7))
                }
            }
            .frame(width: 108, alignment: .leading)
            Text(HomeView.shortTeam(r.team).uppercased())
                .font(GaryFonts.mono(10.5, bold: true))
                .foregroundStyle(TeamColors.color(for: r.team) ?? .white.opacity(0.45))
                .lineLimit(1).minimumScaleFactor(0.7)
                .frame(width: 64, alignment: .leading)
            Text(r.detail ?? "")
                .font(GaryFonts.mono(11.5, bold: true))
                .foregroundStyle(.white.opacity(0.92))
                .lineLimit(1).minimumScaleFactor(0.75)
                .frame(maxWidth: .infinity, alignment: .trailing)
            Group {
                switch r.gary_result {
                case "won":  Text("✓").foregroundStyle(GaryColors.win)
                case "lost": Text("✗").foregroundStyle(GaryColors.loss)
                default:     Text("–").foregroundStyle(.white.opacity(0.35))
                }
            }
            .font(.system(size: 11, weight: .bold))
            .frame(width: 22, alignment: .center)
        }
        .padding(.vertical, 9).padding(.horizontal, 14)
    }
}

// MARK: - Streak Board (the full Streaks experience — streaks table)

/// Live runs around the league: teams on runs, hot bats, cold bats — and
/// which streaks are on the line tonight. TEAMS / HOT BATS / COLD BATS tabs,
/// same gold-when-active grammar as every other strip.
struct StreakBoard: View {
    let rows: [StreakRow]
    /// Tap on a row with a game tonight → that game's page on the Picks tab
    /// (receives an "Away @ Home" matchup string).
    var onTapGame: (String) -> Void = { _ in }
    @State private var tab = 0

    private struct Group {
        let label: String
        let rows: [StreakRow]
    }

    /// Tonight's actionable streaks lead; longest runs break ties.
    private func ordered(_ r: [StreakRow]) -> [StreakRow] {
        r.sorted {
            let (a, b) = ($0.next_game != nil, $1.next_game != nil)
            if a != b { return a }
            return ($0.length ?? 0) > ($1.length ?? 0)
        }
    }

    private var groups: [Group] {
        var out: [Group] = []
        let teams = rows.filter { $0.subject_type == "team" && ["win", "loss"].contains($0.kind ?? "") }
        if !teams.isEmpty { out.append(Group(label: "TEAMS", rows: ordered(teams))) }
        let hot = rows.filter { ["hit", "hr"].contains($0.kind ?? "") }
        if !hot.isEmpty { out.append(Group(label: "HOT BATS", rows: ordered(hot))) }
        let cold = rows.filter { $0.kind == "hitless" }
        if !cold.isEmpty { out.append(Group(label: "COLD BATS", rows: ordered(cold))) }
        let totals = rows.filter { ["over", "under"].contains($0.kind ?? "") }
        if !totals.isEmpty { out.append(Group(label: "TOTALS", rows: ordered(totals))) }
        return out
    }

    /// nil when no row matches any group (e.g. a future pipeline kind) —
    /// indexing groups[-1] here used to be a latent crash.
    private var current: Group? {
        groups.isEmpty ? nil : groups[min(tab, groups.count - 1)]
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            if let current {
                if groups.count > 1 { tabStrip }
                VStack(spacing: 0) {
                    ForEach(Array(current.rows.prefix(10).enumerated()), id: \.offset) { i, r in
                        streakRow(r)
                        if i < min(current.rows.count, 10) - 1 {
                            Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
                        }
                    }
                }
                .quantPanel()
            }
        }
    }

    private var tabStrip: some View {
        HStack(spacing: 18) {
            ForEach(Array(groups.enumerated()), id: \.offset) { i, g in
                Button {
                    withAnimation(.easeInOut(duration: 0.15)) { tab = i }
                } label: {
                    Text(g.label)
                        .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                        .foregroundStyle(i == tab ? GaryColors.gold : .white.opacity(0.4))
                        .frame(minHeight: 30)
                        .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
            }
            Spacer()
        }
        .padding(.horizontal, 2)
    }

    /// "W7" / "L5" / "16 GM" / "HR ×4" / "0-22" — the streak, data voice.
    private func badge(_ r: StreakRow) -> (text: String, color: Color) {
        let n = r.length ?? 0
        switch r.kind {
        case "win":     return ("W\(n)", GaryColors.win)
        case "loss":    return ("L\(n)", GaryColors.loss)
        case "hit":     return ("\(n) GM", GaryColors.gold)
        case "hr":      return ("HR ×\(n)", GaryColors.gold)
        case "hitless": return ("0-\(n)", GaryColors.loss)
        case "over":    return ("O ×\(n)", GaryColors.win)
        case "under":   return ("U ×\(n)", GaryColors.loss)
        default:        return ("\(n)", .white.opacity(0.6))
        }
    }

    /// The detail line often repeats the badge ("W5 — outscored foes 33-14"
    /// next to a W5 badge) — strip the echo, keep only what the badge can't say.
    private func cleanDetail(_ r: StreakRow, badgeText: String) -> String? {
        guard var d = r.detail, !d.isEmpty else { return nil }
        for sep in [" — ", " - "] where d.hasPrefix(badgeText + sep) {
            d = String(d.dropFirst(badgeText.count + sep.count))
        }
        return d.isEmpty ? nil : d
    }

    /// "AT METS · 7:10 PM ET" + "St. Louis Cardinals" → "Cardinals @ Mets"
    /// (away @ home) — the matchup string the Picks deep-link matches on.
    private func matchup(_ r: StreakRow) -> String? {
        guard let next = r.next_game, let team = r.team ?? r.subject else { return nil }
        let head = next.components(separatedBy: "·").first?
            .trimmingCharacters(in: .whitespaces) ?? ""
        let up = head.uppercased()
        let opp: String
        let homeGame: Bool
        if up.hasPrefix("AT ") { opp = String(head.dropFirst(3)); homeGame = false }
        else if up.hasPrefix("VS ") { opp = String(head.dropFirst(3)); homeGame = true }
        else { return nil }
        guard !opp.isEmpty else { return nil }
        return homeGame ? "\(opp) @ \(team)" : "\(team) @ \(opp)"
    }

    private func streakRow(_ r: StreakRow) -> some View {
        let b = badge(r)
        let game = matchup(r)
        let row = HStack(spacing: 12) {
            Text(b.text)
                .font(GaryFonts.mono(12, bold: true))
                .foregroundStyle(b.color)
                .lineLimit(1).minimumScaleFactor(0.7)
                .frame(width: 56, alignment: .leading)
            VStack(alignment: .leading, spacing: 3) {
                Text(r.subject ?? "")
                    .font(GaryFonts.text(14, .semibold))
                    .foregroundStyle(.white.opacity(0.92))
                    .lineLimit(1)
                if let d = cleanDetail(r, badgeText: b.text) {
                    Text(d)
                        .font(GaryFonts.mono(11))
                        .foregroundStyle(.white.opacity(0.62))
                        .lineLimit(1).minimumScaleFactor(0.8)
                }
            }
            Spacer(minLength: 8)
            if let next = r.next_game, !next.isEmpty {
                // Just the game — gold marks it tappable; the section sub
                // already says these are on the line tonight.
                Text(next.uppercased())
                    .font(GaryFonts.mono(10.5, bold: true)).tracking(0.4)
                    .foregroundStyle(GaryColors.gold.opacity(0.9))
                    .lineLimit(1).minimumScaleFactor(0.75)
                if game != nil {
                    Image(systemName: "chevron.right")
                        .font(.system(size: 9, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.3))
                }
            }
        }
        .padding(.horizontal, 14).padding(.vertical, 11)
        return SwiftUI.Group {
            if let game {
                Button { onTapGame(game) } label: { row.contentShape(Rectangle()) }
                    .buttonStyle(.plain)
            } else {
                row
            }
        }
    }
}

/// Deep-link target from Home's Edges rows into the Hub: the tapped lane
/// lands here; PropsHubView consumes it whenever the tab becomes visible
/// (same idiom as PicksFocusState for the Picks tab). @Published so a tap
/// AFTER the Hub's first load still lands — tabs are kept alive, so a
/// load-time-only consume would go dead for the rest of the session.
final class HubFocusState: ObservableObject {
    static let shared = HubFocusState()
    @Published var focusLane: SignalKind? = nil
}

struct PropsHubView: View {
    /// Whether the Hub tab is frontmost. ContentView keeps tab pages alive
    /// (opacity-switched, never recreated), so onAppear/.task fire once per
    /// process — visibility flips drive the staleness refetch and deep-link
    /// consumption instead.
    var isVisible: Bool = true
    var onSelectGame: (String) -> Void = { _ in }

    @StateObject private var focus = HubFocusState.shared
    @Environment(\.scenePhase) private var scenePhase

    @State private var sel: HubLeagueSel = .mlb
    @State private var selectedSignal: Signal? = nil
    /// Player whose full breakdown sheet is open (card-back CTA / board row).
    @State private var breakdownSignal: Signal? = nil
    /// Tapped WC match → opens the full WC game-intel dashboard (Starting XI etc.).
    @State private var wcIntel: Signal? = nil
    @State private var searchText: String = ""
    @FocusState private var searchFocused: Bool
    /// Selected lane in the PLAYER EDGES tab strip; nil = first non-empty lane.
    @State private var laneTab: SignalKind? = nil
    /// Selected lane in THE CONDITIONS tab strip; nil = first non-empty lane.
    @State private var condTab: SignalKind? = nil

    // Real connections fetched from Supabase (insight_connections), mapped to
    // Signals. Real data only — no mock fallback; empty -> honest empty state.
    @State private var fetched: [Signal] = []
    @State private var didLoad = false
    /// When the page last loaded (30-min staleness gate) and for which EST
    /// date (3am-rollover gate) — checked on tab visibility and foreground.
    @State private var loadedAt: Date? = nil
    @State private var loadedDate: String = ""
    /// A fetch errored AND no edges rendered — show the retry surface, not
    /// the misleading "posts with lineups" copy.
    @State private var fetchErrored = false
    /// Yesterday's graded-edge tally (hit, graded) for the track-record line.
    @State private var hitRate: (hit: Int, graded: Int)? = nil
    /// Yesterday's graded edges — fills the pre-lineup morning void.
    @State private var ydaySignals: [Signal] = []
    /// Live streaks (streaks table) — the full Streaks board.
    @State private var streakRows: [StreakRow] = []
    /// Last night league-wide (night_highlights) — the Night Board.
    @State private var nightRows: [NightHighlightRow] = []
    /// Section anchor a deep link wants on screen — consumed by the
    /// ScrollViewReader once layout settles.
    @State private var pendingScrollAnchor: String? = nil
    /// Digest layout — anchors of the long-tail sections currently expanded.
    /// A deep link springs its target open via consumeFocus().
    @State private var openSections: Set<String> = []

    private var source: [Signal] { fetched }

    private func items(_ k: SignalKind) -> [Signal] { source.filter { $0.league == sel && $0.kind == k } }

    /// Streaks/Last Night are per-league feeds (MLB-only pipelines today) —
    /// scope them to the toggle so MLB bats never show under NBA/WC.
    private var selStreakRows: [StreakRow] {
        streakRows.filter { ($0.league ?? "MLB").uppercased() == sel.label }
    }
    private var selNightRows: [NightHighlightRow] {
        nightRows.filter { ($0.league ?? "MLB").uppercased() == sel.label }
    }

    /// Leagues that actually have rows today — drives the toggle so we never
    /// show a tab that can only render an empty state.
    private var availableLeagues: [HubLeagueSel] {
        // Priority order: the Finals, then the Cup, then the daily slate.
        let present = [HubLeagueSel.nba, .wc, .mlb].filter { lg in source.contains { $0.league == lg } }
        return present.isEmpty ? [.mlb] : present
    }

    /// Fetch today's connections for all leagues so the in-app league toggle
    /// works without a refetch. Maps Connection -> Signal, drops unmappable
    /// rows. Safe to re-run (pull-to-refresh / staleness gate) — the user's
    /// league choice is kept unless it has no rows in the new data.
    private func load() async {
        let date = SupabaseAPI.todayEST()
        var collected: [Signal] = []
        var dropped = 0
        var anyError = false
        for lg in ["MLB", "NBA", "WC"] {
            do {
                let conns = try await SupabaseAPI.fetchInsightConnections(date: date, league: lg)
                let signals = conns.compactMap { $0.toSignal() }
                dropped += conns.count - signals.count
                collected.append(contentsOf: signals)
            } catch {
                anyError = true
                print("[PropsHubView] fetchInsightConnections(\(lg)) error: \(error.localizedDescription)")
            }
        }
        if dropped > 0 {
            // A backend lane rename would otherwise vanish silently.
            print("[PropsHubView] dropped \(dropped) row(s) with unmappable league/category — check SignalKind.from against the pipeline")
        }
        // Graded surfaces (track record, receipts, night board): the graded
        // date flips at 3am ET but grading lands ~6:45am — walk back one day
        // when the morning void has nothing yet (Home's idiom).
        var gradedDate = SupabaseAPI.hubGradedDateEST()
        var rate = await SupabaseAPI.fetchInsightHitRate(date: gradedDate)
        var night = await SupabaseAPI.fetchNightHighlights(date: gradedDate)
        if rate == nil, night.isEmpty, let back = Self.shiftDate(gradedDate, by: -1) {
            gradedDate = back
            rate = await SupabaseAPI.fetchInsightHitRate(date: gradedDate)
            night = await SupabaseAPI.fetchNightHighlights(date: gradedDate)
        }
        let liveStreaks = await SupabaseAPI.fetchStreaks()
        // The morning void → yesterday's GRADED board. Today's edges post with
        // lineups (~afternoon); until then the Hub shows its receipts, not an
        // empty room.
        var yday: [Signal] = []
        if collected.isEmpty {
            for lg in ["MLB", "NBA", "WC"] {
                if let conns = try? await SupabaseAPI.fetchInsightConnections(date: gradedDate, league: lg) {
                    yday.append(contentsOf: conns.compactMap { $0.toSignal() }.filter { $0.result != nil })
                }
            }
        }
        await MainActor.run {
            didLoad = true
            loadedAt = Date()
            loadedDate = date
            fetchErrored = anyError && collected.isEmpty
            hitRate = rate
            streakRows = liveStreaks
            nightRows = night
            ydaySignals = yday
            // Keep last-good data only when the fetch ERRORED. A successful
            // zero-row day (post-3am rollover, edges not posted yet) must
            // clear the board, or yesterday's edges render as tonight's.
            if !collected.isEmpty || !anyError { fetched = collected }
            // Land on the highest-priority league with edges tonight (a
            // Finals night opens on NBA even with a full MLB slate posted) —
            // but never stomp a league the user picked that still has rows.
            if !collected.contains(where: { $0.league == sel }),
               let top = availableLeagues.first(where: { lg in collected.contains { $0.league == lg } }) {
                sel = top
            }
            // A deep link that arrived while we couldn't render is still
            // pending — consume it now that the board exists.
            consumeFocus()
        }
    }

    /// Re-fetch when the data is from a previous EST date (3am rollover),
    /// older than 30 minutes, or the last attempt failed.
    private func reloadIfStale() async {
        guard didLoad else { return }
        let expired = loadedAt.map { Date().timeIntervalSince($0) > 1800 } ?? true
        // If the board is empty, refetch the moment the tab becomes visible. A
        // transient non-2xx at launch makes fetchInsightConnections return [] WITHOUT
        // throwing, so fetchErrored stays false and the old guard never retried —
        // leaving the Hub stuck empty even though today's edges exist. (The morning
        // void isn't empty: it carries yesterday's graded board in ydaySignals.)
        let emptyBoard = fetched.isEmpty && ydaySignals.isEmpty
        if loadedDate != SupabaseAPI.todayEST() || expired || fetchErrored || emptyBoard {
            await load()
        }
    }

    /// Route a deep-linked lane to its on-page home: player lanes select the
    /// Player Edges tab, condition lanes the Conditions tab, everything else
    /// scrolls to its section anchor (missing anchors no-op harmlessly).
    /// Leaves the request pending while the page can't render anchors yet
    /// (first load in flight / errored) — load() re-consumes on completion,
    /// the same contract PicksCarouselView.consumeFocus keeps.
    private func consumeFocus() {
        guard focus.focusLane != nil, didLoad, !fetchErrored else { return }
        guard let lane = focus.focusLane else { return }
        focus.focusLane = nil
        // A stale search hides every anchor — the deep link wins over it.
        searchText = ""
        searchFocused = false
        switch lane {
        case .platoon, .hot, .ballpark, .cold, .starterForm:
            laneTab = lane
            pendingScrollAnchor = "playerEdges"
        case .firstInning, .runningGame, .parkWeather:
            condTab = lane
            pendingScrollAnchor = "conditions"
        case .streak: pendingScrollAnchor = "streaks"
        case .regression: pendingScrollAnchor = "regression"
        case .hrThreat: pendingScrollAnchor = "hrThreats"
        case .h2h: pendingScrollAnchor = "owned"
        case .injury: pendingScrollAnchor = "beneficiary"
        case .situational: pendingScrollAnchor = "restFatigue"
        case .tournament: pendingScrollAnchor = "tournament"
        }
        // Digest: spring the deep-linked section open so its rows are visible
        // the moment we scroll to it.
        if let a = pendingScrollAnchor { openSections.insert(a) }
    }

    private static func shiftDate(_ s: String, by days: Int) -> String? {
        let f = DateFormatter()
        f.dateFormat = "yyyy-MM-dd"
        f.timeZone = TimeZone(identifier: "America/New_York")
        guard let d = f.date(from: s),
              let shifted = Calendar.current.date(byAdding: .day, value: days, to: d) else { return nil }
        return f.string(from: shifted)
    }

    private var leagueSignals: [Signal] { source.filter { $0.league == sel } }
    /// WC matches that carry a confirmed-XI edge — one Game Intel card each.
    private var wcIntelSignals: [Signal] { source.filter { $0.league == .wc && $0.confirmedXI != nil } }
    /// Every fetched WC edge for one matchup — the full set handed to the dashboard.
    private func wcEdges(for game: String) -> [Signal] { source.filter { $0.league == .wc && $0.game == game } }

    /// FEATURED picks the highest-relevance signals but caps each kind at 2 so
    /// the strip mixes lanes instead of showing six near-identical cards.
    private var featured: [Signal] {
        var counts: [SignalKind: Int] = [:]
        var out: [Signal] = []
        for s in leagueSignals {           // already relevance-ordered by the fetch
            if s.reg?.day == "tomorrow" { continue }   // look-ahead never headlines "tonight"
            let c = counts[s.kind] ?? 0
            guard c < 2 else { continue }
            counts[s.kind] = c + 1
            out.append(s)
            if out.count == 6 { break }
        }
        return out
    }

    var body: some View {
        GeometryReader { geo in
        ScrollViewReader { proxy in
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 22) {
                header
                searchBar.padding(.horizontal, 16)

                if !didLoad {
                    hubLoadingState
                } else if !searchText.isEmpty {
                    searchResults
                } else if fetchErrored && leagueSignals.isEmpty && ydaySignals.isEmpty
                            && nightRows.isEmpty && streakRows.isEmpty {
                    hubErrorState
                } else if leagueSignals.isEmpty {
                    // The morning Hub leads with what's LIVE — streaks, then
                    // last night's board; yesterday's graded receipts close
                    // the page. Today's edges fill in as the day's runs land.
                    hubEmptyState
                    if !selStreakRows.isEmpty {
                        HubSectionTitle(title: "Streaks").padding(.horizontal, 16)
                            .id("streaks")
                        StreakBoard(rows: selStreakRows, onTapGame: { onSelectGame($0) })
                            .padding(.horizontal, 16)
                    }
                    if !selNightRows.isEmpty {
                        HubSectionTitle(title: "Last Night").padding(.horizontal, 16)
                        NightBoard(rows: selNightRows).padding(.horizontal, 16)
                    }
                    gradedReceipts
                } else {
                    // FEATURED — highest relevance, max 2 per lane so the strip mixes kinds
                    HubSectionTitle(title: "Featured").padding(.horizontal, 16)
                    EdgeFeatureStrip(signals: featured) { breakdownSignal = $0 }

                    // REGRESSION BOARD — a ranked leaderboard with ERA→xERA gap bars
                    if !items(.regression).isEmpty {
                        HubSectionTitle(title: "Regression Board").padding(.horizontal, 16)
                            .id("regression")
                        RegressionBoard(signals: items(.regression)) { s in
                            if s.playerId != nil { breakdownSignal = s } else { selectedSignal = s }
                        }
                    }
                    // GARY HOME RUN THREATS — Gary's homer picks for today, with
                    // his two-sentence reason. Fed by gary_hr_threats.
                    if !items(.hrThreat).isEmpty {
                        HubDisclosure(anchor: "hrThreats", eyebrow: "Gary Home Run Threats", count: items(.hrThreat).count, openSet: $openSections) {
                            VStack(spacing: 0) {
                                ForEach(items(.hrThreat)) { s in
                                    SignalRow(s: s) { _ in
                                        if s.playerId != nil { breakdownSignal = s } else { selectedSignal = s }
                                    }
                                }
                            }
                            .quantPanel().padding(.horizontal, 16)
                        }
                        .id("hrThreats")
                    }
                    // PLAYER EDGES — lane tabs (platoon / heat / ballpark / cooling / starters).
                    if !playerEdgeLanes.isEmpty {
                        HubDisclosure(anchor: "playerEdges", eyebrow: "Player Edges", count: playerEdgeLanes.reduce(0) { $0 + items($1).count }, openSet: $openSections) {
                            VStack(alignment: .leading, spacing: 8) {
                                hubLaneStrip(lanes: playerEdgeLanes, active: activeLane, title: laneTitle) { laneTab = $0 }
                                EdgeScroller(signals: items(activeLane)) { breakdownSignal = $0 }
                            }
                        }
                        .id("playerEdges")
                    }
                    // OWNED — career batter-vs-pitcher history (NBA: season series)
                    if !items(.h2h).isEmpty {
                        HubDisclosure(anchor: "owned", eyebrow: "Owned", count: items(.h2h).count, openSet: $openSections) {
                            VStack(spacing: 0) {
                                ForEach(items(.h2h)) { s in
                                    SignalRow(s: s) { _ in
                                        if s.playerId != nil { breakdownSignal = s } else { selectedSignal = s }
                                    }
                                }
                            }
                            .quantPanel().padding(.horizontal, 16)
                        }
                        .id("owned")
                    }
                    // THE BENEFICIARY — transaction-style OUT → IN swap rows;
                    // tapping a row opens the replacement's full player insights.
                    if !items(.injury).isEmpty {
                        HubDisclosure(anchor: "beneficiary", eyebrow: "The Beneficiary", count: items(.injury).count, openSet: $openSections) {
                            VStack(spacing: 0) {
                                ForEach(items(.injury)) { s in
                                    if s.swap != nil {
                                        BeneficiarySwapRow(s: s) {
                                            if s.playerId != nil { breakdownSignal = s } else { selectedSignal = s }
                                        }
                                    } else {
                                        SignalRow(s: s) { _ in selectedSignal = s }
                                    }
                                }
                            }
                            .quantPanel().padding(.horizontal, 16)
                        }
                        .id("beneficiary")
                    }
                    // WC GAME INTEL — tap a match → the Starting XI / The Read
                    // dashboard (WC league toggle only).
                    if sel == .wc, !wcIntelSignals.isEmpty {
                        HubDisclosure(anchor: "wcIntel", eyebrow: "Game Intel", count: wcIntelSignals.count, openSet: $openSections) {
                            VStack(spacing: 0) { ForEach(wcIntelSignals) { s in SignalRow(s: s) { _ in wcIntel = s } } }
                                .quantPanel().padding(.horizontal, 16)
                        }
                        .id("wcIntel")
                    }
                    // REST & FATIGUE — schedule spots and bullpen workload
                    if !items(.situational).isEmpty {
                        HubDisclosure(anchor: "restFatigue", eyebrow: "Rest & Fatigue", count: items(.situational).count, openSet: $openSections) {
                            VStack(spacing: 0) { ForEach(items(.situational)) { s in SignalRow(s: s) { _ in selectedSignal = s } } }
                                .quantPanel().padding(.horizontal, 16)
                        }
                        .id("restFatigue")
                    }
                    // THE CONDITIONS — game-state reads, one tabbed section
                    // (first inning / the running game / park & weather).
                    if !conditionLanes.isEmpty {
                        HubDisclosure(anchor: "conditions", eyebrow: "The Conditions", count: conditionLanes.reduce(0) { $0 + items($1).count }, openSet: $openSections) {
                            VStack(spacing: 0) {
                                hubLaneStrip(lanes: conditionLanes, active: activeCondLane, title: condTitle) { condTab = $0 }
                                Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1)
                                ForEach(items(activeCondLane)) { s in SignalRow(s: s) { _ in selectedSignal = s } }
                            }
                            .quantPanel().padding(.horizontal, 16)
                        }
                        .id("conditions")
                    }
                    // STREAKS — the full board: teams on runs, hot and cold bats,
                    // and which streaks are on the line tonight (league-scoped).
                    if !selStreakRows.isEmpty {
                        HubDisclosure(anchor: "streaks", eyebrow: "Streaks", count: selStreakRows.count, openSet: $openSections) {
                            StreakBoard(rows: selStreakRows, onTapGame: { onSelectGame($0) })
                                .padding(.horizontal, 16)
                        }
                        .id("streaks")
                    } else if !items(.streak).isEmpty {
                        HubDisclosure(anchor: "streaks", eyebrow: "Streaks", count: items(.streak).count, openSet: $openSections) {
                            VStack(spacing: 0) { ForEach(items(.streak)) { s in SignalRow(s: s) { _ in selectedSignal = s } } }
                                .quantPanel().padding(.horizontal, 16)
                        }
                        .id("streaks")
                    }
                    // LAST NIGHT — the league-wide board.
                    if !selNightRows.isEmpty {
                        HubDisclosure(anchor: "lastNight", eyebrow: "Last Night", count: selNightRows.count, openSet: $openSections) {
                            NightBoard(rows: selNightRows).padding(.horizontal, 16)
                        }
                        .id("lastNight")
                    }
                    // TOURNAMENT STAKES — group standings, title odds, market context (World Cup)
                    if !items(.tournament).isEmpty {
                        HubDisclosure(anchor: "tournament", eyebrow: "Tournament Stakes", count: items(.tournament).count, openSet: $openSections) {
                            VStack(spacing: 0) { ForEach(items(.tournament)) { s in SignalRow(s: s) { _ in selectedSignal = s } } }
                                .quantPanel().padding(.horizontal, 16)
                        }
                        .id("tournament")
                    }
                    // Anything else → a compact list
                    let extras = leagueSignals.filter { ![.regression, .platoon, .ballpark, .hot, .cold, .h2h, .injury, .situational, .streak, .tournament, .hrThreat, .starterForm, .firstInning, .runningGame, .parkWeather].contains($0.kind) }
                    if !extras.isEmpty {
                        HubDisclosure(anchor: "moreEdges", eyebrow: "More Edges", count: extras.count, openSet: $openSections) {
                            VStack(spacing: 0) { ForEach(extras) { s in SignalRow(s: s) { _ in selectedSignal = s } } }
                                .quantPanel().padding(.horizontal, 16)
                        }
                        .id("moreEdges")
                    }
                }
            }
            .padding(.top, 8)
            .padding(.bottom, 120)
            // Floor the content at the viewport height so an empty/under-filled Hub can't be
            // rubber-banded around freely (the "whole page drags off the tracks" bug).
            .frame(minHeight: geo.size.height, alignment: .top)
            .task { if !didLoad { await load() } }   // load() consumes any pending deep link
        }
        // Let the search keyboard collapse: drag the list, return key, or clear.
        .scrollDismissesKeyboard(.immediately)
        .refreshable { await load() }
        // Kept-alive tabs never re-run .task — visibility flips and app
        // foregrounding drive deep-link consumption + the staleness refetch.
        .onChange(of: isVisible) { vis in
            guard vis else { return }
            consumeFocus()
            Task { await reloadIfStale() }
        }
        .onChange(of: scenePhase) { phase in
            guard phase == .active, isVisible else { return }
            Task { await reloadIfStale() }
        }
        .sheet(item: $selectedSignal) { EdgeDetailSheet(signal: $0, onSelectGame: onSelectGame) }
        .sheet(item: $breakdownSignal) { PlayerInsightSheet(signal: $0) }
        .fullScreenCover(item: $wcIntel) { s in
            ZStack(alignment: .top) {
                GaryColors.darkBg.ignoresSafeArea()
                ScrollView(showsIndicators: false) {
                    WCGameIntelView(matchup: s.game,
                                    confirmedXI: s.confirmedXI,
                                    read: s,
                                    edges: wcEdges(for: s.game),
                                    onClose: { wcIntel = nil })
                }
            }
        }
        .onChange(of: pendingScrollAnchor) { anchor in
            guard let anchor else { return }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.25) {
                withAnimation(.easeInOut(duration: 0.35)) { proxy.scrollTo(anchor, anchor: .top) }
                pendingScrollAnchor = nil
            }
        }
        }
        }
    }

    // ---- Player-edge lane tabs (platoon / heat / ballpark / cooling / starters) ----

    /// The five player-stat lanes, filtered to lanes that have rows tonight.
    private var playerEdgeLanes: [SignalKind] {
        // Ballpark ("a different pitcher in this park") is an MLB-only concept — never
        // surface it for other leagues (it was showing, unreadable, under WC).
        let base: [SignalKind] = sel == .mlb
            ? [.platoon, .hot, .ballpark, .cold, .starterForm]
            : [.platoon, .hot, .cold, .starterForm]
        return base.filter { !items($0).isEmpty }
    }
    /// The lane the tab strip is showing: the user's choice when still valid,
    /// else the first lane with content.
    private var activeLane: SignalKind {
        if let t = laneTab, playerEdgeLanes.contains(t) { return t }
        return playerEdgeLanes.first ?? .platoon
    }
    private func laneTitle(_ k: SignalKind) -> String {
        switch k {
        case .platoon: return "PLATOON"
        case .hot: return "HEAT CHECK"
        case .ballpark: return "BALLPARK"
        case .cold: return "COOLING"
        case .starterForm: return "STARTERS"
        default: return k.chip
        }
    }
    private func laneSub(_ k: SignalKind) -> String {
        switch k {
        case .platoon: return "Handedness matchups tonight"
        case .hot: return "Hot bats the line hasn't caught"
        case .ballpark: return "A different pitcher in this park"
        case .cold: return "Slumps the line may not reflect"
        case .starterForm: return "Last three starts vs the season"
        default: return ""
        }
    }

    // ---- Conditions lane tabs (first inning / running game / park & weather) ----

    /// The game-condition lanes, filtered to lanes that have rows tonight.
    private var conditionLanes: [SignalKind] {
        [SignalKind.firstInning, .runningGame, .parkWeather].filter { !items($0).isEmpty }
    }
    private var activeCondLane: SignalKind {
        if let t = condTab, conditionLanes.contains(t) { return t }
        return conditionLanes.first ?? .firstInning
    }
    private func condTitle(_ k: SignalKind) -> String {
        switch k {
        case .firstInning: return "FIRST INNING"
        case .runningGame: return "RUN GAME"
        case .parkWeather: return "PARK & WEATHER"
        default: return k.chip
        }
    }
    private func condSub(_ k: SignalKind) -> String {
        switch k {
        case .firstInning: return "NRFI & YRFI reads on tonight's slate"
        case .runningGame: return "Catcher arms vs teams that run"
        case .parkWeather: return "Wind, heat, and the total"
        default: return ""
        }
    }

    /// Shared lane-tab strip (Player Edges + The Conditions): plain mono text
    /// tabs — active wears gold, the rest dim. The app-wide colored-when-active
    /// rule (the Slate's tabStrip grammar); the capsule boxes retired Jun 11.
    private func hubLaneStrip(lanes: [SignalKind], active: SignalKind,
                              title: @escaping (SignalKind) -> String,
                              onSelect: @escaping (SignalKind) -> Void) -> some View {
        ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 18) {
                ForEach(lanes, id: \.self) { lane in
                    let on = lane == active
                    Button { withAnimation(.easeInOut(duration: 0.15)) { onSelect(lane) } } label: {
                        Text(title(lane))
                            .font(GaryFonts.mono(10.5, bold: true)).tracking(0.8)
                            .foregroundStyle(on ? GaryColors.gold : .white.opacity(0.4))
                            .frame(minHeight: 32)
                            .contentShape(Rectangle())
                    }.buttonStyle(.plain)
                }
                Spacer(minLength: 0)
            }
            .padding(.horizontal, 14)
        }
    }

    // ---- Search ----

    private var searchBar: some View {
        HStack(spacing: 8) {
            Image(systemName: "magnifyingglass")
                .font(.system(size: 12, weight: .semibold))
                .foregroundStyle(.white.opacity(0.35))
            TextField("Search players, teams, edges", text: $searchText)
                .font(GaryFonts.mono(12.5))
                .foregroundStyle(.white)
                .autocorrectionDisabled()
                .textInputAutocapitalization(.never)
                .focused($searchFocused)
                .submitLabel(.search)
                .onSubmit { searchFocused = false }
            if !searchText.isEmpty {
                Button { searchText = ""; searchFocused = false } label: {
                    Image(systemName: "xmark.circle.fill")
                        .font(.system(size: 14)).foregroundStyle(.white.opacity(0.3))
                }.buttonStyle(.plain)
            }
        }
        .padding(.horizontal, 12).padding(.vertical, 9)
        .background(
            RoundedRectangle(cornerRadius: 11, style: .continuous)
                .fill(GaryColors.fieldBg)
                .overlay(RoundedRectangle(cornerRadius: 11, style: .continuous).stroke(GaryColors.warmWhite.opacity(0.07), lineWidth: 1))
        )
    }

    /// One search for everything the page shows: tonight's edges (every
    /// league), the graded receipts, live streaks, and last night's board.
    private var searchResults: some View {
        let q = searchText.lowercased()
        func hits(_ s: Signal) -> Bool {
            s.headline.lowercased().contains(q)
                || s.detail.lowercased().contains(q)
                || s.game.lowercased().contains(q)
                || s.value.lowercased().contains(q)
                || s.kind.chip.lowercased().contains(q)
        }
        let edgeMatches = source.filter(hits)
        let receiptMatches = ydaySignals.filter(hits)
        let streakMatches = streakRows.filter {
            ($0.subject ?? "").lowercased().contains(q)
                || ($0.team ?? "").lowercased().contains(q)
                || ($0.detail ?? "").lowercased().contains(q)
        }
        let nightMatches = nightRows.filter {
            ($0.player_name ?? "").lowercased().contains(q)
                || ($0.team ?? "").lowercased().contains(q)
        }
        let total = edgeMatches.count + receiptMatches.count + streakMatches.count + nightMatches.count
        return Group {
            if total == 0 {
                VStack(spacing: 8) {
                    Text("NO MATCHES")
                        .font(GaryFonts.mono(11, bold: true)).tracking(1)
                        .foregroundStyle(.white.opacity(0.5))
                    Text("Try a player, a team, or a lane like \"platoon\".")
                        .font(.system(size: 12)).foregroundStyle(.white.opacity(0.35))
                }
                .frame(maxWidth: .infinity).padding(.top, 36)
            } else {
                if !edgeMatches.isEmpty {
                    HubSectionTitle(title: "Edges").padding(.horizontal, 16)
                    VStack(spacing: 0) { ForEach(edgeMatches) { s in SignalRow(s: s) { _ in selectedSignal = s } } }
                        .quantPanel().padding(.horizontal, 16)
                }
                if !receiptMatches.isEmpty {
                    HubSectionTitle(title: "Receipts").padding(.horizontal, 16)
                    VStack(spacing: 0) { ForEach(receiptMatches) { s in SignalRow(s: s) { _ in selectedSignal = s } } }
                        .quantPanel().padding(.horizontal, 16)
                }
                if !streakMatches.isEmpty {
                    HubSectionTitle(title: "Streaks").padding(.horizontal, 16)
                    VStack(spacing: 0) {
                        ForEach(Array(streakMatches.enumerated()), id: \.offset) { i, r in
                            searchAuxRow(title: r.subject ?? "", sub: r.detail ?? "", trail: r.next_game ?? "",
                                         divider: i < streakMatches.count - 1)
                        }
                    }
                    .quantPanel().padding(.horizontal, 16)
                }
                if !nightMatches.isEmpty {
                    HubSectionTitle(title: "Last Night").padding(.horizontal, 16)
                    VStack(spacing: 0) {
                        ForEach(Array(nightMatches.enumerated()), id: \.offset) { i, r in
                            searchAuxRow(title: r.player_name ?? "", sub: r.detail ?? "", trail: r.team ?? "",
                                         divider: i < nightMatches.count - 1)
                        }
                    }
                    .quantPanel().padding(.horizontal, 16)
                }
            }
        }
    }

    /// Compact read-only row for streak/night-board search matches.
    private func searchAuxRow(title: String, sub: String, trail: String, divider: Bool) -> some View {
        VStack(spacing: 0) {
            HStack(spacing: 10) {
                VStack(alignment: .leading, spacing: 2) {
                    Text(title).font(.system(size: 13.5, weight: .semibold)).foregroundStyle(.white).lineLimit(1)
                    if !sub.isEmpty {
                        Text(sub).font(.system(size: 11)).foregroundStyle(.white.opacity(0.6)).lineLimit(1)
                    }
                }
                Spacer(minLength: 8)
                if !trail.isEmpty {
                    Text(trail.uppercased())
                        .font(GaryFonts.mono(9.5, bold: false)).tracking(0.4)
                        .foregroundStyle(.white.opacity(0.45)).lineLimit(1)
                }
            }
            .padding(.horizontal, 14).padding(.vertical, 10)
            if divider {
                Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
            }
        }
    }

    /// First-load spinner — without it the page flashes a false "no edges
    /// yet" while the fetch is still in flight.
    private var hubLoadingState: some View {
        VStack(spacing: 12) {
            ProgressView().tint(GaryColors.gold)
            Text("PULLING TONIGHT'S BOARD")
                .font(GaryFonts.mono(10, bold: true)).tracking(1.2)
                .foregroundStyle(.white.opacity(0.35))
        }
        .frame(maxWidth: .infinity).padding(.top, 110)
    }

    /// Fetch failed AND nothing rendered — honest copy, distinct from the
    /// pre-lineup quiet morning, with a retry path.
    private var hubErrorState: some View {
        VStack(spacing: 10) {
            Image(systemName: "wifi.exclamationmark")
                .font(.system(size: 30, weight: .light))
                .foregroundStyle(GaryColors.gold.opacity(0.6))
            Text("COULDN'T LOAD THE HUB")
                .font(GaryFonts.mono(11, bold: true)).tracking(1)
                .foregroundStyle(.white.opacity(0.55))
            Text("Check your connection, then pull down to retry.")
                .font(.system(size: 12)).foregroundStyle(.white.opacity(0.4))
                .multilineTextAlignment(.center).padding(.horizontal, 40)
            Button { Task { await load() } } label: {
                Text("RETRY")
                    .font(GaryFonts.mono(11, bold: true)).tracking(1)
                    .foregroundStyle(.black.opacity(0.85))
                    .padding(.horizontal, 22).padding(.vertical, 9)
                    .background(Capsule().fill(GaryColors.gold))
            }
            .buttonStyle(.plain)
            .padding(.top, 6)
        }
        .frame(maxWidth: .infinity).padding(.top, 90)
    }

    private var hubEmptyState: some View {
        VStack(spacing: 8) {
            Text("NO \(sel.label.uppercased()) EDGES YET")
                .font(GaryFonts.mono(11, bold: true)).tracking(1)
                .foregroundStyle(.white.opacity(0.55))
            Text("Tonight's connections post as lineups and matchups firm up.")
                .font(.system(size: 12)).foregroundStyle(.white.opacity(0.55))
                .multilineTextAlignment(.center).padding(.horizontal, 40)
        }
        .frame(maxWidth: .infinity).padding(.top, 20).padding(.bottom, 6)
    }

    /// Yesterday's graded board — the Hub's receipts, closing the morning
    /// page. Rows open the full edge with its verdict + grader's note.
    @ViewBuilder private var gradedReceipts: some View {
        if !ydaySignals.isEmpty {
            // The tally comes from the remote aggregate; on a transient
            // miss we derive it from the same rows we're about to render —
            // the real stat beats a slogan either way.
            HubSectionHeader(
                eyebrow: "Yesterday · graded",
                sub: {
                    let (hit, graded) = hitRate
                        ?? (ydaySignals.filter { $0.result == "hit" }.count, ydaySignals.count)
                    guard graded > 0 else { return "" }
                    let pct = Int((Double(hit) / Double(graded) * 100).rounded())
                    return "\(hit) of \(graded) hit · \(pct)%"
                }())
            VStack(spacing: 0) {
                ForEach(Array(ydaySignals.prefix(12).enumerated()), id: \.element.id) { i, s in
                    Button { selectedSignal = s } label: {
                        HStack(spacing: 10) {
                            Text(s.kind.chip)
                                .font(GaryFonts.mono(8.5, bold: true)).tracking(0.8)
                                .foregroundStyle(GaryColors.gold.opacity(0.75))
                                .frame(width: 86, alignment: .leading)
                            VStack(alignment: .leading, spacing: 3) {
                                Text(s.headline)
                                    .font(.system(size: 13))
                                    .foregroundStyle(.white.opacity(0.85))
                                    .lineLimit(2)
                                    .multilineTextAlignment(.leading)
                                if let note = s.resultNote, !note.isEmpty {
                                    Text(note)
                                        .font(GaryFonts.mono(11, bold: false))
                                        .foregroundStyle(.white.opacity(0.62))
                                        .lineLimit(1).minimumScaleFactor(0.85)
                                }
                            }
                            Spacer(minLength: 8)
                            Text(s.result == "hit" ? "HIT" : s.result == "push" ? "PUSH" : "MISS")
                                .font(GaryFonts.mono(10, bold: true)).tracking(0.6)
                                .foregroundStyle(s.result == "hit" ? GaryColors.win
                                                 : s.result == "push" ? GaryColors.gold
                                                 : GaryColors.loss)
                            Image(systemName: "chevron.right")
                                .font(.system(size: 9, weight: .semibold))
                                .foregroundStyle(.white.opacity(0.25))
                        }
                        .padding(.horizontal, 14).padding(.vertical, 10)
                        .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    if i < min(ydaySignals.count, 12) - 1 {
                        Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 14)
                    }
                }
            }
            .quantPanel()
            .padding(.horizontal, 16)
        }
    }

    private var header: some View {
        GaryPageHeader(
            title: "The Hub",
            // Track record once graded (>=5 edges), else today's date.
            accent: {
                if let r = hitRate, r.graded >= 5 { return "\(r.hit) OF \(r.graded) HIT YDAY" }
                return GaryPageHeader<EmptyView>.dateLabel()
            }()
        ) {
            // Only leagues with rows today — no toggle into a guaranteed empty state.
            if availableLeagues.count > 1 {
                HStack(spacing: 6) {
                    ForEach(availableLeagues, id: \.self) { l in
                        let on = l == sel
                        Button { withAnimation(.easeInOut(duration: 0.2)) { sel = l } } label: {
                            Text(l.label)
                                .font(GaryFonts.mono(10.5, bold: on)).tracking(0.8)
                                // Pin to one line at intrinsic width so a long date
                                // accent can't squeeze "NBA" into stacked letters
                                // (the broken-pill bug, Jun 13 2026).
                                .lineLimit(1)
                                .fixedSize()
                                .foregroundStyle(on ? GaryColors.selectedText : Color.white.opacity(0.5))
                                .padding(.horizontal, 11).padding(.vertical, 5)
                                .background(
                                    Capsule().fill(on ? GaryColors.selectedFill : Color.white.opacity(0.05))
                                        .overlay(Capsule().stroke(on ? Color.white.opacity(0.25) : Color.white.opacity(0.08), lineWidth: 1))
                                )
                        }.buttonStyle(.plain)
                    }
                }
                .fixedSize(horizontal: true, vertical: false)
            }
        }
    }
}

