/// Slide-out detail for a tapped edge.
struct EdgeDetailSheet: View {
    let signal: Signal
    let onSelectGame: (String) -> Void
    @Environment(\.dismiss) private var dismiss
    /// Board-level rows (WC title odds: "TO LIFT THE CUP") aren't a matchup —
    /// VIEW GAME would land nowhere, so it only shows for real games.
    private var isMatchup: Bool {
        let g = signal.game.lowercased()
        return g.contains("@") || g.contains(" vs ") || g.contains(" v ")
    }
    var body: some View {
        ScrollView {
            VStack(alignment: .leading, spacing: 16) {
                HStack {
                    HStack(spacing: 6) {
                        Image(systemName: signal.kind.icon).font(.system(size: 10, weight: .bold)).foregroundStyle(signal.kind.tint)
                        Text(signal.kind.chip).font(GaryFonts.mono(10, bold: true)).tracking(1.2).foregroundStyle(signal.kind.tint)
                    }
                    Spacer()
                    // Graded edge (receipts path): the verdict, stamped.
                    if let r = signal.result {
                        Text(r.uppercased())
                            .font(GaryFonts.mono(10, bold: true)).tracking(1)
                            .foregroundStyle(r == "hit" ? GaryColors.win : r == "push" ? GaryColors.gold : GaryColors.loss)
                            .padding(.trailing, 6)
                    }
                    Button { dismiss() } label: {
                        Image(systemName: "xmark.circle.fill").font(.system(size: 24)).foregroundStyle(.white.opacity(0.3))
                    }.buttonStyle(.plain)
                }
                Text(signal.game.uppercased()).font(GaryFonts.mono(11, bold: false)).foregroundStyle(.white.opacity(0.55))
                Text(signal.headline).font(GaryFonts.display(25)).foregroundStyle(.white).fixedSize(horizontal: false, vertical: true)
                if !signal.value.isEmpty || !signal.spark.isEmpty {
                    HStack(alignment: .bottom, spacing: 16) {
                        if !signal.value.isEmpty {
                            Text(signal.value).font(GaryFonts.mono(34, bold: true)).foregroundStyle(signal.tone.color)
                        }
                        if !signal.spark.isEmpty { MiniBarChart(values: signal.spark, line: signal.lineVal, tint: signal.kind.tint, height: 40) }
                    }
                }
                if !signal.detail.isEmpty {
                    Text(signal.detail).font(.system(size: 15)).foregroundStyle(.white.opacity(0.75)).lineSpacing(3).fixedSize(horizontal: false, vertical: true)
                }
                if let note = signal.resultNote, !note.isEmpty {
                    Text(note)
                        .font(GaryFonts.mono(11, bold: false))
                        .foregroundStyle(.white.opacity(0.65))
                }
                if isMatchup {
                    Button { dismiss(); onSelectGame(signal.game) } label: {
                        HStack(spacing: 6) { Text("VIEW GAME"); Image(systemName: "arrow.right") }
                            .font(GaryFonts.mono(12, bold: true))
                            .foregroundStyle(.black.opacity(0.85))
                            .frame(maxWidth: .infinity).padding(.vertical, 12)
                            .background(Capsule().fill(GaryColors.gold))
                    }.buttonStyle(.plain).padding(.top, 6)
                }
                Spacer()
            }
            .padding(20)
        }
        .background(GaryColors.darkBg.ignoresSafeArea())
        .presentationDetents([.medium, .large])
        .presentationDragIndicator(.visible)
    }
}

// MARK: - Player Insights (full breakdown behind a hub card)
//
// Fetches the pre-computed player_insight_cards pack for the tapped player and
// renders the betting breakdown: strengths/weaknesses, the pitch-type matchup
// vs tonight's starter, splits, BvP, Statcast truth-check, and tonight's lines.

struct PlayerInsightSheet: View {
    /// Hub path: a tapped Signal — the pack is fetched by player id.
    let signal: Signal?
    /// Game-page path (PLAYER INTEL): the pack already came down with the row.
    var prefetched: PlayerInsightCardRow? = nil
    @Environment(\.dismiss) private var dismiss
    @State private var pack: PlayerInsightPack? = nil
    @State private var loading = true

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(alignment: .leading, spacing: 20) {
                headerView
                if loading {
                    ProgressView().tint(GaryColors.gold)
                        .frame(maxWidth: .infinity).padding(.top, 60)
                } else if let p = pack {
                    packView(p)
                } else {
                    fallbackView
                }
            }
            .padding(20)
            .padding(.bottom, 30)
        }
        .background(GaryColors.darkBg.ignoresSafeArea())
        .presentationDetents([.large])
        .presentationDragIndicator(.visible)
        .task {
            if let row = prefetched {
                pack = row.payload
            } else if let pid = signal?.playerId {
                pack = await SupabaseAPI.fetchPlayerInsightCard(date: SupabaseAPI.todayEST(), playerId: pid)
            }
            loading = false
        }
    }

    private var headerView: some View {
        HStack(alignment: .top) {
            VStack(alignment: .leading, spacing: 3) {
                Text("Player Breakdown")
                    .font(.system(size: 11, weight: .semibold))
                    .foregroundStyle(GaryColors.sectionSub)
                Text(pack?.name ?? fallbackName)
                    .font(GaryFonts.text(27, .bold)).foregroundStyle(.white)
                HStack(spacing: 6) {
                    if let meta = identityLine {
                        Text(meta).font(GaryFonts.mono(11, bold: false))
                            .foregroundStyle(.white.opacity(0.45))
                    }
                }
            }
            Spacer()
            Button { dismiss() } label: {
                Image(systemName: "xmark.circle.fill").font(.system(size: 24)).foregroundStyle(.white.opacity(0.3))
            }.buttonStyle(.plain)
        }
        .padding(.top, 22)
    }

    private var fallbackName: String {
        if let n = prefetched?.player_name, !n.isEmpty { return n }
        guard let signal else { return "Player" }
        return (signal.headline.components(separatedBy: CharacterSet(charactersIn: "(:'")).first ?? signal.headline)
            .trimmingCharacters(in: .whitespaces)
    }

    private var identityLine: String? {
        guard let p = pack else { return signal?.game.uppercased() }
        var bits: [String] = []
        if let t = p.team { bits.append(t.uppercased()) }
        if let pos = p.position { bits.append(pos) }
        if let h = p.hand { bits.append(p.type == "pitcher" ? "throws \(h)" : "bats \(h)") }
        if let g = p.game { bits.append(g.uppercased()) }
        return bits.isEmpty ? nil : bits.joined(separator: " · ")
    }

    private var fallbackView: some View {
        VStack(alignment: .leading, spacing: 12) {
            if let signal {
                Text(signal.detail)
                    .font(.system(size: 15)).foregroundStyle(.white.opacity(0.75)).lineSpacing(3)
                    .fixedSize(horizontal: false, vertical: true)
            }
            Text("The full breakdown for this player isn't available yet — it posts with the day's edge refresh.")
                .font(.system(size: 12)).foregroundStyle(.white.opacity(0.4))
        }
    }

    /// THE EDGE — leads the profile with the exact connection that surfaced this
    /// player tonight (the lane's verdict / read), so a bettor sees the angle
    /// before the raw tables. Only on the Hub path (a triggering signal exists).
    @ViewBuilder
    private var edgeHero: some View {
        if let s = signal {
            let edge = (s.reg?.verdict ?? s.detail).trimmingCharacters(in: .whitespaces)
            VStack(alignment: .leading, spacing: 7) {
                Text(s.kind.chip).font(GaryFonts.mono(9, bold: true)).tracking(1).foregroundStyle(GaryColors.gold)
                Text(s.headline).font(.system(size: 17, weight: .bold)).foregroundStyle(.white)
                    .fixedSize(horizontal: false, vertical: true)
                if !edge.isEmpty {
                    Text(edge).font(.system(size: 13)).foregroundStyle(.white.opacity(0.82)).lineSpacing(2)
                        .fixedSize(horizontal: false, vertical: true)
                }
            }
            .padding(14)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(
                RoundedRectangle(cornerRadius: 14, style: .continuous)
                    .fill(GaryColors.gold.opacity(0.07))
                    .overlay(RoundedRectangle(cornerRadius: 14, style: .continuous).stroke(GaryColors.gold.opacity(0.3), lineWidth: 1))
            )
        }
    }

    @ViewBuilder
    private func packView(_ p: PlayerInsightPack) -> some View {
        // THE EDGE — why this player surfaced tonight (the connection, up front).
        edgeHero
        // Tonight's opponent context
        if let opp = p.opponent, let oppName = opp.name {
            insightEyebrow("TONIGHT")
            Text(p.type == "pitcher" ? "Faces \(oppName)" : "Faces \(oppName)\(opp.hand.map { " (\($0)HP)" } ?? "")")
                .font(.system(size: 15, weight: .semibold)).foregroundStyle(.white.opacity(0.9))
        }

        // Strengths / weaknesses
        if let s = p.strengths, !s.isEmpty {
            insightEyebrow("STRENGTHS")
            bulletList(s, color: HubPalette.green)
        }
        if let w = p.weaknesses, !w.isEmpty {
            insightEyebrow("WEAKNESSES")
            bulletList(w, color: HubPalette.red)
        }

        // Pitch-type matchup vs tonight's starter (the centerpiece)
        if let rows = p.pitchMatchup, !rows.isEmpty {
            insightEyebrow(p.type == "pitcher" ? "ARSENAL" : "VS TONIGHT'S ARSENAL")
            pitchTable(rows, isPitcher: p.type == "pitcher")
        }

        // Splits + form + BvP + venue
        if let splits = p.splits, !splits.isEmpty {
            insightEyebrow("SPLITS")
            VStack(spacing: 0) { ForEach(Array(splits.enumerated()), id: \.offset) { _, row in labeledRow(row) } }
                .quantPanel()
        }
        if let ladder = p.formRows, !ladder.isEmpty {
            // The ladder a bettor builds by hand from three game logs:
            // last game → L5 → L10, with the 15-day window closing it out.
            insightEyebrow("RECENT FORM")
            VStack(spacing: 0) {
                ForEach(Array(ladder.enumerated()), id: \.offset) { _, row in labeledRow(row) }
                if let form = p.form { labeledRow(form) }
            }
            .quantPanel()
        } else if let form = p.form {
            insightEyebrow(form.label ?? "RECENT FORM")
            VStack(spacing: 0) { labeledRow(form, hideLabel: true) }.quantPanel()
        }
        if let bvp = p.bvp {
            insightEyebrow("HEAD-TO-HEAD")
            VStack(spacing: 0) { labeledRow(bvp) }.quantPanel()
        }
        if let venue = p.venue {
            insightEyebrow("THIS PARK")
            VStack(spacing: 0) { labeledRow(venue) }.quantPanel()
        }

        // Statcast truth-check
        if let xs = p.xstats, !xs.isEmpty {
            insightEyebrow("STATCAST CHECK")
            VStack(spacing: 0) { ForEach(Array(xs.enumerated()), id: \.offset) { _, row in xstatRow(row) } }
                .quantPanel()
        }

        // Season + tonight's lines
        if let season = p.season {
            insightEyebrow("SEASON")
            VStack(alignment: .leading, spacing: 2) {
                if let l1 = season.line1 { Text(l1).font(.system(size: 15, weight: .semibold)).foregroundStyle(.white.opacity(0.9)) }
                if let l2 = season.line2 { Text(l2).font(.system(size: 12)).foregroundStyle(.white.opacity(0.5)) }
            }
        }
        if let props = p.props, !props.isEmpty {
            insightEyebrow("TONIGHT'S LINES")
            HStack(spacing: 8) {
                ForEach(Array(props.prefix(4).enumerated()), id: \.offset) { _, pr in
                    VStack(spacing: 2) {
                        Text(pr.label ?? "").font(GaryFonts.mono(8.5, bold: true)).tracking(0.5)
                            .foregroundStyle(.white.opacity(0.45))
                        Text("\(pr.line ?? "")\(pr.odds.map { " (\($0))" } ?? "")")
                            .font(.system(size: 13, weight: .bold)).foregroundStyle(GaryColors.gold)
                        // Hit rate vs tonight's line over the recent window —
                        // factual count, no lean implied.
                        if let rate = pr.rate {
                            Text(rate.uppercased())
                                .font(GaryFonts.mono(7.5, bold: true)).tracking(0.4)
                                .foregroundStyle(.white.opacity(0.5))
                        }
                    }
                    .padding(.horizontal, 10).padding(.vertical, 8)
                    .background(RoundedRectangle(cornerRadius: 10, style: .continuous).fill(Color.white.opacity(0.05)))
                }
            }
        }
    }

    private func insightEyebrow(_ t: String) -> some View {
        HStack(spacing: 8) {
            RoundedRectangle(cornerRadius: 1.5, style: .continuous)
                .fill(GaryColors.gold).frame(width: 6, height: 6).rotationEffect(.degrees(45))
            Text(t).font(GaryFonts.text(13, .bold)).tracking(0.6).foregroundStyle(GaryColors.warmWhite)
        }
        .padding(.top, 6)
    }

    private func bulletList(_ items: [String], color: Color) -> some View {
        VStack(alignment: .leading, spacing: 7) {
            ForEach(Array(items.enumerated()), id: \.offset) { _, item in
                HStack(alignment: .top, spacing: 8) {
                    Circle().fill(color).frame(width: 5, height: 5).padding(.top, 6)
                    Text(item).font(.system(size: 13.5)).foregroundStyle(.white.opacity(0.85))
                        .fixedSize(horizontal: false, vertical: true)
                }
            }
        }
    }

    private func labeledRow(_ row: PlayerInsightPack.LabeledStat, hideLabel: Bool = false) -> some View {
        HStack(alignment: .firstTextBaseline) {
            if !hideLabel, let l = row.label {
                Text(l).font(.system(size: 12, weight: .semibold)).foregroundStyle(.white.opacity(0.6))
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 1) {
                if let v = row.value { Text(v).font(.system(size: 14, weight: .bold)).foregroundStyle(.white.opacity(0.92)) }
                if let d = row.detail { Text(d).font(.system(size: 10.5)).foregroundStyle(.white.opacity(0.4)) }
            }
        }
        .padding(.vertical, 8).padding(.horizontal, 12)
    }

    private func xstatRow(_ row: PlayerInsightPack.XStatRow) -> some View {
        let verdictColor: Color = row.verdict == "overperforming" ? HubPalette.red
            : row.verdict == "underperforming" ? HubPalette.green : Color.white.opacity(0.55)
        return HStack {
            Text(row.label ?? "").font(.system(size: 12, weight: .semibold)).foregroundStyle(.white.opacity(0.6))
            Spacer()
            Text("\(row.actual ?? "—") → \(row.expected ?? "—")")
                .font(GaryFonts.mono(13, bold: true)).foregroundStyle(.white.opacity(0.9))
            if let v = row.verdict {
                Text(v.uppercased())
                    .font(GaryFonts.mono(7.5, bold: true)).tracking(0.6)
                    .foregroundStyle(verdictColor)
                    .padding(.horizontal, 6).padding(.vertical, 3)
                    .overlay(Capsule().stroke(verdictColor.opacity(0.5), lineWidth: 1))
            }
        }
        .padding(.vertical, 8).padding(.horizontal, 12)
    }

    /// Pitch | usage | BA | SLG | whiff table with grade tinting.
    private func pitchTable(_ rows: [PlayerInsightPack.PitchRow], isPitcher: Bool) -> some View {
        VStack(spacing: 0) {
            HStack {
                Text("PITCH").frame(maxWidth: .infinity, alignment: .leading)
                Text("USE%").frame(width: 44, alignment: .trailing)
                Text("BA").frame(width: 44, alignment: .trailing)
                Text("SLG").frame(width: 44, alignment: .trailing)
                Text("WHIFF").frame(width: 48, alignment: .trailing)
            }
            .font(GaryFonts.mono(8, bold: true)).tracking(0.5)
            .foregroundStyle(.white.opacity(0.35))
            .padding(.horizontal, 12).padding(.vertical, 7)

            ForEach(Array(rows.enumerated()), id: \.offset) { i, r in
                let tint: Color = r.grade == "strong" ? (isPitcher ? HubPalette.green : HubPalette.green)
                    : r.grade == "weak" ? HubPalette.red
                    : r.grade == "thin" ? Color.white.opacity(0.35) : Color.white.opacity(0.75)
                HStack {
                    Text(r.pitch ?? "—")
                        .font(.system(size: 12.5, weight: .semibold)).foregroundStyle(tint)
                        .frame(maxWidth: .infinity, alignment: .leading).lineLimit(1)
                    Text(r.usagePct.map { String(format: "%.0f%%", $0) } ?? "—")
                        .frame(width: 44, alignment: .trailing)
                    Text(r.ba ?? "—").frame(width: 44, alignment: .trailing)
                    Text(r.slg ?? "—").frame(width: 44, alignment: .trailing)
                    Text(r.whiffPct.map { String(format: "%.0f%%", $0) } ?? "—")
                        .frame(width: 48, alignment: .trailing)
                }
                .font(GaryFonts.mono(12, bold: false))
                .foregroundStyle(.white.opacity(0.8))
                .padding(.horizontal, 12).padding(.vertical, 7)
                if i < rows.count - 1 {
                    Rectangle().fill(Color.white.opacity(0.05)).frame(height: 1).padding(.leading, 12)
                }
            }
        }
        .quantPanel()
    }
}

/// ESPN-transaction-style injury swap row: the OUT player struck through on
/// top (red), tonight's replacement below (green) with his slot + season line.
/// Tapping anywhere opens the replacement's full Player Insights.
struct BeneficiarySwapRow: View {
    let s: Signal
    let onTap: () -> Void

    var body: some View {
        guard let swap = s.swap else { return AnyView(EmptyView()) }
        return AnyView(
            Button(action: onTap) {
                VStack(alignment: .leading, spacing: 8) {
                    HStack(spacing: 8) {
                        Text([swap.team, swap.position].compactMap { $0 }.joined(separator: " · "))
                            .font(.system(size: 10, weight: .semibold))
                            .foregroundStyle(GaryColors.sectionSub)
                        Spacer()
                        Text(s.game.uppercased())
                            .font(GaryFonts.mono(8, bold: false)).tracking(0.6)
                            .foregroundStyle(.white.opacity(0.3)).lineLimit(1)
                    }

                    // OUT
                    HStack(alignment: .firstTextBaseline, spacing: 8) {
                        Image(systemName: "xmark")
                            .font(.system(size: 9, weight: .heavy))
                            .foregroundStyle(HubPalette.red)
                            .frame(width: 14)
                        Text(swap.out_name ?? "—")
                            .font(.system(size: 15, weight: .semibold))
                            .strikethrough(true, color: HubPalette.red.opacity(0.7))
                            .foregroundStyle(.white.opacity(0.55))
                            .lineLimit(1)
                        Spacer(minLength: 6)
                        if let note = swap.out_note, !note.isEmpty {
                            Text(note.uppercased())
                                .font(GaryFonts.mono(8, bold: true)).tracking(0.4)
                                .foregroundStyle(HubPalette.red.opacity(0.8))
                                .lineLimit(1).minimumScaleFactor(0.8)
                        }
                    }

                    // IN
                    HStack(alignment: .firstTextBaseline, spacing: 8) {
                        Image(systemName: "checkmark")
                            .font(.system(size: 9, weight: .heavy))
                            .foregroundStyle(HubPalette.green)
                            .frame(width: 14)
                        Text(swap.in_name ?? "—")
                            .font(.system(size: 16, weight: .bold))
                            .foregroundStyle(.white)
                            .lineLimit(1)
                        Spacer(minLength: 6)
                        if let note = swap.in_note, !note.isEmpty {
                            Text(note)
                                .font(GaryFonts.mono(8.5, bold: true)).tracking(0.4)
                                .foregroundStyle(HubPalette.green)
                                .lineLimit(1).minimumScaleFactor(0.8)
                        }
                        Image(systemName: "chevron.right")
                            .font(.system(size: 9, weight: .bold))
                            .foregroundStyle(.white.opacity(0.25))
                    }
                }
                .padding(.vertical, 11)
                .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
            .overlay(Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1), alignment: .bottom)
        )
    }
}

struct SignalRow: View {
    let s: Signal
    /// nil = a read-only row (Picks tab's edge lists) — no chevron, no
    /// navigation promise. The Hub passes a handler and gets both.
    var onTap: ((String) -> Void)? = nil

    var body: some View {
        Button { onTap?(s.game) } label: {
            VStack(alignment: .leading, spacing: 6) {
                HStack(spacing: 8) {
                    Text(s.kind.chip).font(GaryFonts.mono(9, bold: true)).tracking(1.3).foregroundStyle(GaryColors.gold)
                    Spacer()
                    Text(s.game.uppercased()).font(GaryFonts.mono(9, bold: false)).tracking(0.6).foregroundStyle(.white.opacity(0.45)).lineLimit(1)
                }
                HStack(alignment: .top, spacing: 10) {
                    VStack(alignment: .leading, spacing: 4) {
                        Text(s.headline).font(GaryFonts.text(16)).foregroundStyle(.white).fixedSize(horizontal: false, vertical: true)
                        if !s.detail.isEmpty {
                            Text(s.detail).font(.system(size: 12.5)).foregroundStyle(.white.opacity(0.65)).fixedSize(horizontal: false, vertical: true)
                        }
                        // Spark mini-bar removed on the Picks edge rows (user call — the
                        // little 2-bar block read as ambiguous).
                    }
                    Spacer(minLength: 6)
                    if !s.value.isEmpty {
                        if s.value.contains(where: { $0.isNumber }) {
                            Text(s.value).font(GaryFonts.mono(20, bold: true)).foregroundStyle(s.tone.color)
                        } else {
                            Text(s.value).font(GaryFonts.mono(8.5, bold: true)).tracking(1).foregroundStyle(s.tone.color)
                                .padding(.horizontal, 7).padding(.vertical, 3)
                                .overlay(Capsule().stroke(s.tone.color.opacity(0.28), lineWidth: 1))
                        }
                    }
                    if onTap != nil {
                        Image(systemName: "chevron.right")
                            .font(.system(size: 9, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.25))
                            .padding(.top, 5)
                    }
                }
                if let xi = s.confirmedXI {
                    ConfirmedXISheetView(meta: xi)
                }
            }
            .padding(.vertical, 11)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .overlay(Rectangle().fill(Color.white.opacity(0.07)).frame(height: 1), alignment: .bottom)
    }
}

/// Confirmed XI display for the WC Confirmed XI lane: each team's formation + the
/// starting XI grouped by line (GK / DEF / MID / FWD), in a compact two-column sheet.
/// Renders beneath the edge in SignalRow when a row carries a confirmedXI meta.
struct ConfirmedXISheetView: View {
    let meta: SwapMeta
    var body: some View {
        HStack(alignment: .top, spacing: 14) {
            if let h = meta.home { teamColumn(h) }
            Rectangle().fill(Color.white.opacity(0.07)).frame(width: 1)
            if let a = meta.away { teamColumn(a) }
        }
        .padding(.top, 8)
    }

    private func teamColumn(_ s: TeamSheet) -> some View {
        VStack(alignment: .leading, spacing: 5) {
            HStack(spacing: 6) {
                Text((s.team ?? "").uppercased())
                    .font(GaryFonts.mono(9, bold: true)).tracking(0.8)
                    .foregroundStyle(.white.opacity(0.75)).lineLimit(1)
                if let f = s.formation, !f.isEmpty {
                    Text(f).font(GaryFonts.mono(8.5, bold: true)).tracking(0.5)
                        .foregroundStyle(.white.opacity(0.5))
                        .padding(.horizontal, 5).padding(.vertical, 2)
                        .overlay(Capsule().stroke(Color.white.opacity(0.18), lineWidth: 1))
                }
            }
            ForEach(["G", "D", "M", "F"], id: \.self) { line in
                let men = (s.xi ?? []).filter { ($0.p ?? "") == line }
                if !men.isEmpty {
                    HStack(alignment: .top, spacing: 5) {
                        Text(lineLabel(line))
                            .font(GaryFonts.mono(7.5, bold: true)).tracking(0.5)
                            .foregroundStyle(.white.opacity(0.3))
                            .frame(width: 24, alignment: .leading).padding(.top, 1)
                        Text(men.map { surname($0.n) }.joined(separator: ", "))
                            .font(.system(size: 11)).foregroundStyle(.white.opacity(0.7))
                            .fixedSize(horizontal: false, vertical: true)
                    }
                }
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    private func lineLabel(_ p: String) -> String {
        switch p {
        case "G": return "GK"
        case "D": return "DEF"
        case "M": return "MID"
        case "F": return "FWD"
        default: return p
        }
    }

    private func surname(_ n: String?) -> String {
        let parts = (n ?? "").split(separator: " ")
        return parts.count > 1 ? String(parts.last!) : (n ?? "")
    }
}

// MARK: - Compact Prop Row (Redesigned)

struct CompactPropRow: View {
    let prop: PropPick
    var gameResult: String? = nil
    var showSportBadge: Bool = false
    /// Game pages carry the score in the page hero (LiveScoreStrip), so their
    /// cards keep the plain start time in the slot. Everywhere else stays state-aware.
    var liveInSlot: Bool = true
    /// Winners keeps the start time visible on settled cards (it sorts by time);
    /// elsewhere settled cards hide it. Mirrors the game card's flag exactly.
    /// Declared BEFORE fixedHeight to match CompactPickRow's field order (the
    /// synthesized init is positional, and the flip wrapper passes them in order).
    var alwaysShowStartTime: Bool = false
    /// Exact height when the flip wrapper passes one — uniform with the game card
    /// (shares CompactPickRow.uniformHeight). nil = natural size (raw/share use).
    var fixedHeight: CGFloat? = nil

    private var accentColor: Color { Sport.from(league: prop.effectiveLeague).accentColor }
    private var isMLBProp: Bool {
        let s = Sport.from(league: prop.effectiveLeague)
        return s == .mlb || s == .mlbHR
    }
    private var accentGradient: LinearGradient {
        Sport.from(league: prop.effectiveLeague).accentGradient
            ?? LinearGradient(colors: [accentColor, accentColor], startPoint: .leading, endPoint: .trailing)
    }
    // MARK: - Result Stamp Properties
    private var resolvedResult: String? {
        guard let result = gameResult?.lowercased(), !result.isEmpty else { return nil }
        return result
    }
    private var resultStampColor: Color {
        switch resolvedResult {
        case "won": return Color(hex: "#3FB950")
        case "push": return GaryColors.gold
        case "lost": return Color(hex: "#E5484D")
        default: return Color(hex: "#E5484D")
        }
    }

    private var formattedTime: String {
        // Same formatter as the game card so both read "1:35 PM ET".
        let viaCommence = Formatters.formatCommenceTime(prop.commence_time)
        if !viaCommence.isEmpty { return viaCommence }
        if let time = prop.time, !time.isEmpty, time != "TBD" { return time }
        return ""
    }

    /// Live/final state for THIS matchup (shared cache; nil when scheduled
    /// or unknown). Only consulted when the card has no settled result.
    @ObservedObject private var liveCache = LiveScoreCache.shared
    /// One-tap share from the prop front — renders the prop share card
    /// (story + square) and presents the system sheet.
    @State private var shareItem: PickShareItem? = nil
    private var liveStatus: LiveScore? {
        guard liveInSlot, resolvedResult == nil else { return nil }
        return liveCache.status(forMatchup: prop.matchup ?? "")
    }

    /// The actual line value (e.g. "24.5") for use inside the bet pill so
    /// the user sees "OVER 24.5" instead of just "OVER". Strips trailing
    /// zeros but keeps the .5 half-points that prop markets actually use.
    private var formattedLineText: String? {
        guard let raw = prop.line?.trimmingCharacters(in: .whitespaces),
              !raw.isEmpty else { return nil }
        if let d = Double(raw) {
            return d.truncatingRemainder(dividingBy: 1) == 0
                ? String(format: "%g", d)
                : String(format: "%.1f", d)
        }
        return raw
    }

    private var leagueTag: String? {
        // Eyebrow league label — always shown so the header reads like the
        // gold game card's (sport accent dot + significance tag).
        guard let league = prop.effectiveLeague, !league.isEmpty else { return nil }
        return league.uppercased()
    }

    private var leagueIcon: String {
        switch (prop.effectiveLeague ?? "").uppercased() {
        case "NBA", "NCAAB", "WNBA": return "basketball.fill"
        case "NFL", "NCAAF", "NFL TDS": return "football.fill"
        case "NHL": return "hockey.puck.fill"
        case "MLB": return "baseball.fill"
        case "EPL": return "soccerball"
        default: return "sportscourt.fill"
        }
    }

    /// Market name without the line ("TOTAL BASES") — propDisplay carries the
    /// line when the raw prop type does, so strip a trailing numeric token; the
    /// chip composes market + call itself. Long names abbreviate so the chip
    /// stays one line.
    private var marketName: String {
        var words = Formatters.propDisplay(prop.prop, league: prop.effectiveLeague)
            .split(separator: " ").map(String.init)
        if let last = words.last, Double(last) != nil { words.removeLast() }
        let name = words.joined(separator: " ").uppercased()
        return Self.marketAbbrevShared[name] ?? name
    }
    static let marketAbbrevShared: [String: String] = [
        "STRIKEOUTS": "K'S", "HOME RUNS": "HR", "STOLEN BASES": "SB",
        "PITCHING OUTS": "OUTS", "HITS + RUNS + RBI": "H+R+RBI",
        // propDisplay yields "Hits Runs Rbis" (no + separators) for this combo —
        // map those raw forms too so the card hero abbreviates to H+R+RBI.
        "HITS RUNS RBIS": "H+R+RBI", "HITS RUNS RBI": "H+R+RBI",
        "POINTS + REBOUNDS + ASSISTS": "PRA", "REBOUNDS + ASSISTS": "R+A",
        "POINTS + REBOUNDS": "P+R", "POINTS + ASSISTS": "P+A",
        "GOALS + ASSISTS": "G+A", "SHOTS ON GOAL": "SOG",
    ]

    /// The pick chip's call text — side + line (e.g. "OVER 1.5"). Mirrors the
    /// gold card's abbreviated pick (compactPick), silver instead of gold.
    private var compactCall: String {
        let side = (prop.bet ?? "").uppercased()
        if let lineText = formattedLineText {
            return side.isEmpty ? lineText : "\(side) \(lineText)"
        }
        return side
    }

    // MARK: Headline front (June 11 2026 — THE pick card design, everywhere)
    //
    // Same anatomy as the game card: gold eyebrow + bear, the market and call
    // stacked as display type, accent league token + player meta line, the
    // share/tier/take footer, diagonal stamp when settled.

    private var eyebrowLabel: String {
        "GARY'S PICK"
    }

    /// "MATT CHAPMAN" over "H+R+RBI OVER 0.5" — the player IS the headline
    /// (user call, Jun 11: the name was hiding in the meta line).
    private var heroLines: String {
        let call = compactCall
        let bet = call.isEmpty ? marketName : "\(marketName) \(call)"
        let player = (prop.player ?? "").uppercased()
        return player.isEmpty ? bet : "\(player)\n\(bet)"
    }

    /// Matchup context for the meta row — team (+ FINAL score when settled).
    /// Time and odds render SEPARATELY (time in the footer, odds in gold) to
    /// match the game card exactly.
    private var metaLine: String {
        var parts: [String] = []
        let team = Formatters.shortTeamName(prop.team, league: prop.effectiveLeague)
        if !team.isEmpty { parts.append(team) }
        if resolvedResult != nil {
            if let ls = liveCache.status(forMatchup: prop.matchup ?? ""),
               ls.isFinal, let s = ls.scoreLine {
                parts.append("FINAL · \(s)")
            } else {
                parts.append("FINAL")
            }
        }
        return parts.joined(separator: " · ")
    }

    /// Odds rendered separately in sport-gold in the meta row (game card parity).
    private var oddsText: String { Formatters.americanOdds(prop.odds) }

    /// Start time on the footer's left corner — game card parity. Settled cards
    /// keep it on the Winners page (alwaysShowStartTime), matching the game card;
    /// live cards hide it (the footer carries the live line instead).
    private var propFrontTime: String? {
        if resolvedResult != nil { return alwaysShowStartTime ? (formattedTime.isEmpty ? nil : formattedTime) : nil }
        if let live = liveStatus, live.isLive || live.isFinal { return nil }
        return formattedTime.isEmpty ? nil : formattedTime
    }

    /// Footer live line — teams + score + situation (minute / outs+bases),
    /// IDENTICAL to the game card via the shared formatter.
    private var liveFooterText: String? {
        guard resolvedResult == nil, let ls = liveStatus else { return nil }
        if ls.isLive { return liveLineRich(ls, label: "LIVE") }
        if ls.isFinal { return liveLineRich(ls, label: "FINAL") }
        return nil
    }

    var body: some View {
        ZStack {
            VStack(alignment: .leading, spacing: 0) {
                HStack(alignment: .top, spacing: 10) {
                    Text(eyebrowLabel)
                        .font(GaryFonts.mono(11.5, bold: true)).tracking(2.2)
                        .foregroundStyle(GaryColors.gold)
                        .padding(.top, 6)
                    Spacer()
                    Image(GaryBrand.mark)
                        .resizable().scaledToFit()
                        .frame(width: 44, height: 44)
                }

                Text(heroLines)
                    .font(GaryFonts.display(36))
                    .foregroundStyle(.white)
                    .lineSpacing(0)
                    .lineLimit(3)
                    .minimumScaleFactor(0.5)
                    .padding(.top, 10)

                HStack(alignment: .center, spacing: 8) {
                    Text(((prop.effectiveLeague ?? "") + " · PROP").uppercased())
                        .font(GaryFonts.mono(11, bold: true)).tracking(1.2)
                        .foregroundStyle(isMLBProp ? GaryColors.mlbGrass : accentColor)
                        .lineLimit(1)
                        .layoutPriority(1)
                    (Text(metaLine).foregroundColor(.white.opacity(0.55))
                        + Text((oddsText.isEmpty || metaLine.isEmpty) ? "" : " · ").foregroundColor(.white.opacity(0.4))
                        + Text(oddsText).foregroundColor(GaryColors.gold))
                        .font(GaryFonts.text(13.5, .medium))
                        .lineLimit(1)
                        .minimumScaleFactor(0.75)
                    Spacer(minLength: 4)
                    // Share — same spot as the game card (meta row), frees the footer.
                    Button {
                        let images = renderPropShareImages(prop: prop, gameResult: resolvedResult)
                        if !images.isEmpty { shareItem = PickShareItem(images: images) }
                    } label: {
                        Image(systemName: "square.and.arrow.up")
                            .font(.system(size: 12, weight: .semibold))
                            .foregroundStyle(.white.opacity(0.5))
                            .frame(width: 26, height: 22)
                            .contentShape(Rectangle())
                    }
                    .buttonStyle(.plain)
                    .accessibilityLabel("Share this prop pick")
                }
                .padding(.top, 10)

                // Footer — live line (teams + score + situation) or start time on
                // the left, tap-to-flip chevron on the right. Matches the game card
                // exactly: share moved up to the meta row, no "Gary's Take" words.
                Rectangle()
                    .fill(.white.opacity(0.12))
                    .frame(height: 1)
                    .padding(.vertical, 12)

                HStack(spacing: 10) {
                    if let live = liveFooterText {
                        Text(live)
                            .font(GaryFonts.mono(11, bold: true)).tracking(0.5)
                            .foregroundStyle(GaryColors.gold)
                            .lineLimit(1)
                            .minimumScaleFactor(0.8)
                    } else if let t = propFrontTime {
                        Text(t)
                            .font(GaryFonts.mono(11, bold: true)).tracking(0.5)
                            .foregroundStyle(GaryColors.gold)
                            .lineLimit(1)
                            .minimumScaleFactor(0.8)
                    }
                    Spacer()
                    Image(systemName: "chevron.right")
                        .font(.system(size: 12, weight: .bold))
                        .foregroundStyle(GaryColors.heroAccent.opacity(0.7))
                }
            }
            .padding(18)

            // Stamp rides the empty space under the bear — gold for every
            // verdict (the brand owns its record).
            if let verdict = resolvedResult {
                let stampColor = verdict == "lost" ? GaryColors.lostTint : GaryColors.gold
                Text(verdict == "won" ? "CASHED" : (verdict == "push" ? "PUSH" : "LOST"))
                    .font(GaryFonts.mono(19, bold: true)).tracking(2.5)
                    .foregroundStyle(stampColor.opacity(0.92))
                    .padding(.horizontal, 10).padding(.vertical, 4)
                    .overlay(Rectangle().stroke(stampColor.opacity(0.85), lineWidth: 2))
                    // Diagonal stamp (game-card parity), raised to sit beside the short
                    // player-name line: prop types run two long lines, and a centered
                    // stamp collided with line 2 — this lands it in the upper black
                    // space, clear of the words (user call, Jun 17).
                    .rotationEffect(.degrees(-8))
                    .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .trailing)
                    .padding(.trailing, 16)
                    .offset(y: -24)
            }
        }
        // Uniform card height — matches the game card so every pick card is the
        // same object regardless of content. FIXED (not a floor) when the flip
        // wrapper passes one, so 2-line heroes don't end up taller than 1-line.
        .frame(minHeight: fixedHeight == nil ? 210 : nil)
        .frame(height: fixedHeight)
        .background(
            RoundedRectangle(cornerRadius: 20, style: .continuous)
                .fill(Color(hex: "#121110"))
                .overlay(
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .stroke(.white.opacity(0.10), lineWidth: 1)
                )
                .shadow(color: .black.opacity(0.5), radius: 18, y: 8)
        )
        .onAppear { LiveScoreCache.shared.startIfNeeded() }
        .sheet(item: $shareItem) { ActivityShareSheet(items: $0.images) }
    }
}

// MARK: - Floating Prop Detail Popup

struct PropDetailPopup: View {
    let prop: PropPick
    let onDismiss: () -> Void

    private var accentColor: Color {
        if prop.isTDPick {
            return prop.tdCategory == "underdog" ? Color(hex: "#22C55E") : Color(hex: "#3B82F6")
        }
        return Sport.from(league: prop.effectiveLeague).accentColor
    }

    private var betColor: Color {
        guard let bet = prop.bet?.lowercased() else { return .white }
        if bet == "over" || bet == "yes" { return .green }
        return .red
    }

    private var categoryLabel: String? {
        guard let cat = prop.tdCategory else { return nil }
        switch cat {
        case "standard": return "Regular Pick"
        case "underdog": return "Value Pick (+200+)"
        case "first_td": return "First TD"
        default: return nil
        }
    }

    /// Clean prop analysis text into paragraphs
    private func cleanAnalysis(_ text: String) -> [String] {
        var cleaned = text
        let labelsToRemove = ["HYPOTHESIS:", "EVIDENCE:", "CONVERGENCE", "IF WRONG:", "THE EDGE:", "THE VERDICT:", "RISK:"]
        for label in labelsToRemove {
            if let range = cleaned.range(of: label, options: .caseInsensitive) {
                let afterLabel = cleaned[range.upperBound...]
                if afterLabel.hasPrefix(" (") || afterLabel.hasPrefix("(") {
                    if let closeRange = afterLabel.range(of: "):") {
                        cleaned.removeSubrange(range.lowerBound...closeRange.upperBound)
                    } else if let closeRange = afterLabel.range(of: ")") {
                        cleaned.removeSubrange(range.lowerBound...closeRange.upperBound)
                    } else {
                        cleaned.removeSubrange(range)
                    }
                } else {
                    cleaned.removeSubrange(range)
                }
            }
        }
        return cleaned.components(separatedBy: "\n")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .map { para in
                var p = para
                if let first = p.first, first.isLowercase { p = p.prefix(1).uppercased() + p.dropFirst() }
                return p
            }
    }

    var body: some View {
        ZStack {
            // Dimmed backdrop
            Color.black.opacity(0.95)
                .ignoresSafeArea()
                .onTapGesture {
                    withAnimation(.spring(response: 0.3, dampingFraction: 0.85)) { onDismiss() }
                }

            // Floating card
            VStack(spacing: 0) {
                // Header bar
                HStack {
                    HStack(spacing: 8) {
                        if let league = prop.effectiveLeague {
                            Text(league)
                                .font(.system(size: 10, weight: .heavy))
                                .tracking(0.5)
                                .foregroundStyle(accentColor)
                        }
                        if let category = categoryLabel {
                            Text(category)
                                .font(.system(size: 10, weight: .medium))
                                .foregroundStyle(.white.opacity(0.4))
                        }
                    }
                    Spacer()
                    Button {
                        withAnimation(.spring(response: 0.3, dampingFraction: 0.85)) { onDismiss() }
                    } label: {
                        Image(systemName: "xmark")
                            .font(.system(size: 11, weight: .bold))
                            .foregroundStyle(.white.opacity(0.5))
                            .padding(8)
                            .background(Circle().fill(.white.opacity(0.08)))
                    }
                }
                .padding(.horizontal, 20)
                .padding(.top, 16)
                .padding(.bottom, 10)

                // Thin accent line
                Rectangle()
                    .fill(accentColor.opacity(0.3))
                    .frame(height: 0.5)
                    .padding(.horizontal, 16)

                ScrollView(showsIndicators: false) {
                    VStack(alignment: .leading, spacing: 18) {
                        VStack(alignment: .leading, spacing: 16) {
                            // Player info
                            VStack(alignment: .leading, spacing: 6) {
                                HStack(alignment: .top) {
                                    VStack(alignment: .leading, spacing: 3) {
                                        Text(prop.player ?? "Unknown")
                                            .font(.system(size: 22, weight: .bold))
                                            .foregroundStyle(.white)

                                        if let team = prop.team {
                                            Text(team)
                                                .font(.system(size: 13, weight: .medium))
                                                .foregroundStyle(.white.opacity(0.5))
                                        }
                                    }

                                    Spacer()

                                    Text(Formatters.americanOdds(prop.odds))
                                        .font(.system(size: 22, weight: .bold))
                                        .foregroundStyle(accentColor)
                                }

                                if let matchup = prop.matchup {
                                    HStack(spacing: 3) {
                                        Image(systemName: "sportscourt.fill").font(.system(size: 9))
                                        Text(matchup).font(.system(size: 10, weight: .medium))
                                    }
                                    .foregroundStyle(accentColor.opacity(0.75))
                                }

                                if let time = prop.time, !time.isEmpty, time != "TBD" {
                                    Text(time)
                                        .font(.system(size: 10, weight: .medium))
                                        .foregroundStyle(.white.opacity(0.42))
                                }
                            }

                            Rectangle().fill(.white.opacity(0.08)).frame(height: 0.5)

                            // Gary's Pick
                            VStack(alignment: .leading, spacing: 10) {
                                Text("GARY'S PICK")
                                    .font(.system(size: 11, weight: .heavy))
                                    .tracking(1.2)
                                    .foregroundStyle(GaryColors.gold)

                                HStack(spacing: 10) {
                                    Text(Formatters.propDisplay(prop.prop, league: prop.effectiveLeague))
                                        .font(.system(size: 14.5, weight: .heavy))
                                        .foregroundStyle(GaryColors.gold)
                                        .lineLimit(2)
                                        .minimumScaleFactor(0.6)

                                    if let bet = prop.bet {
                                        Text(bet.uppercased())
                                            .font(.system(size: 13, weight: .heavy))
                                            .foregroundStyle(betColor)
                                            .padding(.horizontal, 12)
                                            .padding(.vertical, 5)
                                            .background(betColor.opacity(0.12))
                                            .clipShape(Capsule())
                                    }

                                    Spacer()
                                }

                                // EV
                                if let ev = Formatters.computeEV(confidence: prop.confidence, american: prop.odds) {
                                    HStack(spacing: 4) {
                                        Text("EV:")
                                            .foregroundStyle(.white.opacity(0.4))
                                        Text(String(format: "+%.1f%%", ev))
                                            .foregroundStyle(.green)
                                    }
                                    .font(.system(size: 11, weight: .bold))
                                }

                                // Confidence
                                VStack(alignment: .leading, spacing: 4) {
                                    HStack {
                                        Image(systemName: "chart.line.uptrend.xyaxis").font(.system(size: 9))
                                        Text("Confidence").font(.system(size: 9, weight: .medium))
                                        Spacer()
                                    }
                                    .foregroundStyle(.white.opacity(0.3))

                                    GeometryReader { geo in
                                        ZStack(alignment: .leading) {
                                            RoundedRectangle(cornerRadius: 2)
                                                .fill(accentColor.opacity(0.12))
                                            RoundedRectangle(cornerRadius: 2)
                                                .fill(accentColor)
                                                .frame(width: geo.size.width * CGFloat(prop.confidence ?? 0))
                                        }
                                    }
                                    .frame(height: 4)
                                }
                            }
                        }
                        .padding(16)
                        .background(
                            ZStack {
                                RoundedRectangle(cornerRadius: 4)
                                    .fill(Color(hex: "#1C1A1A"))
                                RoundedRectangle(cornerRadius: 4)
                                    .fill(GaryColors.gold.opacity(0.035))
                                RoundedRectangle(cornerRadius: 4)
                                    .stroke(GaryColors.gold.opacity(0.15), lineWidth: 0.5)
                            }
                        )

                        // Divider
                        Rectangle().fill(GaryColors.gold.opacity(0.06)).frame(height: 0.5)

                        // Key Stats
                        if let keyStats = prop.key_stats, !keyStats.isEmpty {
                            VStack(alignment: .leading, spacing: 10) {
                                Text("KEY STATS")
                                    .font(.system(size: 11, weight: .heavy))
                                    .tracking(1.2)
                                    .foregroundStyle(accentColor)

                                ForEach(keyStats, id: \.self) { stat in
                                    HStack(alignment: .top, spacing: 8) {
                                        Circle()
                                            .fill(accentColor)
                                            .frame(width: 5, height: 5)
                                            .padding(.top, 7)
                                        Text(stat)
                                            .font(.system(size: 15))
                                            .foregroundStyle(.white.opacity(0.88))
                                            .lineSpacing(3)
                                    }
                                }
                            }

                            Rectangle().fill(.white.opacity(0.06)).frame(height: 0.5)
                        }

                        // Gary's Take (Analysis)
                        if let analysis = prop.analysis, !analysis.isEmpty {
                            VStack(alignment: .leading, spacing: 10) {
                                Text("GARY'S TAKE")
                                    .font(.system(size: 11, weight: .heavy))
                                    .tracking(1.2)
                                    .foregroundStyle(accentColor)

                                VStack(alignment: .leading, spacing: 12) {
                                    ForEach(Array(cleanAnalysis(analysis).enumerated()), id: \.offset) { _, para in
                                        Text(para)
                                            .font(.system(size: 13))
                                            .foregroundStyle(.white.opacity(0.88))
                                            .lineSpacing(4)
                                            .fixedSize(horizontal: false, vertical: true)
                                    }
                                }
                                .padding(14)
                                .background(
                                    RoundedRectangle(cornerRadius: 10)
                                        .fill(.white.opacity(0.03))
                                        .overlay(
                                            RoundedRectangle(cornerRadius: 10)
                                                .stroke(accentColor.opacity(0.15), lineWidth: 0.5)
                                        )
                                )
                            }
                        }
                    }
                    .padding(.horizontal, 20)
                    .padding(.top, 14)
                    .padding(.bottom, 30)
                }
            }
            .background(
                ZStack {
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .fill(Color(hex: "#1C1A1A"))
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .fill(GaryColors.gold.opacity(0.035))
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .stroke(GaryColors.gold.opacity(0.25), lineWidth: 0.8)
                }
                    .shadow(color: .black.opacity(0.45), radius: 24, y: 8)
                    .shadow(color: .black.opacity(0.72), radius: 26, y: 12)
            )
            .clipShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
            .padding(.horizontal, 16)
            .padding(.vertical, 50)
        }
    }
}

